{
  "name": "ZenTask Manager Pro",
  "description": "A sophisticated Windows-style task management application featuring real-time tracking, company-based categorization, automated end-of-day archiving, and Gemini AI-powered task optimization.",
  "requestFramePermissions": []
}

export enum TaskStatus {
  NOT_STARTED = 'NOT_STARTED',
  IN_PROGRESS = 'IN_PROGRESS',
  DONE = 'DONE'
}

export interface Task {
  id: string;
  content: string;
  company: string;
  createdAt: string; // ISO String
  status: TaskStatus;
}

export interface AppState {
  tasks: Task[];
  lastLaunchDate: string; // To track daily resets
}

export const COMPANIES = [
  "Agriviet",
  "TechFlow",
  "GreenLogistics",
  "SmartSolutions",
  "GlobalTrade Co.",
  "Personal/Other"
];

export const STATUS_LABELS: Record<string, { label: string; color: string }> = {
  NOT_STARTED: { label: 'Chưa làm', color: 'bg-slate-200 text-slate-700' },
  IN_PROGRESS: { label: 'Đang làm', color: 'bg-blue-100 text-blue-700 border border-blue-200' },
  DONE: { label: 'Đã xong', color: 'bg-emerald-100 text-emerald-700 border border-emerald-200' }
};

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { AppState, Task, TaskStatus } from '../types';

const STORAGE_KEY = 'zentask_app_state';

export const saveState = (state: AppState) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
};

export const loadState = (): AppState => {
  const stored = localStorage.getItem(STORAGE_KEY);
  const today = new Date().toDateString();

  if (stored) {
    const state: AppState = JSON.parse(stored);

    // Logic: If current day is different from last launch day,
    // we archive "DONE" tasks from the active view.
    if (state.lastLaunchDate !== today) {
      const filteredTasks = state.tasks.filter(t => t.status !== TaskStatus.DONE);
      return {
        tasks: filteredTasks,
        lastLaunchDate: today
      };
    }
    return state;
  }

  return {
    tasks: [],
    lastLaunchDate: today
  };
};

