import React from 'react';
import { Task, TaskStatus } from '../types';
import { STATUS_LABELS } from '../constants';

interface TaskItemProps {
  task: Task;
  onStatusChange: (id: string, status: TaskStatus) => void;
  onDelete: (id: string) => void;
}

const TaskItem: React.FC<TaskItemProps> = ({ task, onStatusChange, onDelete }) => {
  const formattedTime = new Date(task.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

  return (
    <div className="group bg-white p-4 rounded-2xl border border-slate-100 hover:border-blue-200 hover:shadow-md transition-all flex flex-col sm:flex-row items-start sm:items-center gap-4">
      <div className="flex-1">
        <div className="flex items-center gap-2 mb-1">
          <span className="text-[10px] font-bold px-2 py-0.5 rounded bg-slate-100 text-slate-500 uppercase">
            {task.company}
          </span>
          <span className="text-[10px] text-slate-400 font-medium italic">
            <i className="far fa-clock mr-1"></i> {formattedTime}
          </span>
        </div>
        <p className={`text-slate-800 font-medium ${task.status === TaskStatus.DONE ? 'line-through text-slate-400' : ''}`}>
          {task.content}
        </p>
      </div>

      <div className="flex items-center gap-2 w-full sm:w-auto">
        <div className="flex bg-slate-100 p-1 rounded-xl">
          {(Object.values(TaskStatus) as TaskStatus[]).map((status) => (
            <button
              key={status}
              onClick={() => onStatusChange(task.id, status)}
              className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all ${
                task.status === status
                  ? STATUS_LABELS[status].color
                  : 'text-slate-500 hover:bg-slate-200'
              }`}
            >
              {STATUS_LABELS[status].label}
            </button>
          ))}
        </div>
        <button
          onClick={() => onDelete(task.id)}
          className="p-2 text-slate-300 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"
        >
          <i className="fas fa-times"></i>
        </button>
      </div>
    </div>
  );
};

export default TaskItem;

import React, { useState, useEffect, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import TaskItem from './components/TaskItem';
import { Task, TaskStatus, AppState } from './types';
import { loadState, saveState } from './services/storageService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => loadState());
  const [currentTime, setCurrentTime] = useState(new Date());

  // Update real-time clock and check for day change
  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now);

      // Real-time check: If we just crossed midnight (23:59 -> 00:00)
      const currentDay = now.toDateString();
      if (state.lastLaunchDate !== currentDay) {
        // Automatically trigger reset
        const filteredTasks = state.tasks.filter(t => t.status !== TaskStatus.DONE);
        setState({
          tasks: filteredTasks,
          lastLaunchDate: currentDay
        });
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [state.lastLaunchDate, state.tasks]);

  // Sync with local storage
  useEffect(() => {
    saveState(state);
  }, [state]);

  const addTask = useCallback((content: string, company: string) => {
    const newTask: Task = {
      id: crypto.randomUUID(),
      content,
      company,
      createdAt: new Date().toISOString(),
      status: TaskStatus.NOT_STARTED
    };
    setState(prev => ({
      ...prev,
      tasks: [newTask, ...prev.tasks]
    }));
  }, []);

  const updateTaskStatus = useCallback((id: string, status: TaskStatus) => {
    setState(prev => ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === id ? { ...t, status } : t)
    }));
  }, []);

  const deleteTask = useCallback((id: string) => {
    setState(prev => ({
      ...prev,
      tasks: prev.tasks.filter(t => t.id !== id)
    }));
  }, []);

  const clearAllTasks = useCallback(() => {
    if (confirm("Bạn có chắc chắn muốn xóa tất cả công việc hiện tại?")) {
      setState(prev => ({ ...prev, tasks: [] }));
    }
  }, []);

  const activeCount = state.tasks.filter(t => t.status !== TaskStatus.DONE).length;
  const doneCount = state.tasks.filter(t => t.status === TaskStatus.DONE).length;

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden">
      {/* Sidebar - Entry Area */}
      <Sidebar onAddTask={addTask} onClearAll={clearAllTasks} />

      {/* Main Content - Display Area */}
      <main className="flex-1 flex flex-col min-w-0 bg-slate-50 relative">
        {/* Top Header */}
        <header className="h-24 px-8 border-b border-slate-200 bg-white flex items-center justify-between flex-shrink-0 z-10">
          <div>
            <h2 className="text-2xl font-extrabold text-slate-800 tracking-tight">
              Công Việc Đang Thực Hiện
            </h2>
            <p className="text-sm font-medium text-slate-500 flex items-center gap-2">
              <i className="far fa-calendar-alt text-blue-500"></i>
              {currentTime.toLocaleDateString('vi-VN', { 
                weekday: 'long', 
                year: 'numeric', 
                month: 'long', 
                day: 'numeric' 
              })}
              <span className="mx-2 text-slate-300">•</span>
              <span className="font-mono text-blue-600 font-bold">
                {currentTime.toLocaleTimeString('vi-VN')}
              </span>
            </p>
          </div>

          <div className="flex gap-4">
            <div className="text-right">
              <span className="block text-xs font-bold text-slate-400 uppercase tracking-widest">Đang chờ</span>
              <span className="text-2xl font-black text-blue-600">{activeCount}</span>
            </div>
            <div className="w-[1px] h-10 bg-slate-200 mx-2 self-center"></div>
            <div className="text-right">
              <span className="block text-xs font-bold text-slate-400 uppercase tracking-widest">Đã xong</span>
              <span className="text-2xl font-black text-emerald-500">{doneCount}</span>
            </div>
          </div>
        </header>

        {/* Task List Section */}
        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
          {state.tasks.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 space-y-4">
              <div className="w-24 h-24 rounded-full bg-slate-100 flex items-center justify-center">
                <i className="fas fa-clipboard-list text-4xl text-slate-200"></i>
              </div>
              <div className="text-center">
                <p className="font-bold text-lg text-slate-500">Danh sách trống</p>
                <p className="text-sm">Hãy nhập công việc ở menu bên trái để bắt đầu.</p>
              </div>
            </div>
          ) : (
            <div className="max-w-4xl mx-auto space-y-3 pb-20">
              {state.tasks.map((task) => (
                <TaskItem
                  key={task.id}
                  task={task}
                  onStatusChange={updateTaskStatus}
                  onDelete={deleteTask}
                />
              ))}
            </div>
          )}
        </div>

        {/* Decorative corner element */}
        <div className="absolute bottom-6 right-8 text-[10px] text-slate-400 uppercase font-black tracking-[0.2em] pointer-events-none">
          Live Tracking System v2.0
        </div>
      </main>
    </div>
  );
};

export default App;

export enum TaskStatus {
  NOT_STARTED = 'NOT_STARTED',
  IN_PROGRESS = 'IN_PROGRESS',
  DONE = 'DONE'
}

export interface Task {
  id: string;
  content: string;
  company: string;
  createdAt: string; // ISO String
  status: TaskStatus;
}

export interface AppState {
  username: string;
  tasks: Task[];
  lastLaunchDate: string;
}

export interface AuthContext {
  currentUser: string | null;
}

import { AppState, TaskStatus } from '../types';

const BASE_STORAGE_KEY = 'zentask_v2_user_';

export const saveState = (username: string, state: AppState) => {
  localStorage.setItem(`${BASE_STORAGE_KEY}${username}`, JSON.stringify(state));
};

export const loadState = (username: string): AppState => {
  const stored = localStorage.getItem(`${BASE_STORAGE_KEY}${username}`);
  const today = new Date().toDateString();

  if (stored) {
    const state: AppState = JSON.parse(stored);

    // Logic tự động dọn dẹp task cũ khi sang ngày mới cho từng user
    if (state.lastLaunchDate !== today) {
      const filteredTasks = state.tasks.filter(t => t.status !== TaskStatus.DONE);
      return {
        username,
        tasks: filteredTasks,
        lastLaunchDate: today
      };
    }
    return state;
  }

  return {
    username,
    tasks: [],
    lastLaunchDate: today
  };
};

export const getSavedUsers = (): string[] => {
  const users: string[] = [];
  for (let i = 0; i < localStorage.length; i++) {
    const key = localStorage.key(i);
    if (key?.startsWith(BASE_STORAGE_KEY)) {
      users.push(key.replace(BASE_STORAGE_KEY, ''));
    }
  }
  return users;
};

