import React, { useState, useEffect, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import TaskItem from './components/TaskItem';
import Login from './components/Login';
import { Task, TaskStatus, AppState } from './types';
import { loadState, saveState } from './services/storageService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<string | null>(() => {
    return sessionStorage.getItem('zentask_current_session');
  });

  const [state, setState] = useState<AppState | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());

  // Load state when user logs in
  useEffect(() => {
    if (currentUser) {
      const loaded = loadState(currentUser);
      setState(loaded);
      sessionStorage.setItem('zentask_current_session', currentUser);
    } else {
      setState(null);
      sessionStorage.removeItem('zentask_current_session');
    }
  }, [currentUser]);

  // Update clock and check midnight reset
  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now);

      if (state && state.lastLaunchDate !== now.toDateString()) {
        const filteredTasks = state.tasks.filter(t => t.status !== TaskStatus.DONE);
        setState({
          ...state,
          tasks: filteredTasks,
          lastLaunchDate: now.toDateString()
        });
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [state]);

  // Auto-save state
  useEffect(() => {
    if (currentUser && state) {
      saveState(currentUser, state);
    }
  }, [state, currentUser]);

  const addTask = useCallback((content: string, company: string) => {
    if (!state) return;
    const newTask: Task = {
      id: crypto.randomUUID(),
      content,
      company,
      createdAt: new Date().toISOString(),
      status: TaskStatus.NOT_STARTED
    };
    setState(prev => prev ? ({
      ...prev,
      tasks: [newTask, ...prev.tasks]
    }) : null);
  }, [state]);

  const updateTaskStatus = useCallback((id: string, status: TaskStatus) => {
    setState(prev => prev ? ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === id ? { ...t, status } : t)
    }) : null);
  }, []);

  const deleteTask = useCallback((id: string) => {
    setState(prev => prev ? ({
      ...prev,
      tasks: prev.tasks.filter(t => t.id !== id)
    }) : null);
  }, []);

  const handleLogout = () => {
    setCurrentUser(null);
  };

  if (!currentUser || !state) {
    return <Login onLogin={setCurrentUser} />;
  }

  const activeTasks = state.tasks.filter(t => t.status !== TaskStatus.DONE);
  const doneTasks = state.tasks.filter(t => t.status === TaskStatus.DONE);

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-slate-50">
      <Sidebar 
        username={currentUser}
        onAddTask={addTask} 
        onClearAll={() => setState({ ...state, tasks: [] })} 
        onLogout={handleLogout}
      />

      <main className="flex-1 flex flex-col min-w-0 relative">
        <header className="h-24 px-8 border-b border-slate-200 bg-white/80 backdrop-blur-md flex items-center justify-between flex-shrink-0 z-10">
          <div>
            <h2 className="text-2xl font-black text-slate-800 tracking-tight">
              Task List
            </h2>
            <p className="text-sm font-bold text-blue-600">
              {currentTime.toLocaleDateString('vi-VN', { weekday: 'long', day: 'numeric', month: 'long' })}
              <span className="mx-2 text-slate-300">•</span>
              {currentTime.toLocaleTimeString('vi-VN')}
            </p>
          </div>

          <div className="flex gap-6">
            <div className="text-right">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Đang làm</p>
              <p className="text-2xl font-black text-blue-600">{activeTasks.length}</p>
            </div>
            <div className="text-right">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Hoàn thành</p>
              <p className="text-2xl font-black text-emerald-500">{doneTasks.length}</p>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar bg-gradient-to-br from-slate-50 to-blue-50/30">
          {state.tasks.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center opacity-40">
              <div className="w-20 h-20 bg-slate-200 rounded-full flex items-center justify-center mb-4">
                <i className="fas fa-ghost text-3xl"></i>
              </div>
              <p className="font-bold text-slate-400">Chưa có công việc nào cho {currentUser}</p>
            </div>
          ) : (
            <div className="max-w-4xl mx-auto space-y-3 pb-20">
              {state.tasks.map((task) => (
                <TaskItem
                  key={task.id}
                  task={task}
                  onStatusChange={updateTaskStatus}
                  onDelete={deleteTask}
                />
              ))}
            </div>
          )}
        </div>

        <div className="absolute bottom-6 right-8 text-[10px] text-slate-400 uppercase font-bold tracking-[0.3em] pointer-events-none">
          {currentUser}'s Secure Workspace
        </div>
      </main>
    </div>
  );
};

