export enum TaskStatus {
  NOT_STARTED = 'NOT_STARTED',
  IN_PROGRESS = 'IN_PROGRESS',
  DONE = 'DONE'
}

export interface Task {
  id: string;
  content: string;
  company: string;
  createdAt: string; // ISO String
  status: TaskStatus;
}

export interface User {
  email: string;
  password: string;
}

export interface AppState {
  email: string;
  tasks: Task[];
  lastLaunchDate: string;
}

import { AppState, TaskStatus, User } from '../types';

const USERS_KEY = 'zentask_v3_users_list';
const TASK_STORAGE_PREFIX = 'zentask_v3_tasks_';

// Quản lý người dùng
export const getUsers = (): User[] => {
  const users = localStorage.getItem(USERS_KEY);
  return users ? JSON.parse(users) : [];
};

export const registerUser = (user: User): { success: boolean; message: string } => {
  const users = getUsers();
  if (users.find(u => u.email.toLowerCase() === user.email.toLowerCase())) {
    return { success: false, message: 'Email này đã tồn tại!' };
  }
  users.push(user);
  localStorage.setItem(USERS_KEY, JSON.stringify(users));
  return { success: true, message: 'Đăng ký thành công!' };
};

export const authenticateUser = (user: User): { success: boolean; message: string } => {
  const users = getUsers();
  const found = users.find(u => u.email.toLowerCase() === user.email.toLowerCase() && u.password === user.password);
  if (found) return { success: true, message: 'Đăng nhập thành công!' };
  return { success: false, message: 'Email hoặc mật khẩu không chính xác.' };
};

// Quản lý dữ liệu công việc theo Email
export const saveState = (email: string, state: AppState) => {
  localStorage.setItem(`${TASK_STORAGE_PREFIX}${email}`, JSON.stringify(state));
};

export const loadState = (email: string): AppState => {
  const stored = localStorage.getItem(`${TASK_STORAGE_PREFIX}${email}`);
  const today = new Date().toDateString();

  if (stored) {
    const state: AppState = JSON.parse(stored);
    if (state.lastLaunchDate !== today) {
      const filteredTasks = state.tasks.filter(t => t.status !== TaskStatus.DONE);
      return {
        email,
        tasks: filteredTasks,
        lastLaunchDate: today
      };
    }
    return state;
  }

  return {
    email,
    tasks: [],
    lastLaunchDate: today
  };
};

