/**
 * CryptoService: Cung cấp các phương thức mã hóa chuẩn quân đội (AES-GCM, PBKDF2, SHA-256)
 */

const ENCRYPTION_ALGO = 'AES-GCM';
const PBKDF2_ITERATIONS = 100000;

// Tạo vân tay SHA-256 (Dùng để che giấu email trong storage key)
export async function hashEmail(email: string): Promise<string> {
  const msgUint8 = new TextEncoder().encode(email.toLowerCase().trim());
  const hashBuffer = await crypto.subtle.digest('SHA-256', msgUint8);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
}

// Tạo khóa AES từ mật khẩu và salt (Sử dụng PBKDF2)
async function deriveKey(password: string, salt: Uint8Array): Promise<CryptoKey> {
  const encoder = new TextEncoder();
  const passwordKey = await crypto.subtle.importKey(
    'raw',
    encoder.encode(password),
    { name: 'PBKDF2' },
    false,
    ['deriveKey']
  );

  return crypto.subtle.deriveKey(
    {
      name: 'PBKDF2',
      salt: salt,
      iterations: PBKDF2_ITERATIONS,
      hash: 'SHA-256',
    },
    passwordKey,
    { name: ENCRYPTION_ALGO, length: 256 },
    false,
    ['encrypt', 'decrypt']
  );
}

// Mã hóa dữ liệu bằng mật khẩu
export async function encryptData(data: any, password: string): Promise<string> {
  const encoder = new TextEncoder();
  const salt = crypto.getRandomValues(new Uint8Array(16));
  const iv = crypto.getRandomValues(new Uint8Array(12));
  const key = await deriveKey(password, salt);

  const encrypted = await crypto.subtle.encrypt(
    { name: ENCRYPTION_ALGO, iv },
    key,
    encoder.encode(JSON.stringify(data))
  );

  // Kết quả gộp: salt (16b) + iv (12b) + encrypted_data
  const result = new Uint8Array(salt.length + iv.length + encrypted.byteLength);
  result.set(salt, 0);
  result.set(iv, salt.length);
  result.set(new Uint8Array(encrypted), salt.length + iv.length);

  return btoa(String.fromCharCode(...result));
}

// Giải mã dữ liệu bằng mật khẩu
export async function decryptData(encryptedBase64: string, password: string): Promise<any> {
  try {
    const binary = atob(encryptedBase64);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);

    const salt = bytes.slice(0, 16);
    const iv = bytes.slice(16, 28);
    const data = bytes.slice(28);

    const key = await deriveKey(password, salt);
    const decrypted = await crypto.subtle.decrypt(
      { name: ENCRYPTION_ALGO, iv },
      key,
      data
    );

    return JSON.parse(new TextDecoder().decode(decrypted));
  } catch (e) {
    throw new Error('Mật khẩu không đúng hoặc dữ liệu bị hỏng');
  }
}

// Băm mật khẩu để lưu trữ đối soát (Bảo mật cao hơn plain text)
export async function hashPasswordForStorage(password: string): Promise<string> {
  const msgUint8 = new TextEncoder().encode(password + "zentask_salt_2024");
  const hashBuffer = await crypto.subtle.digest('SHA-256', msgUint8);
  return btoa(String.fromCharCode(...new Uint8Array(hashBuffer)));
}

import { AppState, TaskStatus, User } from '../types';
import { hashEmail, encryptData, decryptData, hashPasswordForStorage } from './cryptoService';

const USERS_LIST_KEY = 'zentask_secure_users';
const TASK_DATA_PREFIX = 'zt_enc_';

// Quản lý người dùng
export const getUsers = (): User[] => {
  const users = localStorage.getItem(USERS_LIST_KEY);
  return users ? JSON.parse(users) : [];
};

export const registerUser = async (user: User): Promise<{ success: boolean; message: string }> => {
  const users = getUsers();
  const emailHash = await hashEmail(user.email);

  if (users.find(u => u.email === emailHash)) {
    return { success: false, message: 'Email này đã được đăng ký!' };
  }

  // Lưu hash của email và hash của mật khẩu
  const secureUser: User = {
    email: emailHash,
    password: await hashPasswordForStorage(user.password)
  };

  users.push(secureUser);
  localStorage.setItem(USERS_LIST_KEY, JSON.stringify(users));
  return { success: true, message: 'Đăng ký thành công!' };
};

export const authenticateUser = async (user: User): Promise<{ success: boolean; message: string }> => {
  const users = getUsers();
  const emailHash = await hashEmail(user.email);
  const passwordHash = await hashPasswordForStorage(user.password);

  const found = users.find(u => u.email === emailHash && u.password === passwordHash);
  if (found) return { success: true, message: 'Đăng nhập thành công!' };
  return { success: false, message: 'Thông tin tài khoản không chính xác.' };
};

// Quản lý dữ liệu công việc (Đã mã hóa)
export const saveStateSecure = async (email: string, password: string, state: AppState) => {
  const emailHash = await hashEmail(email);
  const encrypted = await encryptData(state, password);
  localStorage.setItem(`${TASK_DATA_PREFIX}${emailHash}`, encrypted);
};

export const loadStateSecure = async (email: string, password: string): Promise<AppState> => {
  const emailHash = await hashEmail(email);
  const encrypted = localStorage.getItem(`${TASK_DATA_PREFIX}${emailHash}`);
  const today = new Date().toDateString();

  if (encrypted) {
    try {
      const state: AppState = await decryptData(encrypted, password);
      // Logic tự động dọn dẹp task cũ
      if (state.lastLaunchDate !== today) {
        return {
          email,
          tasks: state.tasks.filter(t => t.status !== TaskStatus.DONE),
          lastLaunchDate: today
        };
      }
      return state;
    } catch (e) {
      throw new Error("Không thể giải mã dữ liệu.");
    }
  }

  return {
    email,
    tasks: [],
    lastLaunchDate: today
  };
};

