import React, { useState, useEffect, useCallback, useRef } from 'react';
import Sidebar from './components/Sidebar';
import TaskItem from './components/TaskItem';
import Login from './components/Login';
import { Task, TaskStatus, AppState } from './types';
import { loadStateSecure, saveStateSecure } from './services/storageService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<{email: string, pass: string} | null>(null);
  const [state, setState] = useState<AppState | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [loading, setLoading] = useState(false);

  // Tránh việc lưu mật khẩu vào localStorage, chỉ giữ trong React State (RAM)
  const handleLogin = async (email: string, pass: string) => {
    setLoading(true);
    try {
      const loaded = await loadStateSecure(email, pass);
      setCurrentUser({ email, pass });
      setState(loaded);
    } catch (e: any) {
      alert(e.message);
    } finally {
      setLoading(false);
    }
  };

  // Đồng bộ hóa thời gian thực
  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now);

      if (state && state.lastLaunchDate !== now.toDateString()) {
        setState(prev => prev ? ({
          ...prev,
          tasks: prev.tasks.filter(t => t.status !== TaskStatus.DONE),
          lastLaunchDate: now.toDateString()
        }) : null);
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [state]);

  // Lưu trữ bảo mật mỗi khi state thay đổi
  useEffect(() => {
    if (currentUser && state) {
      saveStateSecure(currentUser.email, currentUser.pass, state);
    }
  }, [state, currentUser]);

  const addTask = useCallback((content: string, company: string) => {
    if (!state) return;
    const newTask: Task = {
      id: crypto.randomUUID(),
      content,
      company,
      createdAt: new Date().toISOString(),
      status: TaskStatus.NOT_STARTED
    };
    setState(prev => prev ? ({
      ...prev,
      tasks: [newTask, ...prev.tasks]
    }) : null);
  }, [state]);

  const updateTaskStatus = useCallback((id: string, status: TaskStatus) => {
    setState(prev => prev ? ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === id ? { ...t, status } : t)
    }) : null);
  }, []);

  const deleteTask = useCallback((id: string) => {
    setState(prev => prev ? ({
      ...prev,
      tasks: prev.tasks.filter(t => t.id !== id)
    }) : null);
  }, []);

  if (loading) {
    return (
      <div className="h-screen bg-[#0f172a] flex flex-col items-center justify-center text-blue-400">
        <i className="fas fa-shield-alt text-6xl animate-pulse mb-4"></i>
        <p className="font-black uppercase tracking-[0.3em] text-xs">Đang giải mã dữ liệu...</p>
      </div>
    );
  }

  if (!currentUser || !state) {
    return <Login onLogin={handleLogin} />;
  }

  const activeTasks = state.tasks.filter(t => t.status !== TaskStatus.DONE);
  const doneTasks = state.tasks.filter(t => t.status === TaskStatus.DONE);

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-slate-950">
      <Sidebar 
        email={currentUser.email}
        onAddTask={addTask} 
        onClearAll={() => setState({ ...state, tasks: [] })} 
        onLogout={() => {
          setCurrentUser(null);
          setState(null);
        }}
      />

      <main className="flex-1 flex flex-col min-w-0 relative bg-slate-50">
        <header className="h-24 px-8 border-b border-slate-200 bg-white flex items-center justify-between flex-shrink-0 z-10">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center shadow-inner">
               <i className="fas fa-lock text-xl"></i>
            </div>
            <div>
              <h2 className="text-2xl font-black text-slate-800 tracking-tight">Vùng Lưu Trữ Bảo Mật</h2>
              <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest flex items-center gap-1">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span>
                Dữ liệu đã được mã hóa AES-256
              </p>
            </div>
          </div>

          <div className="hidden lg:flex gap-8">
            <div className="text-right">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Thời gian</p>
              <p className="text-xl font-mono font-bold text-slate-800">{currentTime.toLocaleTimeString('vi-VN')}</p>
            </div>
            <div className="text-right">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Trạng thái</p>
              <div className="flex gap-2">
                <span className="px-2 py-1 bg-blue-100 text-blue-700 rounded text-xs font-bold">{activeTasks.length} chờ</span>
                <span className="px-2 py-1 bg-emerald-100 text-emerald-700 rounded text-xs font-bold">{doneTasks.length} xong</span>
              </div>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
          {state.tasks.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center opacity-20">
              <i className="fas fa-shield-virus text-8xl mb-6"></i>
              <p className="font-black uppercase tracking-widest">Hệ thống sẵn sàng</p>
            </div>
          ) : (
            <div className="max-w-4xl mx-auto space-y-4 pb-24">
              {state.tasks.map((task) => (
                <TaskItem
                  key={task.id}
                  task={task}
                  onStatusChange={updateTaskStatus}
                  onDelete={deleteTask}
                />
              ))}
            </div>
          )}
