export enum TaskStatus {
  NOT_STARTED = 'NOT_STARTED',
  IN_PROGRESS = 'IN_PROGRESS',
  DONE = 'DONE'
}

export interface Task {
  id: string;
  content: string;
  company: string;
  createdAt: string; // ISO String
  status: TaskStatus;
}

export interface User {
  email: string;
  password: string;
}

export interface AppState {
  email: string;
  tasks: Task[];
  companies: string[];
  lastLaunchDate: string;
}

import { AppState, TaskStatus, User } from '../types';
import { hashEmail, encryptData, decryptData, hashPasswordForStorage } from './cryptoService';
import { COMPANIES as DEFAULT_COMPANIES } from '../constants';

const USERS_LIST_KEY = 'zentask_secure_users';
const TASK_DATA_PREFIX = 'zt_enc_';

// Quản lý người dùng
export const getUsers = (): User[] => {
  const users = localStorage.getItem(USERS_LIST_KEY);
  return users ? JSON.parse(users) : [];
};

export const registerUser = async (user: User): Promise<{ success: boolean; message: string }> => {
  const users = getUsers();
  const emailHash = await hashEmail(user.email);

  if (users.find(u => u.email === emailHash)) {
    return { success: false, message: 'Email này đã được đăng ký!' };
  }

  // Lưu hash của email và hash của mật khẩu
  const secureUser: User = {
    email: emailHash,
    password: await hashPasswordForStorage(user.password)
  };

  users.push(secureUser);
  localStorage.setItem(USERS_LIST_KEY, JSON.stringify(users));
  return { success: true, message: 'Đăng ký thành công!' };
};

export const authenticateUser = async (user: User): Promise<{ success: boolean; message: string }> => {
  const users = getUsers();
  const emailHash = await hashEmail(user.email);
  const passwordHash = await hashPasswordForStorage(user.password);

  const found = users.find(u => u.email === emailHash && u.password === passwordHash);
  if (found) return { success: true, message: 'Đăng nhập thành công!' };
  return { success: false, message: 'Thông tin tài khoản không chính xác.' };
};

// Quản lý dữ liệu công việc (Đã mã hóa)
export const saveStateSecure = async (email: string, password: string, state: AppState) => {
  const emailHash = await hashEmail(email);
  const encrypted = await encryptData(state, password);
  localStorage.setItem(`${TASK_DATA_PREFIX}${emailHash}`, encrypted);
};

export const loadStateSecure = async (email: string, password: string): Promise<AppState> => {
  const emailHash = await hashEmail(email);
  const encrypted = localStorage.getItem(`${TASK_DATA_PREFIX}${emailHash}`);
  const today = new Date().toDateString();

  if (encrypted) {
    try {
      const state: AppState = await decryptData(encrypted, password);

      // Đảm bảo companies luôn tồn tại (cho các account cũ nâng cấp)
      if (!state.companies) {
        state.companies = DEFAULT_COMPANIES;
      }

      // Logic tự động dọn dẹp task cũ
      if (state.lastLaunchDate !== today) {
        return {
          ...state,
          email,
          tasks: state.tasks.filter(t => t.status !== TaskStatus.DONE),
          lastLaunchDate: today
        };
      }
      return state;
    } catch (e) {
      throw new Error("Không thể giải mã dữ liệu.");
    }
  }

  return {
    email,
    tasks: [],
    companies: DEFAULT_COMPANIES,
    lastLaunchDate: today
  };
};

