import React, { useState, useEffect, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import TaskItem from './components/TaskItem';
import Login from './components/Login';
import Setup from './components/Setup';
import { Task, TaskStatus, AppState } from './types';
import { loadStateSecure, saveStateSecure } from './services/storageService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<{email: string, pass: string} | null>(null);
  const [state, setState] = useState<AppState | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [loading, setLoading] = useState(false);

  const handleLogin = async (email: string, pass: string) => {
    setLoading(true);
    try {
      const loaded = await loadStateSecure(email, pass);
      setCurrentUser({ email, pass });
      setState(loaded);
    } catch (e: any) {
      alert(e.message);
    } finally {
      setLoading(false);
    }
  };

  const handleSetupComplete = (companies: string[]) => {
    setState(prev => prev ? ({
      ...prev,
      companies
    }) : null);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setState(null);
  };

  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now);

      if (state && state.lastLaunchDate !== now.toDateString()) {
        setState(prev => prev ? ({
          ...prev,
          tasks: prev.tasks.filter(t => t.status !== TaskStatus.DONE),
          lastLaunchDate: now.toDateString()
        }) : null);
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [state]);

  useEffect(() => {
    if (currentUser && state) {
      saveStateSecure(currentUser.email, currentUser.pass, state);
    }
  }, [state, currentUser]);

  const addTask = useCallback((content: string, company: string) => {
    if (!state) return;
    const newTask: Task = {
      id: crypto.randomUUID(),
      content,
      company,
      createdAt: new Date().toISOString(),
      status: TaskStatus.NOT_STARTED
    };
    setState(prev => prev ? ({
      ...prev,
      tasks: [newTask, ...prev.tasks]
    }) : null);
  }, [state]);

  const addCompany = useCallback((companyName: string) => {
    setState(prev => {
      if (!prev) return null;
      if (prev.companies.includes(companyName)) return prev;
      return {
        ...prev,
        companies: [...prev.companies, companyName]
      };
    });
  }, []);

  const updateTaskStatus = useCallback((id: string, status: TaskStatus) => {
    setState(prev => prev ? ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === id ? { ...t, status } : t)
    }) : null);
  }, []);

  const deleteTask = useCallback((id: string) => {
    setState(prev => prev ? ({
      ...prev,
      tasks: prev.tasks.filter(t => t.id !== id)
    }) : null);
  }, []);

  if (loading) {
    return (
      <div className="h-screen bg-slate-50 flex flex-col items-center justify-center text-blue-600">
        <div className="w-16 h-16 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="font-bold uppercase tracking-widest text-xs">Đang mở khóa dữ liệu...</p>
      </div>
    );
  }

  if (!currentUser || !state) {
    return <Login onLogin={handleLogin} />;
  }

  // Luồng Setup: Nếu đăng nhập thành công nhưng chưa có công ty nào
  if (state.companies.length === 0) {
    return <Setup onComplete={handleSetupComplete} onLogout={handleLogout} />;
  }

  const activeTasks = state.tasks.filter(t => t.status !== TaskStatus.DONE);
  const doneTasks = state.tasks.filter(t => t.status === TaskStatus.DONE);

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-white">
      {/* NỬA TRÁI: Menu và Nhập liệu */}
      <Sidebar 
        email={currentUser.email}
        companies={state.companies}
        onAddTask={addTask} 
        onAddCompany={addCompany}
        onClearAll={() => setState({ ...state, tasks: [] })} 
        onLogout={handleLogout}
      />

      {/* NỬA PHẢI: Công việc đang thực hiện */}
      <main className="flex-1 flex flex-col min-w-0 bg-slate-50 border-l border-slate-200">
        <header className="h-24 px-10 bg-white border-b border-slate-200 flex items-center justify-between flex-shrink-0">
          <div>
            <h2 className="text-2xl font-black text-slate-800 tracking-tight">CÔNG VIỆC ĐANG THỰC HIỆN</h2>
            <div className="flex items-center gap-2 mt-1">
              <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
              <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">
                {currentTime.toLocaleDateString('vi-VN', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}
              </p>
            </div>
          </div>

          <div className="flex items-center gap-6">
            <div className="text-right border-r border-slate-200 pr-6">
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Chưa hoàn thành</p>
              <p className="text-2xl font-black text-blue-600">{activeTasks.length}</p>
            </div>
            <div className="text-right">
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Thời gian</p>
              <p className="text-2xl font-mono font-bold text-slate-700">{currentTime.toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' })}</p>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-10 custom-scrollbar">
          {state.tasks.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-300">
              <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center shadow-sm mb-4">
                <i className="fas fa-clipboard-list text-4xl"></i>
              </div>
              <p className="font-bold uppercase tracking-widest text-sm">Danh sách trống</p>
            </div>
          ) : (
            <div className="max-w-4xl mx-auto space-y-4 pb-24">
              {state.tasks.map((task) => (
                <TaskItem
                  key={task.id}
                  task={task}
                  onStatusChange={updateTaskStatus}
                  onDelete={deleteTask}
                />
              ))}
            </div>
          )}
        </div>

        {/* Thông tin bảo mật nhỏ gọn ở góc */}
        <div className="absolute bottom-6 right-8 flex items-center gap-2 px-3 py-1.5 bg-white border border-slate-200 rounded-full shadow-sm">
