import React, { useState } from 'react';
import { Task } from '../types';

interface ExportModalProps {
  tasks: Task[];
  onClose: () => void;
}

const ExportModal: React.FC<ExportModalProps> = ({ tasks, onClose }) => {
  const [columns, setColumns] = useState({
    company: true,
    content: true,
    status: true,
    priority: true,
    date: true
  });

  const handleExport = () => {
    const headers = [];
    if (columns.date) headers.push('Ngày tạo');
    if (columns.company) headers.push('Công ty');
    if (columns.content) headers.push('Nội dung công việc');
    if (columns.status) headers.push('Trạng thái');
    if (columns.priority) headers.push('Ưu tiên');

    const csvRows = tasks.map(t => {
      const row = [];
      if (columns.date) row.push(`"${new Date(t.createdAt).toLocaleDateString('vi-VN')}"`);
      if (columns.company) row.push(`"${t.company}"`);
      if (columns.content) row.push(`"${t.content.replace(/"/g, '""')}"`);
      if (columns.status) row.push(`"${t.status === 'DONE' ? 'Đã xong' : t.status === 'IN_PROGRESS' ? 'Đang làm' : 'Chưa làm'}"`);
      if (columns.priority) row.push(`"${t.isPriority ? 'Gấp' : 'Thường'}"`);
      return row.join(',');
    });

    const csvString = [headers.join(','), ...csvRows].join('\n');
    const blob = new Blob(['\ufeff' + csvString], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `ZenTask_Bao_Cao_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="w-full max-w-lg bg-white rounded-[3rem] shadow-2xl p-10 animate-in zoom-in-95 duration-300">
        <h2 className="text-2xl font-black text-slate-800 tracking-tight mb-2">XUẤT BÁO CÁO EXCEL</h2>
        <p className="text-sm text-slate-500 font-medium mb-8">Tùy chỉnh cấu trúc hàng cột cho file báo cáo của bạn.</p>

        <div className="space-y-4 mb-10">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Các cột thông tin hiển thị</p>
          {Object.entries(columns).map(([key, value]) => (
            <label key={key} className="flex items-center gap-4 p-4 rounded-2xl bg-slate-50 border border-slate-100 cursor-pointer hover:border-blue-200 transition-all">
              <input 
                type="checkbox" 
                checked={value} 
                onChange={() => setColumns({...columns, [key]: !value})}
                className="w-5 h-5 rounded-lg text-blue-600 focus:ring-blue-500"
              />
              <span className="text-sm font-bold text-slate-700 capitalize">
                {key === 'company' ? 'Công ty' : key === 'content' ? 'Nội dung' : key === 'status' ? 'Trạng thái' : key === 'priority' ? 'Ưu tiên' : 'Ngày tạo'}
              </span>
            </label>
          ))}
        </div>

        <div className="flex gap-4">
          <button onClick={onClose} className="flex-1 py-4 font-black text-slate-400 hover:text-slate-600 uppercase tracking-widest text-xs">Hủy bỏ</button>
          <button onClick={handleExport} className="flex-2 bg-blue-600 hover:bg-blue-700 text-white font-black py-4 px-8 rounded-2xl shadow-lg shadow-blue-100 flex items-center justify-center gap-3">
            <i className="fas fa-file-excel"></i>
            TẢI XUỐNG FILE .CSV
          </button>
        </div>
      </div>
    </div>
  );
};

