                <select value={selectedCompany} onChange={(e) => setSelectedCompany(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-bold text-slate-700 appearance-none text-sm">
                  {companies.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
                <i className="fas fa-chevron-down absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none text-xs"></i>
              </div>
            )}
          </div>

          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Nội Dung</label>
            <textarea value={content} onChange={(e) => setContent(e.target.value)} placeholder="Nội dung công việc..." className="w-full p-5 bg-slate-50 border border-slate-200 rounded-2xl outline-none h-32 resize-none text-slate-800 font-medium text-sm shadow-inner" />
