export default Sidebar;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import TaskItem from './components/TaskItem';
import Login from './components/Login';
import Setup from './components/Setup';
import HistoryModal from './components/HistoryModal';
import ExportModal from './components/ExportModal';
import { Task, TaskStatus, AppState } from './types';
import { loadStateSecure, saveStateSecure } from './services/storageService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<{email: string, pass: string} | null>(null);
  const [state, setState] = useState<AppState | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [loading, setLoading] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isExportOpen, setIsExportOpen] = useState(false);

  const handleLogin = async (email: string, pass: string) => {
    setLoading(true);
    try {
      const loaded = await loadStateSecure(email, pass);
      setCurrentUser({ email, pass });
      setState(loaded);
    } catch (e: any) { alert(e.message); }
    finally { setLoading(false); }
  };

  const handleSetupComplete = (companies: string[]) => {
    setState(prev => prev ? ({ ...prev, companies }) : null);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setState(null);
  };

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (currentUser && state) saveStateSecure(currentUser.email, currentUser.pass, state);
  }, [state, currentUser]);

  const addTask = useCallback((content: string, company: string, isPriority: boolean) => {
    if (!state) return;
    const newTask: Task = {
      id: crypto.randomUUID(),
      content,
      company,
      createdAt: new Date().toISOString(),
      status: TaskStatus.NOT_STARTED,
      isPriority
    };
    setState(prev => prev ? ({ ...prev, tasks: [newTask, ...prev.tasks] }) : null);
  }, [state]);

  const addCompany = useCallback((companyName: string) => {
    setState(prev => prev ? ({ ...prev, companies: Array.from(new Set([...prev.companies, companyName])) }) : null);
  }, []);

  const updateTaskStatus = useCallback((id: string, status: TaskStatus) => {
    setState(prev => prev ? ({ ...prev, tasks: prev.tasks.map(t => t.id === id ? { ...t, status } : t) }) : null);
  }, []);

  const deleteTask = useCallback((id: string) => {
    if (!confirm("Xóa công việc này khỏi hệ thống?")) return;
    setState(prev => prev ? ({ ...prev, tasks: prev.tasks.filter(t => t.id !== id) }) : null);
  }, []);

  // Logic hiển thị công việc "HIỆN TẠI":
  // 1. Những việc chưa xong (bất kể ngày nào)
  // 2. Những việc đã xong TRONG NGÀY HÔM NAY
  const currentViewTasks = useMemo(() => {
    if (!state) return [];
    const today = new Date().toISOString().split('T')[0];
    return state.tasks.filter(t => {
      if (t.status !== TaskStatus.DONE) return true;
      return t.createdAt.startsWith(today);
    }).sort((a, b) => {
      const getRank = (task: Task) => {
        if (task.status === TaskStatus.IN_PROGRESS) return 0;
        if (task.isPriority) return 1;
        if (task.status === TaskStatus.NOT_STARTED) return 2;
        return 3;
      };
      const rankA = getRank(a), rankB = getRank(b);
      if (rankA !== rankB) return rankA - rankB;
      return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
    });
  }, [state]);

  if (loading) return (
    <div className="h-screen bg-white flex flex-col items-center justify-center text-blue-600">
      <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
      <p className="font-black uppercase tracking-[0.2em] text-[10px]">Đang mở khóa dữ liệu</p>
    </div>
  );

  if (!currentUser || !state) return <Login onLogin={handleLogin} />;
  if (state.companies.length === 0) return <Setup onComplete={handleSetupComplete} onLogout={handleLogout} />;

  const activeCount = state.tasks.filter(t => t.status !== TaskStatus.DONE).length;
  const doneTodayCount = state.tasks.filter(t => t.status === TaskStatus.DONE && t.createdAt.startsWith(new Date().toISOString().split('T')[0])).length;

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-white">
      <Sidebar 
        email={currentUser.email}
        companies={state.companies}
        onAddTask={addTask} 
        onAddCompany={addCompany}
        onClearAll={() => { if(confirm("Xóa toàn bộ?")) setState({ ...state, tasks: [] }); }} 
        onLogout={handleLogout}
        onOpenHistory={() => setIsHistoryOpen(true)}
        onOpenExport={() => setIsExportOpen(true)}
      />

      <main className="flex-1 flex flex-col min-w-0 bg-slate-50 relative">
        <header className="h-24 px-10 bg-white border-b border-slate-100 flex items-center justify-between flex-shrink-0 z-10">
          <div>
            <h2 className="text-2xl font-black text-slate-800 tracking-tight">CÔNG VIỆC HIỆN TẠI</h2>
            <div className="flex items-center gap-2 mt-1">
              <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                {currentTime.toLocaleDateString('vi-VN', { weekday: 'long', day: 'numeric', month: 'long' })}
              </p>
            </div>
          </div>

          <div className="flex items-center gap-8">
            <div className="text-right">
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Đang thực hiện</p>
              <p className="text-2xl font-black text-rose-500">{activeCount}</p>
            </div>
            <div className="text-right">
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Xong hôm nay</p>
              <p className="text-2xl font-black text-emerald-500">{doneTodayCount}</p>
            </div>
            <div className="h-10 w-px bg-slate-100"></div>
            <div className="text-right">
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Giờ hệ thống</p>
              <p className="text-2xl font-mono font-bold text-slate-800">{currentTime.toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' })}</p>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-10 custom-scrollbar">
          {currentViewTasks.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-300 opacity-50">
              <i className="fas fa-tasks text-6xl mb-6"></i>
              <p className="font-black uppercase tracking-widest text-sm">Chưa có công việc nào</p>
            </div>
          ) : (
            <div className="max-w-4xl mx-auto space-y-4 pb-24">
              {currentViewTasks.map((task) => (
                <TaskItem key={task.id} task={task} onStatusChange={updateTaskStatus} onDelete={deleteTask} />
              ))}
            </div>
          )}
        </div>

        <div className="absolute bottom-6 right-10 flex items-center gap-2 px-4 py-2 bg-white border border-slate-100 rounded-full shadow-sm text-[10px] font-black text-slate-400 uppercase tracking-widest">
           <i className="fas fa-database text-blue-500"></i> Tổng lưu trữ: {state.tasks.length} mục
        </div>
      </main>

      {isHistoryOpen && <HistoryModal tasks={state.tasks} onClose={() => setIsHistoryOpen(false)} />}
      {isExportOpen && <ExportModal tasks={state.tasks} onClose={() => setIsExportOpen(false)} />}
    </div>
  );
};

export default App;

export enum TaskStatus {
  NOT_STARTED = 'NOT_STARTED',
  IN_PROGRESS = 'IN_PROGRESS',
  DONE = 'DONE'
}

export interface Task {
  id: string;
  content: string;
  company: string;
  createdAt: string; // ISO String
  status: TaskStatus;
  isPriority: boolean; // Công việc gấp/ưu tiên
}

export interface User {
  email: string;
  password: string;
}

export interface ReportTemplate {
  id: string;
  name: string;
  columns: {
    company: boolean;
    content: boolean;
    status: boolean;
    priority: boolean;
    date: boolean;
  };
}

export interface AppState {
  email: string;
  tasks: Task[];
  companies: string[];
  lastLaunchDate: string;
  reportTemplates?: ReportTemplate[]; // Danh sách các mẫu báo cáo đã lưu
}

import React, { useState, useEffect } from 'react';
import { Task, ReportTemplate } from '../types';

interface ExportModalProps {
  tasks: Task[];
  templates: ReportTemplate[];
  onSaveTemplate: (template: ReportTemplate) => void;
  onDeleteTemplate: (id: string) => void;
  onClose: () => void;
}

const ExportModal: React.FC<ExportModalProps> = ({ tasks, templates, onSaveTemplate, onDeleteTemplate, onClose }) => {
  const todayStr = new Date().toISOString().split('T')[0];
  const [startDate, setStartDate] = useState(todayStr);
  const [endDate, setEndDate] = useState(todayStr);
  const [templateName, setTemplateName] = useState('');
  const [columns, setColumns] = useState({
    company: true,
    content: true,
    status: true,
    priority: true,
    date: true
  });

  const handleApplyTemplate = (tpl: ReportTemplate) => {
    setColumns(tpl.columns);
    setTemplateName(tpl.name);
  };

  const handleSaveTemplate = () => {
    if (!templateName.trim()) {
      alert("Vui lòng nhập tên mẫu báo cáo");
      return;
    }
    const newTemplate: ReportTemplate = {
      id: crypto.randomUUID(),
      name: templateName,
      columns: { ...columns }
    };
    onSaveTemplate(newTemplate);
    alert("Đã lưu mẫu báo cáo thành công!");
  };

  const handleExport = () => {
    // Lọc task theo khoảng ngày
    const filteredTasks = tasks.filter(t => {
      const taskDate = t.createdAt.split('T')[0];
      return taskDate >= startDate && taskDate <= endDate;
    });

    if (filteredTasks.length === 0) {
      alert("Không có dữ liệu trong khoảng thời gian đã chọn.");
      return;
    }

    const headers = [];
    if (columns.date) headers.push('Ngày tạo');
    if (columns.company) headers.push('Công ty');
    if (columns.content) headers.push('Nội dung công việc');
    if (columns.status) headers.push('Trạng thái');
    if (columns.priority) headers.push('Mức độ');

    const csvRows = filteredTasks.map(t => {
      const row = [];
      if (columns.date) row.push(`"${new Date(t.createdAt).toLocaleDateString('vi-VN')}"`);
      if (columns.company) row.push(`"${t.company}"`);
      if (columns.content) row.push(`"${t.content.replace(/"/g, '""')}"`);
      if (columns.status) row.push(`"${t.status === 'DONE' ? 'Đã xong' : t.status === 'IN_PROGRESS' ? 'Đang làm' : 'Chưa làm'}"`);
      if (columns.priority) row.push(`"${t.isPriority ? 'Gấp' : 'Thường'}"`);
      return row.join(',');
    });

    const csvString = [headers.join(','), ...csvRows].join('\n');
    const blob = new Blob(['\ufeff' + csvString], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `ZenTask_Bao_Cao_${startDate}_den_${endDate}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="w-full max-w-5xl bg-white rounded-[3rem] shadow-2xl flex flex-col md:flex-row max-h-[90vh] overflow-hidden animate-in zoom-in-95 duration-300">

        {/* Cửa sổ trái: Quản lý mẫu đã lưu */}
        <div className="w-full md:w-80 bg-slate-50 border-r border-slate-100 p-8 flex flex-col">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-6">Mẫu báo cáo đã lưu</h3>
          <div className="flex-1 overflow-y-auto space-y-3 custom-scrollbar pr-2">
            {templates.length === 0 ? (
              <p className="text-xs text-slate-400 italic">Chưa có mẫu nào được lưu.</p>
            ) : (
              templates.map(tpl => (
                <div key={tpl.id} className="group relative">
                  <button 
                    onClick={() => handleApplyTemplate(tpl)}
                    className="w-full text-left p-4 bg-white border border-slate-200 rounded-2xl hover:border-blue-400 hover:shadow-sm transition-all text-xs font-bold text-slate-700"
                  >
                    {tpl.name}
                  </button>
                  <button 
                    onClick={() => onDeleteTemplate(tpl.id)}
                    className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all p-1"
                  >
                    <i className="fas fa-trash-alt text-[10px]"></i>
                  </button>
                </div>
              ))
            )}
          </div>
          <div className="mt-6 pt-6 border-t border-slate-200">
            <input 
              value={templateName}
              onChange={(e) => setTemplateName(e.target.value)}
              placeholder="Tên mẫu mới..."
              className="w-full p-3 bg-white border border-slate-200 rounded-xl text-xs font-bold outline-none focus:ring-2 focus:ring-blue-500 mb-2"
            />
            <button 
              onClick={handleSaveTemplate}
              className="w-full py-3 bg-slate-800 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-black transition-all"
            >
              Lưu cấu hình này
            </button>
          </div>
        </div>

        {/* Cửa sổ phải: Thiết lập xuất báo cáo */}
        <div className="flex-1 p-10 flex flex-col overflow-y-auto custom-scrollbar">
          <div className="flex justify-between items-start mb-10">
            <div>
              <h2 className="text-3xl font-black text-slate-800 tracking-tight">XUẤT BÁO CÁO TÙY CHỈNH</h2>
              <p className="text-sm text-slate-500 font-medium mt-1">Lọc dữ liệu linh hoạt và chọn cột hiển thị.</p>
            </div>
            <button onClick={onClose} className="w-10 h-10 flex items-center justify-center rounded-xl hover:bg-slate-100 text-slate-400">
              <i className="fas fa-times"></i>
            </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-10">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Từ ngày</label>
              <input 
                type="date" 
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-slate-700 outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Đến ngày</label>
              <input 
                type="date" 
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-slate-700 outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
          </div>

          <div className="space-y-6 mb-10">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Cấu trúc cột báo cáo</p>
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
              {Object.entries(columns).map(([key, value]) => (
                <label key={key} className={`flex items-center gap-3 p-4 rounded-2xl border transition-all cursor-pointer ${value ? 'bg-blue-50 border-blue-200 shadow-sm' : 'bg-white border-slate-100 hover:border-slate-200'}`}>
                  <input 
                    type="checkbox" 
                    checked={value} 
                    onChange={() => setColumns({...columns, [key]: !value})}
                    className="w-5 h-5 rounded-lg text-blue-600 focus:ring-blue-500"
                  />
                  <span className="text-xs font-bold text-slate-700 capitalize">
                    {key === 'company' ? 'Công ty' : key === 'content' ? 'Nội dung' : key === 'status' ? 'Trạng thái' : key === 'priority' ? 'Ưu tiên' : 'Ngày tạo'}
                  </span>
                </label>
              ))}
            </div>
          </div>

          <div className="mt-auto flex gap-4 pt-10 border-t border-slate-100">
            <button onClick={onClose} className="flex-1 py-4 font-black text-slate-400 hover:text-slate-600 uppercase tracking-widest text-[10px]">Hủy bỏ</button>
            <button 
              onClick={handleExport}
              className="flex-2 bg-blue-600 hover:bg-blue-700 text-white font-black py-4 px-12 rounded-2xl shadow-xl shadow-blue-100 flex items-center justify-center gap-3 transition-all active:scale-95"
            >
              <i className="fas fa-file-excel"></i>
              XUẤT DỮ LIỆU NGAY
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

