import React, { useState, useMemo } from 'react';
import { Task, ReportTemplate } from '../types';

interface ExportModalProps {
  tasks: Task[];
  templates: ReportTemplate[];
  onSaveTemplate: (template: ReportTemplate) => void;
  onDeleteTemplate: (id: string) => void;
  onClose: () => void;
}

const ExportModal: React.FC<ExportModalProps> = ({ tasks, templates, onSaveTemplate, onDeleteTemplate, onClose }) => {
  const todayStr = new Date().toISOString().split('T')[0];
  const [startDate, setStartDate] = useState(todayStr);
  const [endDate, setEndDate] = useState(todayStr);
  const [templateName, setTemplateName] = useState('');
  const [columns, setColumns] = useState({
    company: true,
    content: true,
    status: true,
    priority: true,
    date: true
  });

  const filteredTasks = useMemo(() => {
    return tasks.filter(t => {
      const taskDate = t.createdAt.split('T')[0];
      return taskDate >= startDate && taskDate <= endDate;
    });
  }, [tasks, startDate, endDate]);

  const handleApplyTemplate = (tpl: ReportTemplate) => {
    setColumns(tpl.columns);
    setTemplateName(tpl.name);
  };

  const handleSaveTemplate = () => {
    if (!templateName.trim()) {
      alert("Vui lòng nhập tên mẫu báo cáo để lưu hoặc chỉnh sửa");
      return;
    }
    const newTemplate: ReportTemplate = {
      id: crypto.randomUUID(),
      name: templateName,
      columns: { ...columns }
    };
    onSaveTemplate(newTemplate);
    alert("Đã lưu cấu hình báo cáo thành công!");
  };

  const handleExport = () => {
    if (filteredTasks.length === 0) {
      alert("Không có dữ liệu trong khoảng thời gian đã chọn để xuất báo cáo.");
      return;
    }

    const headers = [];
    if (columns.date) headers.push('Ngày tạo');
    if (columns.company) headers.push('Công ty');
    if (columns.content) headers.push('Nội dung công việc');
    if (columns.status) headers.push('Trạng thái');
    if (columns.priority) headers.push('Mức độ');

    const csvRows = filteredTasks.map(t => {
      const row = [];
      if (columns.date) row.push(`"${new Date(t.createdAt).toLocaleDateString('vi-VN')}"`);
      if (columns.company) row.push(`"${t.company}"`);
      if (columns.content) row.push(`"${t.content.replace(/"/g, '""')}"`);
      if (columns.status) row.push(`"${t.status === 'DONE' ? 'Đã xong' : t.status === 'IN_PROGRESS' ? 'Đang làm' : 'Chưa làm'}"`);
      if (columns.priority) row.push(`"${t.isPriority ? 'Gấp' : 'Thường'}"`);
      return row.join(',');
    });

    const csvString = [headers.join(','), ...csvRows].join('\n');
    const blob = new Blob(['\ufeff' + csvString], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `ZenTask_Export_${startDate}_${endDate}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="w-full max-w-7xl bg-white rounded-[3rem] shadow-2xl flex flex-col md:flex-row max-h-[90vh] overflow-hidden animate-in zoom-in-95 duration-300">

        {/* Cột trái: Quản lý Mẫu */}
        <div className="w-full md:w-72 bg-slate-50 border-r border-slate-100 p-8 flex flex-col flex-shrink-0">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-6 flex items-center gap-2">
            <i className="fas fa-layer-group text-blue-500"></i> Mẫu đã lưu
          </h3>
          <div className="flex-1 overflow-y-auto space-y-3 custom-scrollbar pr-2 mb-6">
            {templates.length === 0 ? (
              <p className="text-[10px] text-slate-400 font-bold italic uppercase tracking-wider text-center py-10 opacity-50">Trống mẫu báo cáo</p>
            ) : (
              templates.map(tpl => (
                <div key={tpl.id} className="group relative">
                  <button 
                    onClick={() => handleApplyTemplate(tpl)}
                    className="w-full text-left p-4 bg-white border border-slate-200 rounded-2xl hover:border-blue-400 hover:shadow-sm transition-all text-[11px] font-black text-slate-600 uppercase tracking-widest"
                  >
                    {tpl.name}
                  </button>
                  <button 
                    onClick={() => onDeleteTemplate(tpl.id)}
                    className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all p-2"
                  >
                    <i className="fas fa-trash-alt text-[10px]"></i>
                  </button>
                </div>
              ))
            )}
          </div>
          <div className="mt-auto space-y-2">
            <input 
              value={templateName}
              onChange={(e) => setTemplateName(e.target.value)}
              placeholder="Tên mẫu báo cáo..."
              className="w-full p-4 bg-white border border-slate-200 rounded-2xl text-xs font-bold outline-none focus:ring-2 focus:ring-blue-500 shadow-inner"
            />
            <button 
              onClick={handleSaveTemplate}
              className="w-full py-4 bg-blue-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-blue-700 transition-all shadow-lg shadow-blue-100"
            >
              Lưu/Sửa Mẫu
            </button>
          </div>
        </div>

        {/* Vùng chính: Thiết lập và Xem trước */}
        <div className="flex-1 flex flex-col min-w-0">
          <header className="p-8 border-b border-slate-100 flex items-center justify-between">
            <div>
              <h2 className="text-3xl font-black text-slate-800 tracking-tight">CẤU HÌNH BÁO CÁO</h2>
              <p className="text-sm text-slate-500 font-medium mt-1">Tùy chỉnh khoảng ngày và các cột hiển thị trong file Excel.</p>
            </div>
            <button onClick={onClose} className="w-12 h-12 flex items-center justify-center rounded-2xl hover:bg-slate-50 text-slate-300 hover:text-slate-600 transition-all">
              <i className="fas fa-times text-xl"></i>
            </button>
          </header>

          <div className="flex-1 overflow-y-auto p-8 custom-scrollbar space-y-10">
            {/* Lọc thời gian */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 bg-slate-50 p-6 rounded-[2.5rem] border border-slate-100">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Từ ngày</label>
                <input 
                  type="date" 
                  value={startDate}
                  onChange={(e) => setStartDate(e.target.value)}
                  className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold text-slate-700 outline-none focus:ring-2 focus:ring-blue-500 shadow-sm"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Đến ngày</label>
                <input 
                  type="date" 
                  value={endDate}
                  onChange={(e) => setEndDate(e.target.value)}
                  className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold text-slate-700 outline-none focus:ring-2 focus:ring-blue-500 shadow-sm"
                />
              </div>
            </div>

            {/* Chọn cột */}
            <div className="space-y-4">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Cấu trúc các cột thông tin</p>
              <div className="flex flex-wrap gap-3">
                {Object.entries(columns).map(([key, value]) => (
                  <button 
                    key={key}
                    onClick={() => setColumns({...columns, [key]: !value})}
                    className={`px-6 py-4 rounded-2xl border font-black text-[10px] uppercase tracking-widest transition-all flex items-center gap-3 ${
                      value ? 'bg-slate-900 border-slate-900 text-white shadow-xl scale-105' : 'bg-white border-slate-200 text-slate-400 hover:border-slate-400'
                    }`}
                  >
                    <i className={`fas ${value ? 'fa-check-circle' : 'fa-circle-notch opacity-30'}`}></i>
                    {key === 'company' ? 'Công ty' : key === 'content' ? 'Nội dung' : key === 'status' ? 'Trạng thái' : key === 'priority' ? 'Ưu tiên' : 'Ngày tạo'}
                  </button>
                ))}
              </div>
            </div>

            {/* Xem trước (Preview) */}
            <div className="space-y-4">
              <div className="flex items-center justify-between ml-1">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Xem trước định dạng (Preview)</p>
                <span className="text-[9px] font-bold text-blue-500 bg-blue-50 px-3 py-1 rounded-full">{filteredTasks.length} kết quả tìm thấy</span>
              </div>
              <div className="border border-slate-200 rounded-3xl overflow-hidden bg-white shadow-sm overflow-x-auto">
                <table className="w-full text-left border-collapse min-w-[600px]">
                  <thead>
                    <tr className="bg-slate-50 border-b border-slate-100">
                      {columns.date && <th className="p-4 text-[10px] font-black text-slate-500 uppercase tracking-widest border-r border-slate-100">Ngày</th>}
                      {columns.company && <th className="p-4 text-[10px] font-black text-slate-500 uppercase tracking-widest border-r border-slate-100">Công ty</th>}
                      {columns.content && <th className="p-4 text-[10px] font-black text-slate-500 uppercase tracking-widest border-r border-slate-100">Nội dung</th>}
                      {columns.status && <th className="p-4 text-[10px] font-black text-slate-500 uppercase tracking-widest border-r border-slate-100">Trạng thái</th>}
                      {columns.priority && <th className="p-4 text-[10px] font-black text-slate-500 uppercase tracking-widest">Mức độ</th>}
                    </tr>
                  </thead>
                  <tbody className="text-xs font-bold text-slate-600">
                    {filteredTasks.length === 0 ? (
                      <tr>
                        <td colSpan={5} className="p-10 text-center text-slate-300 italic">Không có dữ liệu hiển thị cho khoảng thời gian này</td>
                      </tr>
                    ) : (
                      filteredTasks.slice(0, 5).map(t => (
                        <tr key={t.id} className="border-b border-slate-50 hover:bg-slate-50/50 transition-colors">
                          {columns.date && <td className="p-4 border-r border-slate-100 text-slate-400">{new Date(t.createdAt).toLocaleDateString('vi-VN')}</td>}
                          {columns.company && <td className="p-4 border-r border-slate-100"><span className="bg-slate-100 px-2 py-1 rounded-lg text-[10px]">{t.company}</span></td>}
                          {columns.content && <td className="p-4 border-r border-slate-100 truncate max-w-[200px]">{t.content}</td>}
                          {columns.status && <td className="p-4 border-r border-slate-100">{t.status === 'DONE' ? 'Đã xong' : 'Đang làm'}</td>}
                          {columns.priority && <td className="p-4">{t.isPriority ? '🔥 Gấp' : 'Thường'}</td>}
                        </tr>
                      ))
                    )}
                    {filteredTasks.length > 5 && (
                      <tr>
                        <td colSpan={5} className="p-3 text-center bg-slate-50/50 text-[9px] font-black text-slate-400 uppercase tracking-[0.3em]">
                          ... và {filteredTasks.length - 5} mục khác sẽ được xuất file ...
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>

          <footer className="p-8 border-t border-slate-100 flex items-center justify-end gap-6 bg-slate-50/30">
            <button onClick={onClose} className="text-[10px] font-black text-slate-400 hover:text-slate-600 uppercase tracking-widest px-6">Đóng thiết lập</button>
            <button 
              onClick={handleExport}
              disabled={filteredTasks.length === 0}
              className="bg-emerald-600 hover:bg-emerald-700 disabled:opacity-30 disabled:hover:bg-emerald-600 text-white font-black py-4 px-10 rounded-2xl shadow-xl shadow-emerald-100 flex items-center gap-3 transition-all active:scale-95"
            >
              <i className="fas fa-file-excel"></i>
              TẢI FILE EXCEL (.CSV)
            </button>
          </footer>
        </div>
      </div>
    </div>
  );
};

