import React from 'react';
import { Task, TaskStatus } from '../types';
import { STATUS_LABELS } from '../constants';

interface TaskItemProps {
  task: Task;
  onStatusChange?: (id: string, status: TaskStatus) => void;
  onDelete?: (id: string) => void;
  readOnly?: boolean;
}

const getCompanyColor = (company: string) => {
  const colors = [
    { bg: 'bg-blue-50', text: 'text-blue-600', border: 'border-blue-200', badge: 'bg-blue-600', light: 'bg-blue-100' },
    { bg: 'bg-emerald-50', text: 'text-emerald-600', border: 'border-emerald-200', badge: 'bg-emerald-600', light: 'bg-emerald-100' },
    { bg: 'bg-indigo-50', text: 'text-indigo-600', border: 'border-indigo-200', badge: 'bg-indigo-600', light: 'bg-indigo-100' },
    { bg: 'bg-amber-50', text: 'text-amber-600', border: 'border-amber-200', badge: 'bg-amber-600', light: 'bg-amber-100' },
    { bg: 'bg-violet-50', text: 'text-violet-600', border: 'border-violet-200', badge: 'bg-violet-600', light: 'bg-violet-100' },
    { bg: 'bg-cyan-50', text: 'text-cyan-600', border: 'border-cyan-200', badge: 'bg-cyan-600', light: 'bg-cyan-100' },
    { bg: 'bg-orange-50', text: 'text-orange-600', border: 'border-orange-200', badge: 'bg-orange-600', light: 'bg-orange-100' },
    { bg: 'bg-fuchsia-50', text: 'text-fuchsia-600', border: 'border-fuchsia-200', badge: 'bg-fuchsia-600', light: 'bg-fuchsia-100' },
  ];

  let hash = 0;
  for (let i = 0; i < company.length; i++) {
    hash = company.charCodeAt(i) + ((hash << 5) - hash);
  }
  return colors[Math.abs(hash) % colors.length];
};

const TaskItem: React.FC<TaskItemProps> = ({ task, onStatusChange, onDelete, readOnly = false }) => {
  const formattedTime = new Date(task.createdAt).toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' });
  const cpColor = getCompanyColor(task.company);
  const isDone = task.status === TaskStatus.DONE;
  const isInProgress = task.status === TaskStatus.IN_PROGRESS;

  return (
    <div className={`group p-6 rounded-[1.5rem] border-l-[6px] border-t border-r border-b transition-all flex flex-col sm:flex-row items-start sm:items-center gap-6 ${
      isDone ? 'opacity-50 grayscale bg-slate-50 border-slate-200' : 
      task.isPriority ? 'bg-rose-50/50 border-rose-200 border-l-rose-500' : 
      `${cpColor.bg} ${cpColor.border} border-l-${cpColor.badge.replace('bg-', '')}`
    } ${!isDone && !readOnly && 'hover:shadow-xl hover:scale-[1.01] active:scale-100'}`}>

      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-3 mb-2 flex-wrap">
          {isInProgress && (
            <span className="flex items-center gap-1.5 text-[9px] font-black px-2.5 py-1 rounded-full bg-blue-600 text-white uppercase tracking-widest animate-pulse">
              <i className="fas fa-spinner fa-spin text-[8px]"></i> Đang làm
            </span>
          )}
          {task.isPriority && (
            <span className="flex items-center gap-1.5 text-[9px] font-black px-2.5 py-1 rounded-full bg-rose-500 text-white uppercase tracking-widest shadow-sm shadow-rose-200">
              <i className="fas fa-bolt text-[8px]"></i> Việc Gấp
            </span>
          )}
          <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest ${
            task.isPriority ? 'bg-rose-100 text-rose-700' : `${cpColor.light} ${cpColor.text}`
          }`}>
            {task.company}
          </span>
          <span className="text-[10px] text-slate-400 font-bold uppercase tracking-tight">
            <i className="far fa-clock mr-1.5"></i> {formattedTime}
          </span>
        </div>
        <p className={`text-slate-800 font-bold text-lg leading-snug ${isDone ? 'line-through opacity-40' : ''}`}>
          {task.content}
        </p>
      </div>

      {!readOnly && (
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <div className={`flex p-1.5 rounded-2xl border bg-white/60 backdrop-blur-sm ${task.isPriority ? 'border-rose-100' : cpColor.border}`}>
            {(Object.values(TaskStatus) as TaskStatus[]).map((status) => (
              <button
                key={status}
                onClick={() => onStatusChange?.(task.id, status)}
                className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                  task.status === status
                    ? STATUS_LABELS[status].color + " shadow-sm scale-105"
                    : 'text-slate-400 hover:bg-white hover:text-slate-600'
                }`}
              >
                {STATUS_LABELS[status].label}
              </button>
            ))}
          </div>
          <button
            onClick={() => onDelete?.(task.id)}
            className="w-10 h-10 rounded-xl flex items-center justify-center text-slate-300 hover:text-red-500 hover:bg-red-50 transition-all opacity-0 group-hover:opacity-100"
          >
            <i className="fas fa-times"></i>
          </button>
        </div>
      )}

      {readOnly && (
        <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-slate-400">
           <i className="fas fa-lock text-[8px]"></i> {STATUS_LABELS[task.status].label}
        </div>
      )}
    </div>
  );
};

