import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import TaskItem from './components/TaskItem';
import Login from './components/Login';
import Setup from './components/Setup';
import HistoryModal from './components/HistoryModal';
import ExportModal from './components/ExportModal';
import { Task, TaskStatus, AppState, ReportTemplate } from './types';
import { loadStateSecure, saveStateSecure } from './services/storageService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<{email: string, pass: string} | null>(null);
  const [state, setState] = useState<AppState | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [loading, setLoading] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isExportOpen, setIsExportOpen] = useState(false);

  const handleLogin = async (email: string, pass: string) => {
    setLoading(true);
    try {
      const loaded = await loadStateSecure(email, pass);
      setCurrentUser({ email, pass });
      setState(loaded);
    } catch (e: any) { alert(e.message); }
    finally { setLoading(false); }
  };

  const handleSetupComplete = (companies: string[]) => {
    setState(prev => prev ? ({ ...prev, companies }) : null);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setState(null);
  };

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (currentUser && state) saveStateSecure(currentUser.email, currentUser.pass, state);
  }, [state, currentUser]);

  const addTask = useCallback((content: string, company: string, isPriority: boolean) => {
    if (!state) return;
    const newTask: Task = {
      id: crypto.randomUUID(),
      content,
      company,
      createdAt: new Date().toISOString(),
      status: TaskStatus.NOT_STARTED,
      isPriority
    };
    setState(prev => prev ? ({ ...prev, tasks: [newTask, ...prev.tasks] }) : null);
  }, [state]);

  const addCompany = useCallback((companyName: string) => {
    setState(prev => prev ? ({ ...prev, companies: Array.from(new Set([...prev.companies, companyName])) }) : null);
  }, []);

  const updateTaskStatus = useCallback((id: string, status: TaskStatus) => {
    setState(prev => prev ? ({ ...prev, tasks: prev.tasks.map(t => t.id === id ? { ...t, status } : t) }) : null);
  }, []);

  const deleteTask = useCallback((id: string) => {
    if (!confirm("Bạn muốn xóa vĩnh viễn công việc này?")) return;
    setState(prev => prev ? ({ ...prev, tasks: prev.tasks.filter(t => t.id !== id) }) : null);
  }, []);

  const saveReportTemplate = useCallback((template: ReportTemplate) => {
    setState(prev => {
      if (!prev) return null;
      const templates = prev.reportTemplates || [];
      const existingIdx = templates.findIndex(t => t.name === template.name);
      if (existingIdx >= 0) {
        const newTemplates = [...templates];
        newTemplates[existingIdx] = template;
        return { ...prev, reportTemplates: newTemplates };
      }
      return { ...prev, reportTemplates: [...templates, template] };
    });
  }, []);

  const deleteReportTemplate = useCallback((id: string) => {
    setState(prev => {
      if (!prev) return null;
      const templates = prev.reportTemplates || [];
      return { ...prev, reportTemplates: templates.filter(tpl => tpl.id !== id) };
    });
  }, []);

  const currentViewTasks = useMemo(() => {
    if (!state) return [];
    const today = new Date().toISOString().split('T')[0];
    return state.tasks.filter(t => {
      if (t.status !== TaskStatus.DONE) return true;
      return t.createdAt.startsWith(today);
    }).sort((a, b) => {
      const getRank = (task: Task) => {
        if (task.status === TaskStatus.IN_PROGRESS) return 0;
        if (task.isPriority) return 1;
        if (task.status === TaskStatus.NOT_STARTED) return 2;
        return 3;
      };
      const rankA = getRank(a), rankB = getRank(b);
      if (rankA !== rankB) return rankA - rankB;
      return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
    });
  }, [state]);

  if (loading) return (
    <div className="h-screen bg-white flex flex-col items-center justify-center text-blue-600">
      <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
      <p className="font-black uppercase tracking-[0.2em] text-[10px]">Đang truy xuất dữ liệu...</p>
    </div>
  );

  if (!currentUser || !state) return <Login onLogin={handleLogin} />;
  if (state.companies.length === 0) return <Setup onComplete={handleSetupComplete} onLogout={handleLogout} />;

  const activeCount = state.tasks.filter(t => t.status !== TaskStatus.DONE).length;
  const doneTodayCount = state.tasks.filter(t => t.status === TaskStatus.DONE && t.createdAt.startsWith(new Date().toISOString().split('T')[0])).length;

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-white">
      <Sidebar 
        email={currentUser.email}
        companies={state.companies}
        onAddTask={addTask} 
        onAddCompany={addCompany}
        onClearAll={() => { if(confirm("Xóa toàn bộ kho lưu trữ vĩnh viễn?")) setState({ ...state, tasks: [] }); }} 
        onLogout={handleLogout}
        onOpenHistory={() => setIsHistoryOpen(true)}
        onOpenExport={() => setIsExportOpen(true)}
      />

      <main className="flex-1 flex flex-col min-w-0 bg-slate-50 relative">
        <header className="h-24 px-10 bg-white border-b border-slate-100 flex items-center justify-between z-10 shadow-sm">
          <div>
            <h2 className="text-2xl font-black text-slate-800 tracking-tight">CÔNG VIỆC HIỆN TẠI</h2>
            <div className="flex items-center gap-2 mt-1">
              <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                {currentTime.toLocaleDateString('vi-VN', { weekday: 'long', day: 'numeric', month: 'long' })}
              </p>
            </div>
          </div>

          <div className="flex items-center gap-8">
            <div className="text-right">
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Đang làm</p>
              <p className="text-2xl font-black text-rose-500 leading-tight">{activeCount}</p>
            </div>
            <div className="text-right">
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Xong hôm nay</p>
              <p className="text-2xl font-black text-emerald-500 leading-tight">{doneTodayCount}</p>
            </div>
            <div className="h-10 w-px bg-slate-100"></div>
            <div className="text-right">
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Hệ thống</p>
              <p className="text-2xl font-mono font-bold text-slate-800 leading-tight">{currentTime.toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' })}</p>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-10 custom-scrollbar">
          {currentViewTasks.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-300 opacity-50">
              <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center mb-6 shadow-sm border border-slate-100">
                <i className="fas fa-clipboard-check text-4xl"></i>
              </div>
              <p className="font-black uppercase tracking-widest text-sm">Danh sách sạch sẽ</p>
            </div>
          ) : (
            <div className="max-w-4xl mx-auto space-y-4 pb-24">
              {currentViewTasks.map((task) => (
                <TaskItem key={task.id} task={task} onStatusChange={updateTaskStatus} onDelete={deleteTask} />
              ))}
            </div>
          )}
        </div>

        <div className="absolute bottom-6 right-10 flex items-center gap-2 px-4 py-2 bg-white border border-slate-100 rounded-full shadow-lg text-[10px] font-black text-slate-400 uppercase tracking-widest">
           <i className="fas fa-database text-blue-500"></i> Dữ liệu: {state.tasks.length}
        </div>
      </main>

      {isHistoryOpen && (
        <HistoryModal 
          tasks={state.tasks} 
          onClose={() => setIsHistoryOpen(false)} 
        />
      )}
      {isExportOpen && (
        <ExportModal 
          tasks={state.tasks} 
          templates={state.reportTemplates || []}
          onSaveTemplate={saveReportTemplate}
          onDeleteTemplate={deleteReportTemplate}
          onClose={() => setIsExportOpen(false)} 
        />
      )}
    </div>
  );
};

export default App;

export enum TaskStatus {
  NOT_STARTED = 'NOT_STARTED',
  IN_PROGRESS = 'IN_PROGRESS',
  DONE = 'DONE'
}

export interface Task {
  id: string;
  content: string;
  company: string;
  createdAt: string; // ISO String
  status: TaskStatus;
  isPriority: boolean; // Công việc gấp/ưu tiên
}

export interface User {
  email: string;
  password: string;
}

export type ReportLayout = 'FLAT' | 'GROUPED_BY_COMPANY';

export interface ReportTemplate {
  id: string;
  name: string;
  layout: ReportLayout;
  columns: {
    company: boolean;
    content: boolean;
    status: boolean;
    priority: boolean;
    date: boolean;
    pendingTasks: boolean;
  };
}

export interface AppState {
  email: string;
  tasks: Task[];
  companies: string[];
  lastLaunchDate: string;
  reportTemplates?: ReportTemplate[];
}

import React, { useState, useMemo } from 'react';
import { Task, ReportTemplate, ReportLayout, TaskStatus } from '../types';

interface ExportModalProps {
  tasks: Task[];
  templates: ReportTemplate[];
  onSaveTemplate: (template: ReportTemplate) => void;
  onDeleteTemplate: (id: string) => void;
  onClose: () => void;
}

const ExportModal: React.FC<ExportModalProps> = ({ tasks, templates, onSaveTemplate, onDeleteTemplate, onClose }) => {
  const todayStr = new Date().toISOString().split('T')[0];
  const [startDate, setStartDate] = useState(todayStr);
  const [endDate, setEndDate] = useState(todayStr);
  const [templateName, setTemplateName] = useState('');
  const [layout, setLayout] = useState<ReportLayout>('FLAT');
  const [columns, setColumns] = useState({
    company: true,
    content: true,
    status: true,
    priority: true,
    date: true,
    pendingTasks: true
  });

  const filteredTasks = useMemo(() => {
    return tasks.filter(t => {
      const taskDate = t.createdAt.split('T')[0];
      return taskDate >= startDate && taskDate <= endDate;
    });
  }, [tasks, startDate, endDate]);

  const groupedTasks = useMemo<Record<string, Task[]> | null>(() => {
    if (layout !== 'GROUPED_BY_COMPANY') return null;
    const groups: Record<string, Task[]> = {};
    filteredTasks.forEach(task => {
      if (!groups[task.company]) groups[task.company] = [];
      groups[task.company].push(task);
    });
    return groups;
  }, [filteredTasks, layout]);

  const handleApplyTemplate = (tpl: ReportTemplate) => {
    setColumns({ ...tpl.columns });
    setLayout(tpl.layout || 'FLAT');
    setTemplateName(tpl.name);
  };

  const handleSaveTemplate = () => {
    if (!templateName.trim()) {
      alert("Vui lòng nhập tên để lưu mẫu cấu hình này");
      return;
    }
    const newTemplate: ReportTemplate = {
      id: crypto.randomUUID(),
      name: templateName,
      layout,
      columns: { ...columns }
    };
    onSaveTemplate(newTemplate);
    alert("Đã lưu cấu hình báo cáo thành công!");
  };

  const generateCSV = () => {
    const csvRows: string[] = [];
    const headers = [];

    if (columns.company) headers.push('Công ty');
    if (columns.content) headers.push('Nội dung công việc');
    if (columns.pendingTasks) headers.push('Công việc đang làm');

    if (layout === 'FLAT') {
      if (columns.date) headers.push('Ngày');
      if (columns.status) headers.push('Trạng thái');
      if (columns.priority) headers.push('Mức độ');
    }

    csvRows.push(headers.join(','));

    if (layout === 'FLAT') {
      filteredTasks.forEach(t => {
        const row = [];
        if (columns.company) row.push(`"${t.company}"`);
        if (columns.content) row.push(`"${t.content.replace(/"/g, '""')}"`);
        if (columns.pendingTasks) {
          const isPending = t.status !== TaskStatus.DONE;
          row.push(`"${isPending ? t.content.replace(/"/g, '""') : ''}"`);
        }
        if (columns.date) row.push(`"${new Date(t.createdAt).toLocaleDateString('vi-VN')}"`);
        if (columns.status) row.push(`"${t.status === 'DONE' ? 'Xong' : 'Đang làm'}"`);
        if (columns.priority) row.push(`"${t.isPriority ? 'Gấp' : 'Thường'}"`);
        csvRows.push(row.join(','));
      });
    } else {
      // Grouped by Company - One row per company
      (Object.entries(groupedTasks || {}) as [string, Task[]][]).forEach(([company, tasks]) => {
        const row = [];
        if (columns.company) row.push(`"${company.toUpperCase()}"`);

        // Gộp tất cả đầu việc vào 1 ô duy nhất
        if (columns.content) {
          const combinedContent = tasks.map((t, idx) => `${idx + 1}. ${t.content}`).join('\n');
          row.push(`"${combinedContent.replace(/"/g, '""')}"`);
        }

        // Cột công việc đang làm: chỉ lấy những việc chưa xong
        if (columns.pendingTasks) {
          const pending = tasks.filter(t => t.status !== TaskStatus.DONE);
          const combinedPending = pending.map((t, idx) => `${idx + 1}. ${t.content}`).join('\n');
          row.push(`"${combinedPending.replace(/"/g, '""')}"`);
        }

        csvRows.push(row.join(','));
      });
    }

    return '\ufeff' + csvRows.join('\n');
  };

  const handleExport = () => {
    if (filteredTasks.length === 0) {
      alert("Không có dữ liệu để xuất.");
      return;
    }
    const csvContent = generateCSV();
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `ZenTask_BaoCao_${layout === 'FLAT' ? 'Phang' : 'Nhom'}_${startDate}.csv`;
    link.click();
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="w-full max-w-7xl bg-white rounded-[3rem] shadow-2xl flex flex-col md:flex-row max-h-[95vh] overflow-hidden animate-in zoom-in-95 duration-300">

        <div className="w-full md:w-72 bg-slate-50 border-r border-slate-100 p-8 flex flex-col flex-shrink-0">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-6">Mẫu của bạn</h3>
          <div className="flex-1 overflow-y-auto space-y-3 custom-scrollbar pr-2 mb-6">
            {templates.map(tpl => (
              <div key={tpl.id} className="group relative">
                <button 
                  onClick={() => handleApplyTemplate(tpl)}
                  className="w-full text-left p-4 bg-white border border-slate-200 rounded-2xl hover:border-blue-400 hover:shadow-sm transition-all text-[11px] font-black text-slate-600 uppercase"
                >
                  {tpl.name}
                </button>
                <button 
                  onClick={() => onDeleteTemplate(tpl.id)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all p-2"
                >
                  <i className="fas fa-trash-alt text-[10px]"></i>
                </button>
              </div>
            ))}
          </div>
          <div className="space-y-2">
            <input 
              value={templateName}
              onChange={(e) => setTemplateName(e.target.value)}
              placeholder="Tên mẫu mới..."
              className="w-full p-4 bg-white border border-slate-200 rounded-2xl text-xs font-bold outline-none shadow-inner"
            />
            <button 
              onClick={handleSaveTemplate}
              className="w-full py-4 bg-slate-800 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-black transition-all"
            >
              Lưu mẫu hiện tại
            </button>
          </div>
        </div>

        <div className="flex-1 flex flex-col min-w-0">
          <header className="p-8 border-b border-slate-100 flex items-center justify-between">
            <div>
              <h2 className="text-3xl font-black text-slate-800 tracking-tight uppercase">Thiết kế báo cáo</h2>
              <p className="text-sm text-slate-500 font-medium">Tùy chỉnh hàng, cột và cách trình bày dữ liệu.</p>
            </div>
            <button onClick={onClose} className="w-12 h-12 flex items-center justify-center rounded-2xl hover:bg-slate-50 text-slate-300">
              <i className="fas fa-times text-xl"></i>
            </button>
          </header>

          <div className="flex-1 overflow-y-auto p-8 custom-scrollbar space-y-10">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Bắt đầu</label>
                <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Kết thúc</label>
                <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold" />
              </div>
            </div>

            <div className="space-y-4">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Kiểu trình bày (Hàng)</p>
              <div className="flex gap-4">
                <button 
                  onClick={() => setLayout('FLAT')}
                  className={`flex-1 p-5 rounded-[2rem] border-2 transition-all text-left ${layout === 'FLAT' ? 'border-blue-600 bg-blue-50' : 'border-slate-100 hover:border-slate-200 bg-white'}`}
                >
                  <div className={`w-10 h-10 rounded-xl mb-3 flex items-center justify-center ${layout === 'FLAT' ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-400'}`}>
                    <i className="fas fa-list-ul"></i>
                  </div>
                  <p className="font-black text-xs uppercase tracking-widest text-slate-800">Danh sách phẳng</p>
                  <p className="text-[10px] text-slate-500 mt-1">Hàng: Từng công việc riêng lẻ.</p>
                </button>

                <button 
                  onClick={() => setLayout('GROUPED_BY_COMPANY')}
                  className={`flex-1 p-5 rounded-[2rem] border-2 transition-all text-left ${layout === 'GROUPED_BY_COMPANY' ? 'border-indigo-600 bg-indigo-50' : 'border-slate-100 hover:border-slate-200 bg-white'}`}
                >
                  <div className={`w-10 h-10 rounded-xl mb-3 flex items-center justify-center ${layout === 'GROUPED_BY_COMPANY' ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}>
                    <i className="fas fa-layer-group"></i>
                  </div>
                  <p className="font-black text-xs uppercase tracking-widest text-slate-800">Gộp theo Công ty</p>
                  <p className="text-[10px] text-slate-500 mt-1">Hàng: 1 Công ty = 1 Ô nội dung chứa tất cả việc.</p>
                </button>
              </div>
            </div>

            <div className="space-y-4">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Các cột thông tin</p>
              <div className="flex flex-wrap gap-2">
                {Object.entries(columns).map(([key, value]) => (
                  <button 
                    key={key}
                    onClick={() => setColumns({...columns, [key as keyof typeof columns]: !value})}
                    className={`px-6 py-3 rounded-2xl border font-black text-[10px] uppercase tracking-widest transition-all ${
                      value ? 'bg-slate-900 text-white border-slate-900 shadow-lg' : 'bg-white text-slate-400 border-slate-200'
                    }`}
                  >
                    {key === 'company' ? 'Công ty' : 
                     key === 'content' ? 'Nội dung' : 
                     key === 'status' ? 'Trạng thái' : 
                     key === 'priority' ? 'Ưu tiên' : 
                     key === 'date' ? 'Ngày' : 'Việc đang làm'}
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-4">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Xem trước định dạng (Preview)</p>
              <div className="border border-slate-100 rounded-[2.5rem] bg-white shadow-sm overflow-hidden overflow-x-auto min-h-[200px]">
                  <table className="w-full text-left text-xs border-collapse">
                    <thead className="bg-slate-50 border-b border-slate-100 font-black text-slate-400 uppercase tracking-tighter">
                      <tr>
                        {columns.company && <th className="p-4 border-r border-slate-100">Công ty</th>}
                        {columns.content && <th className="p-4 border-r border-slate-100">Nội dung công việc (Gộp)</th>}
                        {columns.pendingTasks && <th className="p-4 border-r border-slate-100">Công việc đang làm</th>}
                        {layout === 'FLAT' && columns.date && <th className="p-4 border-r border-slate-100">Ngày</th>}
                        {layout === 'FLAT' && columns.status && <th className="p-4">Trạng thái</th>}
                      </tr>
                    </thead>
                    <tbody className="font-bold text-slate-700">
                      {layout === 'FLAT' ? (
                        filteredTasks.slice(0, 5).map(t => (
                          <tr key={t.id} className="border-b border-slate-50">
                            {columns.company && <td className="p-4 border-r border-slate-100">{t.company}</td>}
                            {columns.content && <td className="p-4 border-r border-slate-100 truncate max-w-[200px]">{t.content}</td>}
                            {columns.pendingTasks && <td className="p-4 border-r border-slate-100">{t.status !== TaskStatus.DONE ? t.content : '-'}</td>}
                            {columns.date && <td className="p-4 border-r border-slate-100 text-slate-400">{new Date(t.createdAt).toLocaleDateString('vi-VN')}</td>}
                            {columns.status && <td className="p-4">{t.status === 'DONE' ? 'Xong' : 'Làm'}</td>}
                          </tr>
                        ))
                      ) : (
                        (Object.entries(groupedTasks || {}) as [string, Task[]][]).slice(0, 5).map(([company, tks]) => (
                          <tr key={company} className="border-b border-slate-50">
                            {columns.company && <td className="p-4 border-r border-slate-100 bg-slate-50/30 align-top uppercase">{company}</td>}
                            {columns.content && (
                              <td className="p-4 border-r border-slate-100 whitespace-pre-line leading-relaxed align-top">
                                {tks.map((tk, i) => `${i + 1}. ${tk.content}`).join('\n')}
                              </td>
                            )}
                            {columns.pendingTasks && (
                              <td className="p-4 border-r border-slate-100 whitespace-pre-line leading-relaxed align-top text-blue-600">
                                {tks.filter(tk => tk.status !== TaskStatus.DONE).map((tk, i) => `${i + 1}. ${tk.content}`).join('\n') || 'Trống'}
                              </td>
                            )}
                          </tr>
                        ))
                      )}
                    </tbody>
                  </table>
              </div>
            </div>
          </div>

          <footer className="p-8 border-t border-slate-100 flex items-center justify-end gap-6 bg-slate-50/20">
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{filteredTasks.length} mục dữ liệu</span>
            <button onClick={handleExport} className="bg-emerald-600 hover:bg-emerald-700 text-white font-black py-4 px-12 rounded-2xl shadow-xl shadow-emerald-100 flex items-center gap-3 active:scale-95 transition-all">
              <i className="fas fa-file-excel"></i> XUẤT FILE (.CSV)
            </button>
          </footer>
        </div>
      </div>
    </div>
  );
};

