export const STATUS_LABELS: Record<string, { label: string; color: string }> = {
  NOT_STARTED: { label: 'Chưa làm', color: 'bg-slate-200 text-slate-700' },
  IN_PROGRESS: { label: 'Đang làm', color: 'bg-blue-100 text-blue-700 border border-blue-200' },
  DONE: { label: 'Đã xong', color: 'bg-emerald-100 text-emerald-700 border border-emerald-200' }
};

export const getCompanyColor = (company: string) => {
  const colors = [
    { bg: 'bg-blue-50', text: 'text-blue-600', border: 'border-blue-200', badge: 'bg-blue-600', light: 'bg-blue-100' },
    { bg: 'bg-emerald-50', text: 'text-emerald-600', border: 'border-emerald-200', badge: 'bg-emerald-600', light: 'bg-emerald-100' },
    { bg: 'bg-indigo-50', text: 'text-indigo-600', border: 'border-indigo-200', badge: 'bg-indigo-600', light: 'bg-indigo-100' },
    { bg: 'bg-amber-50', text: 'text-amber-600', border: 'border-amber-200', badge: 'bg-amber-600', light: 'bg-amber-100' },
    { bg: 'bg-violet-50', text: 'text-violet-600', border: 'border-violet-200', badge: 'bg-violet-600', light: 'bg-violet-100' },
    { bg: 'bg-cyan-50', text: 'text-cyan-600', border: 'border-cyan-200', badge: 'bg-cyan-600', light: 'bg-cyan-100' },
    { bg: 'bg-orange-50', text: 'text-orange-600', border: 'border-orange-200', badge: 'bg-orange-600', light: 'bg-orange-100' },
    { bg: 'bg-fuchsia-50', text: 'text-fuchsia-600', border: 'border-fuchsia-200', badge: 'bg-fuchsia-600', light: 'bg-fuchsia-100' },
  ];

  let hash = 0;
  for (let i = 0; i < company.length; i++) {
    hash = company.charCodeAt(i) + ((hash << 5) - hash);
  }
  return colors[Math.abs(hash) % colors.length];
};

import React from 'react';
import { Task, TaskStatus } from '../types';
import { STATUS_LABELS, getCompanyColor } from '../constants';

interface TaskItemProps {
  task: Task;
  onStatusChange?: (id: string, status: TaskStatus) => void;
  onDelete?: (id: string) => void;
  readOnly?: boolean;
}

const TaskItem: React.FC<TaskItemProps> = ({ task, onStatusChange, onDelete, readOnly = false }) => {
  const formattedTime = new Date(task.createdAt).toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' });
  const cpColor = getCompanyColor(task.company);
  const isDone = task.status === TaskStatus.DONE;
  const isInProgress = task.status === TaskStatus.IN_PROGRESS;

  return (
    <div className={`group p-6 rounded-[1.5rem] border-l-[6px] border-t border-r border-b transition-all flex flex-col sm:flex-row items-start sm:items-center gap-6 ${
      isDone ? 'opacity-50 grayscale bg-slate-50 border-slate-200' : 
      task.isPriority ? 'bg-rose-50/50 border-rose-200 border-l-rose-500' : 
      `${cpColor.bg} ${cpColor.border} border-l-${cpColor.badge.replace('bg-', '')}`
    } ${!isDone && !readOnly && 'hover:shadow-xl hover:scale-[1.01] active:scale-100'}`}>

      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-3 mb-2 flex-wrap">
          {isInProgress && (
            <span className="flex items-center gap-1.5 text-[9px] font-black px-2.5 py-1 rounded-full bg-blue-600 text-white uppercase tracking-widest animate-pulse">
              <i className="fas fa-spinner fa-spin text-[8px]"></i> Đang làm
            </span>
          )}
          {task.isPriority && (
            <span className="flex items-center gap-1.5 text-[9px] font-black px-2.5 py-1 rounded-full bg-rose-500 text-white uppercase tracking-widest shadow-sm shadow-rose-200">
              <i className="fas fa-bolt text-[8px]"></i> Việc Gấp
            </span>
          )}
          <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest ${
            task.isPriority ? 'bg-rose-100 text-rose-700' : `${cpColor.light} ${cpColor.text}`
          }`}>
            {task.company}
          </span>
          <span className="text-[10px] text-slate-400 font-bold uppercase tracking-tight">
            <i className="far fa-clock mr-1.5"></i> {formattedTime}
          </span>
        </div>
        <p className={`text-slate-800 font-bold text-lg leading-snug ${isDone ? 'line-through opacity-40' : ''}`}>
          {task.content}
        </p>
      </div>

      {!readOnly && (
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <div className={`flex p-1.5 rounded-2xl border bg-white/60 backdrop-blur-sm ${task.isPriority ? 'border-rose-100' : cpColor.border}`}>
            {(Object.values(TaskStatus) as TaskStatus[]).map((status) => (
              <button
                key={status}
                onClick={() => onStatusChange?.(task.id, status)}
                className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                  task.status === status
                    ? STATUS_LABELS[status].color + " shadow-sm scale-105"
                    : 'text-slate-400 hover:bg-white hover:text-slate-600'
                }`}
              >
                {STATUS_LABELS[status].label}
              </button>
            ))}
          </div>
          <button
            onClick={() => onDelete?.(task.id)}
            className="w-10 h-10 rounded-xl flex items-center justify-center text-slate-300 hover:text-red-500 hover:bg-red-50 transition-all opacity-0 group-hover:opacity-100"
          >
            <i className="fas fa-times"></i>
          </button>
        </div>
      )}

      {readOnly && (
        <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-slate-400">
           <i className="fas fa-lock text-[8px]"></i> {STATUS_LABELS[task.status].label}
        </div>
      )}
    </div>
  );
};

export default TaskItem;

import React, { useState, useMemo, useRef } from 'react';
import { Task, ReportTemplate, ReportLayout, TaskStatus } from '../types';
import { getCompanyColor } from '../constants';

interface ExportModalProps {
  tasks: Task[];
  templates: ReportTemplate[];
  onSaveTemplate: (template: ReportTemplate) => void;
  onDeleteTemplate: (id: string) => void;
  onClose: () => void;
}

const ExportModal: React.FC<ExportModalProps> = ({ tasks, templates, onSaveTemplate, onDeleteTemplate, onClose }) => {
  const today = new Date();
  const todayStr = today.toISOString().split('T')[0];
  const currentMonth = today.getMonth() + 1;
  const reportRef = useRef<HTMLDivElement>(null);

  const [startDate, setStartDate] = useState(todayStr);
  const [endDate, setEndDate] = useState(todayStr);
  const [templateName, setTemplateName] = useState('');
  const [layout, setLayout] = useState<ReportLayout>('FLAT');
  const [columns, setColumns] = useState({
    company: true,
    content: true,
    status: true,
    priority: true,
    date: true,
    pendingTasks: true
  });

  const filteredTasks = useMemo(() => {
    return tasks.filter(t => {
      const taskDate = t.createdAt.split('T')[0];
      return taskDate >= startDate && taskDate <= endDate;
    });
  }, [tasks, startDate, endDate]);

  const groupedTasks = useMemo<Record<string, Task[]> | null>(() => {
    if (layout !== 'GROUPED_BY_COMPANY') return null;
    const groups: Record<string, Task[]> = {};
    filteredTasks.forEach(task => {
      if (!groups[task.company]) groups[task.company] = [];
      groups[task.company].push(task);
    });
    return groups;
  }, [filteredTasks, layout]);

  const formatDate = (dateStr: string) => {
    const [y, m, d] = dateStr.split('-');
    return `${d}/${m}/${y}`;
  };

  const handleApplyTemplate = (tpl: ReportTemplate) => {
    setColumns({ ...tpl.columns });
    setLayout(tpl.layout || 'FLAT');
    setTemplateName(tpl.name);
  };

  const handleSaveTemplate = () => {
    if (!templateName.trim()) {
      alert("Vui lòng nhập tên để lưu mẫu cấu hình này");
      return;
    }
    const newTemplate: ReportTemplate = {
      id: crypto.randomUUID(),
      name: templateName,
      layout,
      columns: { ...columns }
    };
    onSaveTemplate(newTemplate);
    alert("Đã lưu cấu hình báo cáo thành công!");
  };

  // --- LOGIC XUẤT FILE ---

  const handleExportCSV = () => {
    const csvRows: string[] = [];
    csvRows.push(`"BÁO CÁO TUẦN THÁNG ${currentMonth}"`);
    csvRows.push(`"Ngày: ${formatDate(startDate)} - ${formatDate(endDate)}"`);
    csvRows.push("");

    const headers: string[] = [];
    if (layout === 'FLAT') {
      if (columns.company) headers.push('Công ty');
      if (columns.content) headers.push('Nội dung công việc');
      if (columns.pendingTasks) headers.push('Công việc đang làm');
      if (columns.date) headers.push('Ngày tạo');
      if (columns.status) headers.push('Trạng thái');
      csvRows.push(headers.join(','));
      filteredTasks.forEach(t => {
        const row = [];
        if (columns.company) row.push(`"${t.company}"`);
        if (columns.content) row.push(`"${t.content.replace(/"/g, '""')}"`);
        if (columns.pendingTasks) row.push(`"${t.status !== TaskStatus.DONE ? t.content.replace(/"/g, '""') : ''}"`);
        if (columns.date) row.push(`"${new Date(t.createdAt).toLocaleDateString('vi-VN')}"`);
        if (columns.status) row.push(`"${t.status === 'DONE' ? 'Xong' : 'Làm'}"`);
        csvRows.push(row.join(','));
      });
    } else {
      headers.push('Công ty', 'Tổng nội dung', 'Đang làm');
      csvRows.push(headers.join(','));
      Object.entries(groupedTasks || {}).forEach(([company, tasks]) => {
        const row = [`"${company.toUpperCase()}"`];
        row.push(`"${tasks.map((t, idx) => `${idx + 1}. ${t.content}`).join('\r\n').replace(/"/g, '""')}"`);
        row.push(`"${tasks.filter(t => t.status !== TaskStatus.DONE).map((t, idx) => `${idx + 1}. ${t.content}`).join('\r\n').replace(/"/g, '""')}"`);
        csvRows.push(row.join(','));
      });
    }

    const blob = new Blob(['\ufeff' + csvRows.join('\n')], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `Bao_Cao_${startDate}.csv`;
    link.click();
  };

  const handleExportWord = () => {
    if (!reportRef.current) return;
    const content = reportRef.current.innerHTML;
    const header = `<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
                    <head><meta charset='utf-8'><title>Báo cáo</title>
                    <style>
                      table { border-collapse: collapse; width: 100%; }
                      th, td { border: 1px solid black; padding: 8px; text-align: left; }
                      .bg-slate-50 { background-color: #f8fafc; }
                    </style>
                    </head><body>`;
    const footer = "</body></html>";
    const sourceHTML = header + content + footer;

    const blob = new Blob(['\ufeff', sourceHTML], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Bao_Cao_${startDate}.doc`;
    link.click();
  };

  const handleExportImage = async () => {
    if (!reportRef.current) return;
    try {
      const canvas = await (window as any).html2canvas(reportRef.current, {
        scale: 2,
        backgroundColor: '#ffffff',
        logging: false
      });
      const dataUrl = canvas.toDataURL('image/png');
      const link = document.createElement('a');
      link.href = dataUrl;
      link.download = `Bao_Cao_${startDate}.png`;
      link.click();
    } catch (err) {
      console.error("Export image failed", err);
      alert("Không thể tạo file ảnh. Vui lòng thử lại.");
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="w-full max-w-7xl bg-white rounded-[3rem] shadow-2xl flex flex-col md:flex-row max-h-[95vh] overflow-hidden animate-in zoom-in-95 duration-300">

        {/* Left Sidebar */}
        <div className="w-full md:w-72 bg-slate-50 border-r border-slate-100 p-8 flex flex-col flex-shrink-0">
