export default ExportModal;

import React, { useState, useMemo, useRef } from 'react';
import { Task, ReportTemplate, ReportLayout, TaskStatus } from '../types';
import { getCompanyColor } from '../constants';

interface ExportModalProps {
  tasks: Task[];
  templates: ReportTemplate[];
  onSaveTemplate: (template: ReportTemplate) => void;
  onDeleteTemplate: (id: string) => void;
  onClose: () => void;
}

const ExportModal: React.FC<ExportModalProps> = ({ tasks, templates, onSaveTemplate, onDeleteTemplate, onClose }) => {
  const today = new Date();
  const todayStr = today.toISOString().split('T')[0];
  const currentMonth = today.getMonth() + 1;
  const reportRef = useRef<HTMLDivElement>(null);

  const [startDate, setStartDate] = useState(todayStr);
  const [endDate, setEndDate] = useState(todayStr);
  const [templateName, setTemplateName] = useState('');
  const [layout, setLayout] = useState<ReportLayout>('FLAT');
  const [columns, setColumns] = useState({
    company: true,
    content: true,
    status: true,
    priority: true,
    date: true,
    pendingTasks: true
  });

  const filteredTasks = useMemo(() => {
    return tasks.filter(t => {
      const taskDate = t.createdAt.split('T')[0];
      return taskDate >= startDate && taskDate <= endDate;
    });
  }, [tasks, startDate, endDate]);

  const groupedTasks = useMemo<Record<string, Task[]> | null>(() => {
    if (layout !== 'GROUPED_BY_COMPANY') return null;
    const groups: Record<string, Task[]> = {};
    filteredTasks.forEach(task => {
      if (!groups[task.company]) groups[task.company] = [];
      groups[task.company].push(task);
    });
    return groups;
  }, [filteredTasks, layout]);

  const formatDate = (dateStr: string) => {
    const [y, m, d] = dateStr.split('-');
    return `${d}/${m}/${y}`;
  };

  const handleApplyTemplate = (tpl: ReportTemplate) => {
    setColumns({ ...tpl.columns });
    setLayout(tpl.layout || 'FLAT');
    setTemplateName(tpl.name);
  };

  const handleSaveTemplate = () => {
    if (!templateName.trim()) {
      alert("Vui lòng nhập tên để lưu mẫu cấu hình này");
      return;
    }
    const newTemplate: ReportTemplate = {
      id: crypto.randomUUID(),
      name: templateName,
      layout,
      columns: { ...columns }
    };
    onSaveTemplate(newTemplate);
    alert("Đã lưu cấu hình báo cáo thành công!");
  };

  // --- LOGIC XUẤT FILE ---

  const handleExportCSV = () => {
    const csvRows: string[] = [];
    csvRows.push(`"BÁO CÁO TUẦN THÁNG ${currentMonth}"`);
    csvRows.push(`"Ngày: ${formatDate(startDate)} - ${formatDate(endDate)}"`);
    csvRows.push("");

    const headers: string[] = [];
    if (layout === 'FLAT') {
      if (columns.company) headers.push('Công ty');
      if (columns.content) headers.push('Nội dung công việc');
      if (columns.pendingTasks) headers.push('Công việc đang làm');
      if (columns.date) headers.push('Ngày tạo');
      if (columns.status) headers.push('Trạng thái');
      csvRows.push(headers.join(','));
      filteredTasks.forEach(t => {
        const row = [];
        if (columns.company) row.push(`"${t.company}"`);
        if (columns.content) row.push(`"${t.content.replace(/"/g, '""')}"`);
        if (columns.pendingTasks) row.push(`"${t.status !== TaskStatus.DONE ? t.content.replace(/"/g, '""') : ''}"`);
        if (columns.date) row.push(`"${new Date(t.createdAt).toLocaleDateString('vi-VN')}"`);
        if (columns.status) row.push(`"${t.status === 'DONE' ? 'Xong' : 'Làm'}"`);
        csvRows.push(row.join(','));
      });
    } else {
      headers.push('Công ty', 'Tổng nội dung', 'Đang làm');
      csvRows.push(headers.join(','));
      // Fix: Cast Object.entries result to [string, Task[]][] to ensure tasks is typed correctly
      (Object.entries(groupedTasks || {}) as [string, Task[]][]).forEach(([company, tasks]) => {
        const row = [`"${company.toUpperCase()}"`];
        row.push(`"${tasks.map((t, idx) => `${idx + 1}. ${t.content}`).join('\r\n').replace(/"/g, '""')}"`);
        row.push(`"${tasks.filter(t => t.status !== TaskStatus.DONE).map((t, idx) => `${idx + 1}. ${t.content}`).join('\r\n').replace(/"/g, '""')}"`);
        csvRows.push(row.join(','));
      });
    }

    const blob = new Blob(['\ufeff' + csvRows.join('\n')], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `Bao_Cao_${startDate}.csv`;
    link.click();
  };

  const handleExportWord = () => {
    if (!reportRef.current) return;
    const content = reportRef.current.innerHTML;
    const header = `<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
                    <head><meta charset='utf-8'><title>Báo cáo</title>
                    <style>
                      table { border-collapse: collapse; width: 100%; }
                      th, td { border: 1px solid black; padding: 8px; text-align: left; }
                      .bg-slate-50 { background-color: #f8fafc; }
                    </style>
                    </head><body>`;
    const footer = "</body></html>";
    const sourceHTML = header + content + footer;

    const blob = new Blob(['\ufeff', sourceHTML], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Bao_Cao_${startDate}.doc`;
    link.click();
  };

  const handleExportImage = async () => {
    if (!reportRef.current) return;
    try {
      const canvas = await (window as any).html2canvas(reportRef.current, {
        scale: 2,
        backgroundColor: '#ffffff',
        logging: false
      });
      const dataUrl = canvas.toDataURL('image/png');
      const link = document.createElement('a');
      link.href = dataUrl;
      link.download = `Bao_Cao_${startDate}.png`;
      link.click();
    } catch (err) {
      console.error("Export image failed", err);
      alert("Không thể tạo file ảnh. Vui lòng thử lại.");
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="w-full max-w-7xl bg-white rounded-[3rem] shadow-2xl flex flex-col md:flex-row max-h-[95vh] overflow-hidden animate-in zoom-in-95 duration-300">

        {/* Left Sidebar */}
        <div className="w-full md:w-72 bg-slate-50 border-r border-slate-100 p-8 flex flex-col flex-shrink-0">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-6">Mẫu của bạn</h3>
          <div className="flex-1 overflow-y-auto space-y-3 custom-scrollbar pr-2 mb-6">
            {templates.map(tpl => (
              <div key={tpl.id} className="group relative">
                <button onClick={() => handleApplyTemplate(tpl)} className="w-full text-left p-4 bg-white border border-slate-200 rounded-2xl hover:border-blue-400 text-[11px] font-black text-slate-600 uppercase">
                  {tpl.name}
                </button>
                <button onClick={() => onDeleteTemplate(tpl.id)} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 p-2">
                  <i className="fas fa-trash-alt text-[10px]"></i>
                </button>
              </div>
            ))}
          </div>
          <div className="space-y-2">
            <input value={templateName} onChange={(e) => setTemplateName(e.target.value)} placeholder="Tên mẫu mới..." className="w-full p-4 bg-white border border-slate-200 rounded-2xl text-xs font-bold outline-none" />
            <button onClick={handleSaveTemplate} className="w-full py-4 bg-slate-800 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest">Lưu mẫu mới</button>
          </div>
        </div>

        {/* Main Configuration */}
        <div className="flex-1 flex flex-col min-w-0">
          <header className="p-8 border-b border-slate-100 flex items-center justify-between">
            <div>
              <h2 className="text-3xl font-black text-slate-800 tracking-tight uppercase">Trình xuất báo cáo</h2>
              <p className="text-sm text-slate-500 font-medium">Chọn định dạng và dữ liệu bạn cần.</p>
            </div>
            <button onClick={onClose} className="w-12 h-12 flex items-center justify-center rounded-2xl hover:bg-slate-50 text-slate-300">
              <i className="fas fa-times text-xl"></i>
            </button>
          </header>

          <div className="flex-1 overflow-y-auto p-8 custom-scrollbar space-y-8">
            <div className="grid grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Từ ngày</label>
                <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Đến ngày</label>
                <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold" />
              </div>
            </div>

            <div className="space-y-4">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Bố cục hiển thị</p>
              <div className="flex gap-4">
                <button onClick={() => setLayout('FLAT')} className={`flex-1 p-5 rounded-3xl border-2 transition-all ${layout === 'FLAT' ? 'border-blue-600 bg-blue-50' : 'border-slate-100 bg-white'}`}>
                  <p className="font-black text-xs uppercase tracking-widest">Danh sách chi tiết</p>
                </button>
                <button onClick={() => setLayout('GROUPED_BY_COMPANY')} className={`flex-1 p-5 rounded-3xl border-2 transition-all ${layout === 'GROUPED_BY_COMPANY' ? 'border-indigo-600 bg-indigo-50' : 'border-slate-100 bg-white'}`}>
                  <p className="font-black text-xs uppercase tracking-widest">Gộp theo công ty</p>
                </button>
              </div>
            </div>

            <div className="space-y-4">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Bản xem trước (Preview)</p>
              <div ref={reportRef} className="border border-slate-100 rounded-[2.5rem] bg-white shadow-sm overflow-hidden p-10">
                  <div className="text-center mb-8">
                    <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">BÁO CÁO TUẦN THÁNG {currentMonth}</h3>
                    <p className="text-sm font-bold text-slate-400 mt-1 uppercase tracking-widest">Ngày: {formatDate(startDate)} - {formatDate(endDate)}</p>
