  const [layout, setLayout] = useState<ReportLayout>('FLAT');
  const [columns, setColumns] = useState({
    company: true,
    content: true,
    status: true,
    priority: true,
    date: true,
    pendingTasks: true
  });

  const filteredTasks = useMemo(() => {
    return tasks.filter(t => {
      const taskDate = t.createdAt.split('T')[0];
      return taskDate >= startDate && taskDate <= endDate;
    });
  }, [tasks, startDate, endDate]);

  const groupedTasks = useMemo<Record<string, Task[]> | null>(() => {
    if (layout !== 'GROUPED_BY_COMPANY') return null;
    const groups: Record<string, Task[]> = {};
    filteredTasks.forEach(task => {
      if (!groups[task.company]) groups[task.company] = [];
      groups[task.company].push(task);
    });
    return groups;
  }, [filteredTasks, layout]);

  const formatDate = (dateStr: string) => {
    const [y, m, d] = dateStr.split('-');
    return `${d}/${m}/${y}`;
  };

  const handleApplyTemplate = (tpl: ReportTemplate) => {
    setColumns({ ...tpl.columns });
    setLayout(tpl.layout || 'FLAT');
    setTemplateName(tpl.name);
  };

  const handleSaveTemplate = () => {
    if (!templateName.trim()) {
      alert("Vui lòng nhập tên để lưu mẫu cấu hình này");
      return;
    }
    const newTemplate: ReportTemplate = {
      id: crypto.randomUUID(),
      name: templateName,
      layout,
      columns: { ...columns }
    };
    onSaveTemplate(newTemplate);
    alert("Đã lưu cấu hình báo cáo thành công!");
  };

  // --- LOGIC XUẤT FILE ---

  const handleExportCSV = () => {
    const csvRows: string[] = [];
    csvRows.push(`"BÁO CÁO TUẦN THÁNG ${currentMonth}"`);
    csvRows.push(`"Ngày: ${formatDate(startDate)} - ${formatDate(endDate)}"`);
    csvRows.push("");

    const headers: string[] = [];
    if (layout === 'FLAT') {
      if (columns.company) headers.push('Công ty');
      if (columns.content) headers.push('Nội dung công việc');
      if (columns.pendingTasks) headers.push('Công việc đang làm');
      if (columns.date) headers.push('Ngày tạo');
      if (columns.status) headers.push('Trạng thái');
      csvRows.push(headers.join(','));
      filteredTasks.forEach(t => {
        const row = [];
        if (columns.company) row.push(`"${t.company}"`);
        if (columns.content) row.push(`"${t.content.replace(/"/g, '""')}"`);
        if (columns.pendingTasks) row.push(`"${t.status !== TaskStatus.DONE ? t.content.replace(/"/g, '""') : ''}"`);
        if (columns.date) row.push(`"${new Date(t.createdAt).toLocaleDateString('vi-VN')}"`);
        if (columns.status) row.push(`"${t.status === 'DONE' ? 'Xong' : 'Làm'}"`);
        csvRows.push(row.join(','));
      });
    } else {
      headers.push('Công ty', 'Tổng nội dung', 'Đang làm');
      csvRows.push(headers.join(','));
      (Object.entries(groupedTasks || {}) as [string, Task[]][]).forEach(([company, tasks]) => {
        const row = [`"${company.toUpperCase()}"`];
        row.push(`"${tasks.map((t, idx) => `${idx + 1}. ${t.content}`).join('\r\n').replace(/"/g, '""')}"`);
        row.push(`"${tasks.filter(t => t.status !== TaskStatus.DONE).map((t, idx) => `${idx + 1}. ${t.content}`).join('\r\n').replace(/"/g, '""')}"`);
        csvRows.push(row.join(','));
      });
    }

    const blob = new Blob(['\ufeff' + csvRows.join('\n')], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `Bao_Cao_${startDate}.csv`;
    link.click();
  };

  const handleExportWord = () => {
    if (!reportRef.current) return;

    // Tạo bản sao tạm để xử lý CSS cho Word (Word không hiểu Tailwind tốt)
    const reportHtml = reportRef.current.innerHTML;

    const header = `<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
                    <head><meta charset='utf-8'><title>Báo cáo</title>
                    <style>
                      table { border-collapse: collapse; width: 100%; border: 1px solid #e2e8f0; }
                      th { background-color: #f1f5f9; font-weight: bold; border: 1px solid #cbd5e1; padding: 10px; text-align: left; text-transform: uppercase; font-size: 12px; }
                      td { border: 1px solid #e2e8f0; padding: 10px; text-align: left; font-size: 11px; vertical-align: top; }
                      h3 { text-align: center; font-family: sans-serif; text-transform: uppercase; }
                      .date-info { text-align: center; color: #64748b; margin-bottom: 20px; font-family: sans-serif; }

                      /* Các màu nền cho công ty */
                      .bg-blue-100 { background-color: #dbeafe !important; }
                      .bg-emerald-100 { background-color: #dcfce7 !important; }
                      .bg-indigo-100 { background-color: #e0e7ff !important; }
                      .bg-amber-100 { background-color: #fef3c7 !important; }
                      .bg-violet-100 { background-color: #ede9fe !important; }
                      .bg-cyan-100 { background-color: #cffafe !important; }
                      .bg-orange-100 { background-color: #ffedd5 !important; }
                      .bg-fuchsia-100 { background-color: #fae8ff !important; }

                      .text-blue-600 { color: #2563eb; }
                      .text-emerald-600 { color: #059669; }
                      .text-indigo-600 { color: #4f46e5; }
                      .text-amber-600 { color: #d97706; }
                      .text-violet-600 { color: #7c3aed; }
                      .text-cyan-600 { color: #0891b2; }
                      .text-orange-600 { color: #ea580c; }
                      .text-fuchsia-600 { color: #c026d3; }
                    </style>
                    </head><body>`;
    const footer = "</body></html>";
    const sourceHTML = header + reportHtml + footer;

    const blob = new Blob(['\ufeff', sourceHTML], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Bao_Cao_${startDate}.doc`;
    link.click();
  };

  const handleExportImage = async () => {
    if (!reportRef.current) return;
    try {
      const canvas = await (window as any).html2canvas(reportRef.current, {
        scale: 2,
        backgroundColor: '#ffffff',
        logging: false,
        useCORS: true
      });
      const dataUrl = canvas.toDataURL('image/png');
      const link = document.createElement('a');
      link.href = dataUrl;
      link.download = `Bao_Cao_${startDate}.png`;
      link.click();
    } catch (err) {
      console.error("Export image failed", err);
      alert("Không thể tạo file ảnh. Vui lòng thử lại.");
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="w-full max-w-7xl bg-white rounded-[3rem] shadow-2xl flex flex-col md:flex-row max-h-[95vh] overflow-hidden animate-in zoom-in-95 duration-300">

        {/* Left Sidebar */}
        <div className="w-full md:w-72 bg-slate-50 border-r border-slate-100 p-8 flex flex-col flex-shrink-0">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-6">Mẫu của bạn</h3>
          <div className="flex-1 overflow-y-auto space-y-3 custom-scrollbar pr-2 mb-6">
            {templates.map(tpl => (
              <div key={tpl.id} className="group relative">
                <button onClick={() => handleApplyTemplate(tpl)} className="w-full text-left p-4 bg-white border border-slate-200 rounded-2xl hover:border-blue-400 text-[11px] font-black text-slate-600 uppercase">
                  {tpl.name}
                </button>
                <button onClick={() => onDeleteTemplate(tpl.id)} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 p-2">
                  <i className="fas fa-trash-alt text-[10px]"></i>
                </button>
              </div>
            ))}
          </div>
          <div className="space-y-2">
            <input value={templateName} onChange={(e) => setTemplateName(e.target.value)} placeholder="Tên mẫu mới..." className="w-full p-4 bg-white border border-slate-200 rounded-2xl text-xs font-bold outline-none" />
            <button onClick={handleSaveTemplate} className="w-full py-4 bg-slate-800 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest">Lưu mẫu mới</button>
          </div>
        </div>

        {/* Main Configuration */}
        <div className="flex-1 flex flex-col min-w-0">
          <header className="p-8 border-b border-slate-100 flex items-center justify-between">
            <div>
              <h2 className="text-3xl font-black text-slate-800 tracking-tight uppercase">Trình xuất báo cáo</h2>
              <p className="text-sm text-slate-500 font-medium">Chọn định dạng và dữ liệu bạn cần.</p>
            </div>
            <button onClick={onClose} className="w-12 h-12 flex items-center justify-center rounded-2xl hover:bg-slate-50 text-slate-300">
              <i className="fas fa-times text-xl"></i>
            </button>
          </header>

          <div className="flex-1 overflow-y-auto p-8 custom-scrollbar space-y-8">
            <div className="grid grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Từ ngày</label>
                <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Đến ngày</label>
                <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold" />
              </div>
            </div>

            <div className="space-y-4">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Bố cục hiển thị</p>
              <div className="flex gap-4">
                <button onClick={() => setLayout('FLAT')} className={`flex-1 p-5 rounded-3xl border-2 transition-all ${layout === 'FLAT' ? 'border-blue-600 bg-blue-50' : 'border-slate-100 bg-white'}`}>
                  <p className="font-black text-xs uppercase tracking-widest">Danh sách chi tiết</p>
                </button>
                <button onClick={() => setLayout('GROUPED_BY_COMPANY')} className={`flex-1 p-5 rounded-3xl border-2 transition-all ${layout === 'GROUPED_BY_COMPANY' ? 'border-indigo-600 bg-indigo-50' : 'border-slate-100 bg-white'}`}>
                  <p className="font-black text-xs uppercase tracking-widest">Gộp theo công ty</p>
                </button>
              </div>
            </div>

            <div className="space-y-4">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Bản xem trước (Preview)</p>
              <div ref={reportRef} className="border border-slate-100 rounded-[2.5rem] bg-white shadow-sm overflow-hidden p-10">
                  <div className="text-center mb-8">
                    <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">BÁO CÁO TUẦN THÁNG {currentMonth}</h3>
                    <p className="date-info text-sm font-bold text-slate-400 mt-1 uppercase tracking-widest">Ngày: {formatDate(startDate)} - {formatDate(endDate)}</p>
                  </div>

                  <table className="w-full text-left text-[11px] border-collapse">
                    <thead className="bg-slate-50 border-b-2 border-slate-200 font-black text-slate-600 uppercase">
                      <tr>
                        {layout === 'FLAT' ? (
                          <>
                            <th className="p-4 border">Công ty</th>
                            <th className="p-4 border">Nội dung</th>
                            <th className="p-4 border">Đang làm</th>
                            <th className="p-4 border text-center">Ngày</th>
                            <th className="p-4 border text-center">Trạng thái</th>
                          </>
                        ) : (
                          <>
                            <th className="p-4 border">Công ty</th>
                            <th className="p-4 border">Nội dung (Gộp)</th>
                            <th className="p-4 border">Việc đang làm</th>
                          </>
                        )}
                      </tr>
                    </thead>
                    <tbody className="font-medium text-slate-700">
                      {layout === 'FLAT' ? (
                        filteredTasks.map(t => {
                          const cpColor = getCompanyColor(t.company);
                          return (
                            <tr key={t.id} className={cpColor.light}>
                              <td className={`p-4 border font-bold ${cpColor.text}`}>{t.company}</td>
                              <td className="p-4 border">{t.content}</td>
                              <td className="p-4 border text-blue-600 italic font-bold">{t.status !== TaskStatus.DONE ? t.content : ''}</td>
                              <td className="p-4 border text-center text-slate-500">{new Date(t.createdAt).toLocaleDateString('vi-VN')}</td>
                              <td className="p-4 border text-center font-bold">{t.status === 'DONE' ? 'Xong' : 'Làm'}</td>
                            </tr>
                          );
                        })
                      ) : (
                        (Object.entries(groupedTasks || {}) as [string, Task[]][]).map(([company, tks]) => {
                          const cpColor = getCompanyColor(company);
                          return (
                            <tr key={company} className={cpColor.light}>
                              <td className={`p-4 border font-black uppercase align-top ${cpColor.text}`}>{company}</td>
                              <td className="p-4 border whitespace-pre-line align-top">{tks.map((tk, i) => `${i + 1}. ${tk.content}`).join('\n')}</td>
                              <td className="p-4 border whitespace-pre-line align-top text-blue-600 font-bold">{tks.filter(tk => tk.status !== TaskStatus.DONE).map((tk, i) => `${i + 1}. ${tk.content}`).join('\n') || '-'}</td>
                            </tr>
                          );
                        })
                      )}
                    </tbody>
                  </table>
              </div>
            </div>
          </div>

          <footer className="p-8 border-t border-slate-100 flex flex-wrap items-center justify-end gap-4 bg-slate-50/20">
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mr-auto">{filteredTasks.length} dòng dữ liệu</span>

            <button onClick={handleExportCSV} className="bg-emerald-600 hover:bg-emerald-700 text-white font-black py-3 px-6 rounded-2xl flex items-center gap-2 transition-all shadow-md">
              <i className="fas fa-file-excel"></i> EXCEL
            </button>
            <button onClick={handleExportWord} className="bg-blue-600 hover:bg-blue-700 text-white font-black py-3 px-6 rounded-2xl flex items-center gap-2 transition-all shadow-md">
              <i className="fas fa-file-word"></i> WORD
            </button>
            <button onClick={handleExportImage} className="bg-indigo-600 hover:bg-indigo-700 text-white font-black py-3 px-6 rounded-2xl flex items-center gap-2 transition-all shadow-md">
              <i className="fas fa-file-image"></i> ẢNH
            </button>
          </footer>
        </div>
      </div>
    </div>
  );
};

export default ExportModal;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import TaskItem from './components/TaskItem';
import Login from './components/Login';
import Setup from './components/Setup';
import HistoryModal from './components/HistoryModal';
import ExportModal from './components/ExportModal';
import { Task, TaskStatus, AppState, ReportTemplate } from './types';
import { loadStateSecure, saveStateSecure } from './services/storageService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<{email: string, pass: string} | null>(null);
  const [state, setState] = useState<AppState | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [loading, setLoading] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isExportOpen, setIsExportOpen] = useState(false);
  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);

  const handleLogin = async (email: string, pass: string) => {
    setLoading(true);
    try {
      const loaded = await loadStateSecure(email, pass);
      setCurrentUser({ email, pass });
      setState(loaded);
    } catch (e: any) { alert(e.message); }
    finally { setLoading(false); }
  };

  const handleSetupComplete = (companies: string[]) => {
    setState(prev => prev ? ({ ...prev, companies }) : null);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setState(null);
  };

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (currentUser && state) saveStateSecure(currentUser.email, currentUser.pass, state);
  }, [state, currentUser]);

  const addTask = useCallback((content: string, company: string, isPriority: boolean) => {
    if (!state) return;
    const newTask: Task = {
      id: crypto.randomUUID(),
      content,
      company,
      createdAt: new Date().toISOString(),
      status: TaskStatus.NOT_STARTED,
      isPriority
    };
    setState(prev => prev ? ({ ...prev, tasks: [newTask, ...prev.tasks] }) : null);
    setIsMobileSidebarOpen(false); // Đóng sidebar sau khi thêm trên mobile
  }, [state]);

  const addCompany = useCallback((companyName: string) => {
    setState(prev => prev ? ({ ...prev, companies: Array.from(new Set([...prev.companies, companyName])) }) : null);
  }, []);

  const updateTaskStatus = useCallback((id: string, status: TaskStatus) => {
    setState(prev => prev ? ({ ...prev, tasks: prev.tasks.map(t => t.id === id ? { ...t, status } : t) }) : null);
  }, []);

  const deleteTask = useCallback((id: string) => {
    if (!confirm("Bạn muốn xóa vĩnh viễn công việc này?")) return;
    setState(prev => prev ? ({ ...prev, tasks: prev.tasks.filter(t => t.id !== id) }) : null);
  }, []);

  const saveReportTemplate = useCallback((template: ReportTemplate) => {
    setState(prev => {
      if (!prev) return null;
      const templates = prev.reportTemplates || [];
      const existingIdx = templates.findIndex(t => t.name === template.name);
      if (existingIdx >= 0) {
        const newTemplates = [...templates];
        newTemplates[existingIdx] = template;
        return { ...prev, reportTemplates: newTemplates };
      }
      return { ...prev, reportTemplates: [...templates, template] };
    });
  }, []);

  const deleteReportTemplate = useCallback((id: string) => {
    setState(prev => {
      if (!prev) return null;
      const templates = prev.reportTemplates || [];
      return { ...prev, reportTemplates: templates.filter(tpl => tpl.id !== id) };
    });
  }, []);

  const currentViewTasks = useMemo(() => {
    if (!state) return [];
    const today = new Date().toISOString().split('T')[0];
    return state.tasks.filter(t => {
      if (t.status !== TaskStatus.DONE) return true;
      return t.createdAt.startsWith(today);
    }).sort((a, b) => {
      const getRank = (task: Task) => {
        if (task.status === TaskStatus.IN_PROGRESS) return 0;
        if (task.isPriority) return 1;
        if (task.status === TaskStatus.NOT_STARTED) return 2;
        return 3;
      };
      const rankA = getRank(a), rankB = getRank(b);
      if (rankA !== rankB) return rankA - rankB;
      return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
    });
  }, [state]);

  if (loading) return (
    <div className="h-screen bg-white flex flex-col items-center justify-center text-blue-600 p-6 text-center">
      <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
      <p className="font-black uppercase tracking-[0.2em] text-[10px]">Đang truy xuất dữ liệu an toàn...</p>
    </div>
  );

  if (!currentUser || !state) return <Login onLogin={handleLogin} />;
  if (state.companies.length === 0) return <Setup onComplete={handleSetupComplete} onLogout={handleLogout} />;

  const activeCount = state.tasks.filter(t => t.status !== TaskStatus.DONE).length;
  const doneTodayCount = state.tasks.filter(t => t.status === TaskStatus.DONE && t.createdAt.startsWith(new Date().toISOString().split('T')[0])).length;

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-white">
      {/* Mobile Overlay */}
      {isMobileSidebarOpen && (
        <div 
          className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-40 md:hidden"
          onClick={() => setIsMobileSidebarOpen(false)}
        />
      )}

      {/* Sidebar - Drawer on Mobile, Fixed on Desktop */}
      <div className={`fixed inset-y-0 left-0 z-50 transform ${isMobileSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0 transition-transform duration-300 ease-in-out md:flex-shrink-0`}>
        <Sidebar 
          email={currentUser.email}
          companies={state.companies}
          onAddTask={addTask} 
          onAddCompany={addCompany}
          onClearAll={() => { if(confirm("Xóa toàn bộ kho lưu trữ vĩnh viễn?")) setState({ ...state, tasks: [] }); }} 
          onLogout={handleLogout}
          onOpenHistory={() => { setIsHistoryOpen(true); setIsMobileSidebarOpen(false); }}
          onOpenExport={() => { setIsExportOpen(true); setIsMobileSidebarOpen(false); }}
          onCloseMobile={() => setIsMobileSidebarOpen(false)}
        />
      </div>

      <main className="flex-1 flex flex-col min-w-0 bg-slate-50 relative h-screen overflow-hidden">
        <header className="min-h-[96px] py-4 px-6 md:px-10 bg-white border-b border-slate-100 flex flex-col md:flex-row md:items-center justify-between z-10 shadow-sm gap-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <button 
                onClick={() => setIsMobileSidebarOpen(true)}
                className="md:hidden w-10 h-10 rounded-xl bg-slate-50 text-slate-600 flex items-center justify-center border border-slate-100"
              >
                <i className="fas fa-bars"></i>
              </button>
              <div>
                <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tight leading-tight">CÔNG VIỆC HIỆN TẠI</h2>
                <div className="flex items-center gap-2 mt-0.5">
                  <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                  <p className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest truncate max-w-[150px] md:max-w-none">
                    {currentTime.toLocaleDateString('vi-VN', { weekday: 'short', day: 'numeric', month: 'short' })}
                  </p>
                </div>
              </div>
            </div>
            {/* Clock for mobile header */}
            <div className="md:hidden text-right">
               <p className="text-xl font-mono font-bold text-slate-800 leading-tight">
                {currentTime.toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' })}
              </p>
            </div>
          </div>

          <div className="flex items-center justify-between md:justify-end gap-4 md:gap-8">
            <div className="text-left md:text-right border-r md:border-r-0 border-slate-100 pr-4 md:pr-0">
              <p className="text-[8px] md:text-[9px] font-black text-slate-400 uppercase tracking-widest">Đang làm</p>
              <p className="text-xl md:text-2xl font-black text-rose-500 leading-tight">{activeCount}</p>
            </div>
            <div className="text-left md:text-right">
