  onAddCompany: (company: string) => void;
  onClearAll: () => void;
  onLogout: () => void;
  onOpenHistory: () => void;
  onOpenExport: () => void;
  onCloseMobile?: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  email, companies, onAddTask, onAddCompany, onClearAll, onLogout, onOpenHistory, onOpenExport, onCloseMobile
}) => {
  const [content, setContent] = useState('');
  const [selectedCompany, setSelectedCompany] = useState(companies[0] || '');
