              {isPriority && <i className="fas fa-check text-[8px]"></i>}
            </div>
            <span className={`text-[10px] font-black uppercase tracking-widest ${isPriority ? 'text-rose-600' : 'text-slate-600'}`}>Công việc quan trọng</span>
          </div>

          <button type="submit" className="w-full bg-slate-900 hover:bg-black text-white font-black py-4 rounded-xl shadow-xl transition-all flex items-center justify-center gap-3 text-xs tracking-widest">
            <i className="fas fa-plus"></i> CẬP NHẬT DỮ LIỆU
          </button>
        </form>
      </div>

      <div className="mt-8 pt-6 border-t border-slate-100 flex items-center justify-between flex-shrink-0">
        <p className="text-[8px] text-slate-300 font-bold uppercase tracking-[0.2em]">ZenTask v5.0</p>
        <button onClick={onClearAll} title="Xóa tất cả" className="text-slate-300 hover:text-red-500 transition-colors p-2"><i className="far fa-trash-alt"></i></button>
      </div>
    </div>
  );
};

