import React from 'react';
import { Task, TaskStatus } from '../types';
import { STATUS_LABELS, getCompanyColor } from '../constants';

interface TaskItemProps {
  task: Task;
  onStatusChange?: (id: string, status: TaskStatus) => void;
  onDelete?: (id: string) => void;
  readOnly?: boolean;
}

const TaskItem: React.FC<TaskItemProps> = ({ task, onStatusChange, onDelete, readOnly = false }) => {
  const formattedTime = new Date(task.createdAt).toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' });
  const cpColor = getCompanyColor(task.company);
  const isDone = task.status === TaskStatus.DONE;
  const isInProgress = task.status === TaskStatus.IN_PROGRESS;

  return (
    <div className={`group p-4 md:p-6 rounded-[1.2rem] md:rounded-[1.5rem] border-l-[6px] border-t border-r border-b transition-all flex flex-col items-start gap-4 md:gap-6 ${
      isDone ? 'opacity-50 bg-slate-50 border-slate-200' : 
      task.isPriority ? 'bg-rose-50/50 border-rose-200 border-l-rose-500' : 
      `${cpColor.bg} ${cpColor.border} border-l-${cpColor.badge.replace('bg-', '')}`
    } ${!isDone && !readOnly && 'hover:shadow-lg active:scale-[0.99]'}`}>

      <div className="w-full min-w-0">
        <div className="flex items-center gap-2 mb-3 flex-wrap">
          {isInProgress && (
            <span className="flex items-center gap-1.5 text-[8px] md:text-[9px] font-black px-2 py-0.5 md:px-2.5 md:py-1 rounded-full bg-blue-600 text-white uppercase tracking-widest animate-pulse">
              <i className="fas fa-spinner fa-spin text-[7px] md:text-[8px]"></i> Đang làm
            </span>
          )}
          {task.isPriority && (
            <span className="flex items-center gap-1.5 text-[8px] md:text-[9px] font-black px-2 py-0.5 md:px-2.5 md:py-1 rounded-full bg-rose-500 text-white uppercase tracking-widest">
              <i className="fas fa-bolt text-[7px] md:text-[8px]"></i> Gấp
            </span>
          )}
          <span className={`text-[9px] md:text-[10px] font-black px-2.5 py-0.5 md:px-3 md:py-1 rounded-full uppercase tracking-widest ${
            task.isPriority ? 'bg-rose-100 text-rose-700' : `${cpColor.light} ${cpColor.text}`
          }`}>
            {task.company}
          </span>
          <span className="text-[9px] md:text-[10px] text-slate-400 font-bold uppercase tracking-tight ml-auto">
            <i className="far fa-clock mr-1"></i> {formattedTime}
          </span>
        </div>
        <p className={`text-slate-800 font-bold text-base md:text-lg leading-snug break-words ${isDone ? 'line-through opacity-40' : ''}`}>
          {task.content}
        </p>
      </div>

      {!readOnly && (
        <div className="flex items-center justify-between w-full mt-2 md:mt-0">
          <div className={`flex p-1 rounded-xl md:rounded-2xl border bg-white/80 backdrop-blur-sm ${task.isPriority ? 'border-rose-100' : cpColor.border}`}>
            {(Object.values(TaskStatus) as TaskStatus[]).map((status) => (
              <button
                key={status}
                onClick={() => onStatusChange?.(task.id, status)}
                className={`px-3 py-1.5 md:px-4 md:py-2 rounded-lg md:rounded-xl text-[8px] md:text-[10px] font-black uppercase tracking-widest transition-all ${
                  task.status === status
                    ? STATUS_LABELS[status].color + " shadow-sm scale-105"
                    : 'text-slate-400 hover:text-slate-600'
                }`}
              >
                {STATUS_LABELS[status].label}
              </button>
            ))}
          </div>
          <button
            onClick={() => onDelete?.(task.id)}
            className="w-9 h-9 md:w-10 md:h-10 rounded-lg md:rounded-xl flex items-center justify-center text-slate-300 hover:text-red-500 hover:bg-red-50 transition-all"
          >
            <i className="fas fa-trash-alt text-sm"></i>
          </button>
        </div>
      )}

      {readOnly && (
        <div className="flex items-center gap-2 text-[9px] md:text-[10px] font-black uppercase tracking-widest text-slate-400 ml-auto">
           <i className="fas fa-lock text-[8px]"></i> {STATUS_LABELS[task.status].label}
        </div>
      )}
    </div>
  );
};

export default TaskItem;

import React, { useState, useMemo, useRef } from 'react';
import { Task, ReportTemplate, ReportLayout, TaskStatus } from '../types';
import { getCompanyColor } from '../constants';

interface ExportModalProps {
  tasks: Task[];
  templates: ReportTemplate[];
  onSaveTemplate: (template: ReportTemplate) => void;
  onDeleteTemplate: (id: string) => void;
  onClose: () => void;
}

const ExportModal: React.FC<ExportModalProps> = ({ tasks, templates, onSaveTemplate, onDeleteTemplate, onClose }) => {
  const today = new Date();
  const todayStr = today.toISOString().split('T')[0];
  const currentMonth = today.getMonth() + 1;
  const reportRef = useRef<HTMLDivElement>(null);

  const [startDate, setStartDate] = useState(todayStr);
  const [endDate, setEndDate] = useState(todayStr);
  const [templateName, setTemplateName] = useState('');
  const [layout, setLayout] = useState<ReportLayout>('FLAT');
  const [columns, setColumns] = useState({
    company: true,
    content: true,
    status: true,
    priority: true,
    date: true,
    pendingTasks: true
  });

  const filteredTasks = useMemo(() => {
    return tasks.filter(t => {
      const taskDate = t.createdAt.split('T')[0];
      return taskDate >= startDate && taskDate <= endDate;
    });
  }, [tasks, startDate, endDate]);

  const groupedTasks = useMemo<Record<string, Task[]> | null>(() => {
    if (layout !== 'GROUPED_BY_COMPANY') return null;
    const groups: Record<string, Task[]> = {};
    filteredTasks.forEach(task => {
      if (!groups[task.company]) groups[task.company] = [];
      groups[task.company].push(task);
    });
    return groups;
  }, [filteredTasks, layout]);

  const formatDate = (dateStr: string) => {
    const [y, m, d] = dateStr.split('-');
    return `${d}/${m}/${y}`;
  };

  const handleApplyTemplate = (tpl: ReportTemplate) => {
    setColumns({ ...tpl.columns });
    setLayout(tpl.layout || 'FLAT');
    setTemplateName(tpl.name);
  };

  const handleSaveTemplate = () => {
    if (!templateName.trim()) {
      alert("Vui lòng nhập tên để lưu mẫu cấu hình này");
      return;
    }
    const newTemplate: ReportTemplate = {
      id: crypto.randomUUID(),
      name: templateName,
      layout,
      columns: { ...columns }
    };
    onSaveTemplate(newTemplate);
    alert("Đã lưu cấu hình báo cáo thành công!");
  };

  // --- LOGIC XUẤT FILE ---

  const handleExportCSV = () => {
    const csvRows: string[] = [];
    csvRows.push(`"BÁO CÁO TUẦN THÁNG ${currentMonth}"`);
    csvRows.push(`"Ngày: ${formatDate(startDate)} - ${formatDate(endDate)}"`);
    csvRows.push("");

    const headers: string[] = [];
    if (layout === 'FLAT') {
      if (columns.company) headers.push('Công ty');
      if (columns.content) headers.push('Nội dung công việc');
      if (columns.pendingTasks) headers.push('Công việc đang làm');
      if (columns.date) headers.push('Ngày tạo');
      if (columns.status) headers.push('Trạng thái');
      csvRows.push(headers.join(','));
      filteredTasks.forEach(t => {
        const row = [];
        if (columns.company) row.push(`"${t.company}"`);
        if (columns.content) row.push(`"${t.content.replace(/"/g, '""')}"`);
        if (columns.pendingTasks) row.push(`"${t.status !== TaskStatus.DONE ? t.content.replace(/"/g, '""') : ''}"`);
        if (columns.date) row.push(`"${new Date(t.createdAt).toLocaleDateString('vi-VN')}"`);
        if (columns.status) row.push(`"${t.status === 'DONE' ? 'Xong' : 'Làm'}"`);
        csvRows.push(row.join(','));
      });
    } else {
      headers.push('Công ty', 'Tổng nội dung', 'Đang làm');
      csvRows.push(headers.join(','));
      (Object.entries(groupedTasks || {}) as [string, Task[]][]).forEach(([company, tasks]) => {
        const row = [`"${company.toUpperCase()}"`];
        row.push(`"${tasks.map((t, idx) => `${idx + 1}. ${t.content}`).join('\r\n').replace(/"/g, '""')}"`);
        row.push(`"${tasks.filter(t => t.status !== TaskStatus.DONE).map((t, idx) => `${idx + 1}. ${t.content}`).join('\r\n').replace(/"/g, '""')}"`);
        csvRows.push(row.join(','));
      });
    }

    const blob = new Blob(['\ufeff' + csvRows.join('\n')], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `Bao_Cao_${startDate}.csv`;
    link.click();
  };

  const handleExportWord = () => {
    if (!reportRef.current) return;
    const reportHtml = reportRef.current.innerHTML;
    const header = `<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'><head><meta charset='utf-8'><style>table{border-collapse:collapse;width:100%;border:1px solid #e2e8f0}th{background-color:#f1f5f9;font-weight:bold;border:1px solid #cbd5e1;padding:10px;text-align:left;text-transform:uppercase;font-size:12px}td{border:1px solid #e2e8f0;padding:10px;text-align:left;font-size:11px;vertical-align:top}h3{text-align:center;font-family:sans-serif;text-transform:uppercase}.date-info{text-align:center;color:#64748b;margin-bottom:20px;font-family:sans-serif}.bg-blue-100{background-color:#dbeafe!important}.bg-emerald-100{background-color:#dcfce7!important}.bg-indigo-100{background-color:#e0e7ff!important}.bg-amber-100{background-color:#fef3c7!important}.bg-violet-100{background-color:#ede9fe!important}.bg-cyan-100{background-color:#cffafe!important}.bg-orange-100{background-color:#ffedd5!important}.bg-fuchsia-100{background-color:#fae8ff!important}.text-blue-600{color:#2563eb}.text-emerald-600{color:#059669}.text-indigo-600{color:#4f46e5}.text-amber-600{color:#d97706}.text-violet-600{color:#7c3aed}.text-cyan-600{color:#0891b2}.text-orange-600{color:#ea580c}.text-fuchsia-600{color:#c026d3}</style></head><body>`;
    const footer = "</body></html>";
    const blob = new Blob(['\ufeff', header + reportHtml + footer], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Bao_Cao_${startDate}.doc`;
    link.click();
  };

  const handleExportImage = async () => {
    if (!reportRef.current) return;
    try {
      const canvas = await (window as any).html2canvas(reportRef.current, { scale: 2, backgroundColor: '#ffffff', logging: false, useCORS: true });
      const dataUrl = canvas.toDataURL('image/png');
      const link = document.createElement('a');
      link.href = dataUrl;
      link.download = `Bao_Cao_${startDate}.png`;
      link.click();
    } catch (err) {
      alert("Xuất ảnh thất bại. Hãy thử lại!");
    }
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-0 md:p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="w-full h-full md:h-auto md:max-w-7xl bg-white md:rounded-[3rem] shadow-2xl flex flex-col md:flex-row max-h-[100vh] md:max-h-[95vh] overflow-hidden">

        {/* Templates Sidebar - Collapsible on Mobile or Stacked */}
        <div className="hidden md:flex w-72 bg-slate-50 border-r border-slate-100 p-8 flex-col flex-shrink-0">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-6">Mẫu cấu hình</h3>
          <div className="flex-1 overflow-y-auto space-y-3 custom-scrollbar pr-2 mb-6">
            {templates.length === 0 ? <p className="text-[10px] text-slate-300 italic text-center py-10">Trống</p> : templates.map(tpl => (
              <div key={tpl.id} className="group relative">
                <button onClick={() => handleApplyTemplate(tpl)} className="w-full text-left p-4 bg-white border border-slate-200 rounded-2xl hover:border-blue-400 text-[11px] font-black text-slate-600 uppercase transition-all">
                  {tpl.name}
                </button>
                <button onClick={() => onDeleteTemplate(tpl.id)} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all p-2">
                  <i className="fas fa-trash-alt text-[10px]"></i>
                </button>
              </div>
            ))}
          </div>
          <div className="space-y-2">
