export const getCompanyColor = (company: string) => {
  // Bảng màu mở rộng 20 bộ màu cực kỳ khác biệt để tránh trùng lặp
  const colors = [
    { bg: 'bg-blue-50', text: 'text-blue-700', border: 'border-blue-200', badge: 'bg-blue-600', light: 'bg-blue-100' },
    { bg: 'bg-emerald-50', text: 'text-emerald-700', border: 'border-emerald-200', badge: 'bg-emerald-600', light: 'bg-emerald-100' },
    { bg: 'bg-violet-50', text: 'text-violet-700', border: 'border-violet-200', badge: 'bg-violet-600', light: 'bg-violet-100' },
    { bg: 'bg-amber-50', text: 'text-amber-700', border: 'border-amber-200', badge: 'bg-amber-600', light: 'bg-amber-100' },
    { bg: 'bg-rose-50', text: 'text-rose-700', border: 'border-rose-200', badge: 'bg-rose-600', light: 'bg-rose-100' },
    { bg: 'bg-cyan-50', text: 'text-cyan-700', border: 'border-cyan-200', badge: 'bg-cyan-600', light: 'bg-cyan-100' },
    { bg: 'bg-orange-50', text: 'text-orange-700', border: 'border-orange-200', badge: 'bg-orange-600', light: 'bg-orange-100' },
    { bg: 'bg-fuchsia-50', text: 'text-fuchsia-700', border: 'border-fuchsia-200', badge: 'bg-fuchsia-600', light: 'bg-fuchsia-100' },
    { bg: 'bg-teal-50', text: 'text-teal-700', border: 'border-teal-200', badge: 'bg-teal-600', light: 'bg-teal-100' },
    { bg: 'bg-indigo-50', text: 'text-indigo-700', border: 'border-indigo-200', badge: 'bg-indigo-600', light: 'bg-indigo-100' },
    { bg: 'bg-lime-50', text: 'text-lime-700', border: 'border-lime-200', badge: 'bg-lime-600', light: 'bg-lime-100' },
    { bg: 'bg-sky-50', text: 'text-sky-700', border: 'border-sky-200', badge: 'bg-sky-600', light: 'bg-sky-100' },
    { bg: 'bg-purple-50', text: 'text-purple-700', border: 'border-purple-200', badge: 'bg-purple-600', light: 'bg-purple-100' },
    { bg: 'bg-pink-50', text: 'text-pink-700', border: 'border-pink-200', badge: 'bg-pink-600', light: 'bg-pink-100' },
    { bg: 'bg-slate-50', text: 'text-slate-700', border: 'border-slate-200', badge: 'bg-slate-600', light: 'bg-slate-100' },
    { bg: 'bg-yellow-50', text: 'text-yellow-700', border: 'border-yellow-200', badge: 'bg-yellow-600', light: 'bg-yellow-100' },
    { bg: 'bg-red-50', text: 'text-red-700', border: 'border-red-200', badge: 'bg-red-600', light: 'bg-red-100' },
    { bg: 'bg-stone-50', text: 'text-stone-700', border: 'border-stone-200', badge: 'bg-stone-600', light: 'bg-stone-100' },
    { bg: 'bg-zinc-50', text: 'text-zinc-700', border: 'border-zinc-200', badge: 'bg-zinc-600', light: 'bg-zinc-100' },
    { bg: 'bg-neutral-50', text: 'text-neutral-700', border: 'border-neutral-200', badge: 'bg-neutral-600', light: 'bg-neutral-100' },
  ];

  // Sử dụng thuật toán DJB2 để băm chuỗi (tốt hơn toán tử cộng dồn đơn giản)
  let hash = 5381;
  const str = company.toLowerCase().trim();
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) + hash) + str.charCodeAt(i); 
  }

  return colors[Math.abs(hash) % colors.length];
};

import React, { useState, useMemo, useRef } from 'react';
import { Task, ReportTemplate, ReportLayout, TaskStatus } from '../types';
import { getCompanyColor } from '../constants';

interface ExportModalProps {
  tasks: Task[];
  templates: ReportTemplate[];
  onSaveTemplate: (template: ReportTemplate) => void;
  onDeleteTemplate: (id: string) => void;
  onClose: () => void;
}

const ExportModal: React.FC<ExportModalProps> = ({ tasks, templates, onSaveTemplate, onDeleteTemplate, onClose }) => {
  const today = new Date();
  const todayStr = today.toISOString().split('T')[0];
  const currentMonth = today.getMonth() + 1;
  const reportRef = useRef<HTMLDivElement>(null);

  const [startDate, setStartDate] = useState(todayStr);
  const [endDate, setEndDate] = useState(todayStr);
  const [templateName, setTemplateName] = useState('');
  const [layout, setLayout] = useState<ReportLayout>('FLAT');
  const [columns, setColumns] = useState({
    company: true,
    content: true,
    status: true,
    priority: true,
    date: true,
    pendingTasks: true
  });

  const filteredTasks = useMemo(() => {
    return tasks.filter(t => {
      const taskDate = t.createdAt.split('T')[0];
      return taskDate >= startDate && taskDate <= endDate;
    });
  }, [tasks, startDate, endDate]);

  const groupedTasks = useMemo<Record<string, Task[]> | null>(() => {
    if (layout !== 'GROUPED_BY_COMPANY') return null;
    const groups: Record<string, Task[]> = {};
    filteredTasks.forEach(task => {
      if (!groups[task.company]) groups[task.company] = [];
      groups[task.company].push(task);
    });
    return groups;
  }, [filteredTasks, layout]);

  const formatDate = (dateStr: string) => {
    const [y, m, d] = dateStr.split('-');
    return `${d}/${m}/${y}`;
  };

  const handleApplyTemplate = (tpl: ReportTemplate) => {
    setColumns({ ...tpl.columns });
    setLayout(tpl.layout || 'FLAT');
    setTemplateName(tpl.name);
  };

  const handleSaveTemplate = () => {
    if (!templateName.trim()) {
      alert("Vui lòng nhập tên để lưu mẫu cấu hình này");
      return;
    }
    const newTemplate: ReportTemplate = {
      id: crypto.randomUUID(),
      name: templateName,
      layout,
      columns: { ...columns }
    };
    onSaveTemplate(newTemplate);
    alert("Đã lưu cấu hình báo cáo thành công!");
  };

  // --- LOGIC XUẤT FILE ---

  const handleExportCSV = () => {
    const csvRows: string[] = [];
    csvRows.push(`"BÁO CÁO TUẦN THÁNG ${currentMonth}"`);
    csvRows.push(`"Ngày: ${formatDate(startDate)} - ${formatDate(endDate)}"`);
    csvRows.push("");

    const headers: string[] = [];
    if (layout === 'FLAT') {
      if (columns.company) headers.push('Công ty');
      if (columns.content) headers.push('Nội dung công việc');
      if (columns.pendingTasks) headers.push('Công việc đang làm');
      if (columns.date) headers.push('Ngày tạo');
      if (columns.status) headers.push('Trạng thái');
      csvRows.push(headers.join(','));
      filteredTasks.forEach(t => {
        const row = [];
        if (columns.company) row.push(`"${t.company}"`);
        if (columns.content) row.push(`"${t.content.replace(/"/g, '""')}"`);
        if (columns.pendingTasks) row.push(`"${t.status !== TaskStatus.DONE ? t.content.replace(/"/g, '""') : ''}"`);
        if (columns.date) row.push(`"${new Date(t.createdAt).toLocaleDateString('vi-VN')}"`);
        if (columns.status) row.push(`"${t.status === 'DONE' ? 'Xong' : 'Làm'}"`);
        csvRows.push(row.join(','));
      });
    } else {
      headers.push('Công ty', 'Tổng nội dung', 'Đang làm');
      csvRows.push(headers.join(','));
      (Object.entries(groupedTasks || {}) as [string, Task[]][]).forEach(([company, tasks]) => {
        const row = [`"${company.toUpperCase()}"`];
        row.push(`"${tasks.map((t, idx) => `${idx + 1}. ${t.content}`).join('\r\n').replace(/"/g, '""')}"`);
        row.push(`"${tasks.filter(t => t.status !== TaskStatus.DONE).map((t, idx) => `${idx + 1}. ${t.content}`).join('\r\n').replace(/"/g, '""')}"`);
        csvRows.push(row.join(','));
      });
    }

    const blob = new Blob(['\ufeff' + csvRows.join('\n')], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `Bao_Cao_${startDate}.csv`;
    link.click();
  };

  const handleExportWord = () => {
    if (!reportRef.current) return;
    const reportHtml = reportRef.current.innerHTML;

    // Header HTML cho Word với bảng màu mở rộng
    const header = `<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
                    <head><meta charset='utf-8'><title>Báo cáo</title>
                    <style>
                      table { border-collapse: collapse; width: 100%; border: 1px solid #e2e8f0; }
                      th { background-color: #f1f5f9; font-weight: bold; border: 1px solid #cbd5e1; padding: 10px; text-align: left; text-transform: uppercase; font-size: 12px; }
                      td { border: 1px solid #e2e8f0; padding: 10px; text-align: left; font-size: 11px; vertical-align: top; }
                      h3 { text-align: center; font-family: sans-serif; text-transform: uppercase; }
                      .date-info { text-align: center; color: #64748b; margin-bottom: 20px; font-family: sans-serif; }

                      /* Các màu nền cho công ty - Đồng bộ với constants.ts */
                      .bg-blue-100 { background-color: #dbeafe !important; } .text-blue-700 { color: #1d4ed8 !important; }
                      .bg-emerald-100 { background-color: #dcfce7 !important; } .text-emerald-700 { color: #047857 !important; }
                      .bg-violet-100 { background-color: #ede9fe !important; } .text-violet-700 { color: #6d28d9 !important; }
                      .bg-amber-100 { background-color: #fef3c7 !important; } .text-amber-700 { color: #b45309 !important; }
                      .bg-rose-100 { background-color: #ffe4e6 !important; } .text-rose-700 { color: #be123c !important; }
                      .bg-cyan-100 { background-color: #cffafe !important; } .text-cyan-700 { color: #0e7490 !important; }
                      .bg-orange-100 { background-color: #ffedd5 !important; } .text-orange-700 { color: #c2410c !important; }
                      .bg-fuchsia-100 { background-color: #fae8ff !important; } .text-fuchsia-700 { color: #a21caf !important; }
                      .bg-teal-100 { background-color: #ccfbf1 !important; } .text-teal-700 { color: #0f766e !important; }
