export enum TaskStatus {
  NOT_STARTED = 'NOT_STARTED',
  IN_PROGRESS = 'IN_PROGRESS',
  DONE = 'DONE'
}

export interface Task {
  id: string;
  content: string;
  company: string;
  createdAt: string; // ISO String
  status: TaskStatus;
  isPriority: boolean; // Công việc gấp/ưu tiên
  deletedAt?: string; // ISO String - Dùng cho thùng rác 30 ngày
}

export interface User {
  email: string;
  password: string;
}

export type ReportLayout = 'FLAT' | 'GROUPED_BY_COMPANY';

export interface ReportTemplate {
  id: string;
  name: string;
  layout: ReportLayout;
  columns: {
    company: boolean;
    content: boolean;
    status: boolean;
    priority: boolean;
    date: boolean;
    pendingTasks: boolean;
  };
}

export interface AppState {
  email: string;
  tasks: Task[];
  companies: string[];
  lastLaunchDate: string;
  reportTemplates?: ReportTemplate[];
}

export const COMPANIES = [
  "Agriviet",
  "TechFlow",
  "GreenLogistics",
  "SmartSolutions",
  "GlobalTrade Co.",
  "Personal/Other"
];

export const STATUS_LABELS: Record<string, { label: string; color: string }> = {
  NOT_STARTED: { label: 'Chưa làm', color: 'bg-slate-200 text-slate-700' },
  IN_PROGRESS: { label: 'Đang làm', color: 'bg-blue-100 text-blue-700 border border-blue-200' },
  DONE: { label: 'Đã xong', color: 'bg-emerald-100 text-emerald-700 border border-emerald-200' }
};

export const getCompanyColor = (company: string) => {
  // Bảng màu 20 bộ - Đã loại bỏ Đỏ (Red), Hồng (Pink), Đỏ hồng (Rose) để dành riêng cho việc gấp
  const colors = [
    { bg: 'bg-blue-50', text: 'text-blue-700', border: 'border-blue-200', badge: 'bg-blue-600', light: 'bg-blue-100' },
    { bg: 'bg-emerald-50', text: 'text-emerald-700', border: 'border-emerald-200', badge: 'bg-emerald-600', light: 'bg-emerald-100' },
    { bg: 'bg-violet-50', text: 'text-violet-700', border: 'border-violet-200', badge: 'bg-violet-600', light: 'bg-violet-100' },
    { bg: 'bg-amber-50', text: 'text-amber-700', border: 'border-amber-200', badge: 'bg-amber-600', light: 'bg-amber-100' },
    { bg: 'bg-cyan-50', text: 'text-cyan-700', border: 'border-cyan-200', badge: 'bg-cyan-600', light: 'bg-cyan-100' },
    { bg: 'bg-teal-50', text: 'text-teal-700', border: 'border-teal-200', badge: 'bg-teal-600', light: 'bg-teal-100' },
    { bg: 'bg-indigo-50', text: 'text-indigo-700', border: 'border-indigo-200', badge: 'bg-indigo-600', light: 'bg-indigo-100' },
    { bg: 'bg-lime-50', text: 'text-lime-700', border: 'border-lime-200', badge: 'bg-lime-600', light: 'bg-lime-100' },
    { bg: 'bg-sky-50', text: 'text-sky-700', border: 'border-sky-200', badge: 'bg-sky-600', light: 'bg-sky-100' },
    { bg: 'bg-purple-50', text: 'text-purple-700', border: 'border-purple-200', badge: 'bg-purple-600', light: 'bg-purple-100' },
    { bg: 'bg-slate-50', text: 'text-slate-700', border: 'border-slate-200', badge: 'bg-slate-600', light: 'bg-slate-100' },
    { bg: 'bg-yellow-50', text: 'text-yellow-700', border: 'border-yellow-200', badge: 'bg-yellow-600', light: 'bg-yellow-100' },
    { bg: 'bg-stone-50', text: 'text-stone-700', border: 'border-stone-200', badge: 'bg-stone-600', light: 'bg-stone-100' },
    { bg: 'bg-zinc-50', text: 'text-zinc-700', border: 'border-zinc-200', badge: 'bg-zinc-600', light: 'bg-zinc-100' },
    { bg: 'bg-neutral-50', text: 'text-neutral-700', border: 'border-neutral-200', badge: 'bg-neutral-600', light: 'bg-neutral-100' },
    { bg: 'bg-blue-100/30', text: 'text-blue-800', border: 'border-blue-300', badge: 'bg-blue-800', light: 'bg-blue-200' },
    { bg: 'bg-emerald-100/30', text: 'text-emerald-800', border: 'border-emerald-300', badge: 'bg-emerald-800', light: 'bg-emerald-200' },
    { bg: 'bg-indigo-100/30', text: 'text-indigo-800', border: 'border-indigo-300', badge: 'bg-indigo-800', light: 'bg-indigo-200' },
    { bg: 'bg-teal-100/30', text: 'text-teal-800', border: 'border-teal-300', badge: 'bg-teal-800', light: 'bg-teal-200' },
    { bg: 'bg-purple-100/30', text: 'text-purple-800', border: 'border-purple-300', badge: 'bg-purple-800', light: 'bg-purple-200' },
  ];

  // Thuật toán băm DJB2 cải tiến
  let hash = 5381;
  const str = company.toLowerCase().trim();
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) + hash) + str.charCodeAt(i); 
  }

  // Sử dụng phép chia lấy dư để chọn màu
  return colors[Math.abs(hash) % colors.length];
};

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import TaskItem from './components/TaskItem';
import Login from './components/Login';
import Setup from './components/Setup';
import HistoryModal from './components/HistoryModal';
import ExportModal from './components/ExportModal';
import { Task, TaskStatus, AppState, ReportTemplate } from './types';
import { loadStateSecure, saveStateSecure } from './services/storageService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<{email: string, pass: string} | null>(null);
  const [state, setState] = useState<AppState | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [loading, setLoading] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isExportOpen, setIsExportOpen] = useState(false);
  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);

  // State cho hộp thoại xác nhận xóa
  const [confirmDelete, setConfirmDelete] = useState<string | null>(null);

  const handleLogin = async (email: string, pass: string) => {
    setLoading(true);
    try {
      const loaded = await loadStateSecure(email, pass);
      setCurrentUser({ email, pass });
      setState(loaded);
    } catch (e: any) { alert(e.message); }
    finally { setLoading(false); }
  };

  const handleSetupComplete = (companies: string[]) => {
    setState(prev => prev ? ({ ...prev, companies }) : null);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setState(null);
  };

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  // Tự động dọn dẹp task trong thùng rác cũ hơn 30 ngày
  useEffect(() => {
    if (state && state.tasks) {
      const now = new Date();
      const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

      const cleanedTasks = state.tasks.filter(t => {
        if (!t.deletedAt) return true;
        const deletedTime = new Date(t.deletedAt);
        return deletedTime > thirtyDaysAgo;
      });

      if (cleanedTasks.length !== state.tasks.length) {
        setState(prev => prev ? ({ ...prev, tasks: cleanedTasks }) : null);
      }
    }
  }, [state?.lastLaunchDate]);

  useEffect(() => {
    if (currentUser && state) saveStateSecure(currentUser.email, currentUser.pass, state);
  }, [state, currentUser]);

  const addTask = useCallback((content: string, company: string, isPriority: boolean) => {
    if (!state) return;
    const newTask: Task = {
      id: crypto.randomUUID(),
      content,
      company,
      createdAt: new Date().toISOString(),
      status: TaskStatus.NOT_STARTED,
      isPriority
    };
    setState(prev => prev ? ({ ...prev, tasks: [newTask, ...prev.tasks] }) : null);
    setIsMobileSidebarOpen(false);
  }, [state]);

  const addCompany = useCallback((companyName: string) => {
    setState(prev => prev ? ({ ...prev, companies: Array.from(new Set([...prev.companies, companyName])) }) : null);
  }, []);

  const updateTaskStatus = useCallback((id: string, status: TaskStatus) => {
    setState(prev => prev ? ({ ...prev, tasks: prev.tasks.map(t => t.id === id ? { ...t, status } : t) }) : null);
  }, []);

  // Xóa tạm thời (Soft Delete) - Lưu lại trong 30 ngày
  const deleteTask = useCallback((id: string) => {
    setState(prev => prev ? ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === id ? { ...t, deletedAt: new Date().toISOString() } : t)
    }) : null);
    setConfirmDelete(null);
  }, []);

  const saveReportTemplate = useCallback((template: ReportTemplate) => {
    setState(prev => {
      if (!prev) return null;
      const templates = prev.reportTemplates || [];
      const existingIdx = templates.findIndex(t => t.name === template.name);
      if (existingIdx >= 0) {
        const newTemplates = [...templates];
        newTemplates[existingIdx] = template;
        return { ...prev, reportTemplates: newTemplates };
      }
      return { ...prev, reportTemplates: [...templates, template] };
    });
  }, []);

  const deleteReportTemplate = useCallback((id: string) => {
    setState(prev => {
      if (!prev) return null;
      const templates = prev.reportTemplates || [];
      return { ...prev, reportTemplates: templates.filter(tpl => tpl.id !== id) };
    });
  }, []);

  const currentViewTasks = useMemo(() => {
    if (!state) return [];
    const today = new Date().toISOString().split('T')[0];
    // Chỉ hiển thị các task chưa bị xóa
    return state.tasks.filter(t => !t.deletedAt).filter(t => {
      if (t.status !== TaskStatus.DONE) return true;
      return t.createdAt.startsWith(today);
    }).sort((a, b) => {
      const getRank = (task: Task) => {
        if (task.status === TaskStatus.IN_PROGRESS) return 0;
        if (task.isPriority) return 1;
        if (task.status === TaskStatus.NOT_STARTED) return 2;
        return 3;
      };
      const rankA = getRank(a), rankB = getRank(b);
      if (rankA !== rankB) return rankA - rankB;
      return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
    });
  }, [state]);

  if (loading) return (
    <div className="h-screen bg-white flex flex-col items-center justify-center text-blue-600 p-6 text-center">
      <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
      <p className="font-black uppercase tracking-[0.2em] text-[10px]">Đang truy xuất dữ liệu an toàn...</p>
    </div>
  );

  if (!currentUser || !state) return <Login onLogin={handleLogin} />;
  if (state.companies.length === 0) return <Setup onComplete={handleSetupComplete} onLogout={handleLogout} />;

  const activeCount = state.tasks.filter(t => !t.deletedAt && t.status !== TaskStatus.DONE).length;
  const doneTodayCount = state.tasks.filter(t => !t.deletedAt && t.status === TaskStatus.DONE && t.createdAt.startsWith(new Date().toISOString().split('T')[0])).length;

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-white">
      {/* Delete Confirmation Modal */}
      {confirmDelete && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-200">
           <div className="bg-white p-8 md:p-10 rounded-[2.5rem] shadow-2xl max-w-sm w-full text-center animate-in zoom-in-95 duration-200 border border-slate-100">
              <div className="w-16 h-16 bg-rose-50 text-rose-500 rounded-full flex items-center justify-center mx-auto mb-6">
                 <i className="fas fa-trash-alt text-2xl"></i>
              </div>
              <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight mb-2">Bạn chắc chắn chứ?</h3>
              <p className="text-sm text-slate-500 font-medium mb-8">Công việc sẽ được chuyển vào mục lưu trữ tạm thời trong 30 ngày trước khi bị xóa hẳn.</p>
              <div className="flex gap-3">
                 <button 
                  onClick={() => setConfirmDelete(null)}
                  className="flex-1 py-4 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all"
                 >
                   HỦY BỎ
                 </button>
                 <button 
                  onClick={() => deleteTask(confirmDelete)}
                  className="flex-1 py-4 bg-rose-600 hover:bg-rose-700 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-rose-200 transition-all"
                 >
                   ĐỒNG Ý XÓA
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* Mobile Overlay */}
      {isMobileSidebarOpen && (
        <div 
          className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-40 md:hidden"
          onClick={() => setIsMobileSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <div className={`fixed inset-y-0 left-0 z-50 transform ${isMobileSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0 transition-transform duration-300 ease-in-out md:flex-shrink-0`}>
        <Sidebar 
          email={currentUser.email}
          companies={state.companies}
          onAddTask={addTask} 
          onAddCompany={addCompany}
          onClearAll={() => { if(confirm("Xóa toàn bộ kho lưu trữ vĩnh viễn?")) setState({ ...state, tasks: [] }); }} 
          onLogout={handleLogout}
          onOpenHistory={() => { setIsHistoryOpen(true); setIsMobileSidebarOpen(false); }}
          onOpenExport={() => { setIsExportOpen(true); setIsMobileSidebarOpen(false); }}
          onCloseMobile={() => setIsMobileSidebarOpen(false)}
        />
      </div>

      <main className="flex-1 flex flex-col min-w-0 bg-slate-50 relative h-screen overflow-hidden">
        <header className="min-h-[96px] py-4 px-6 md:px-10 bg-white border-b border-slate-100 flex flex-col md:flex-row md:items-center justify-between z-10 shadow-sm gap-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <button 
                onClick={() => setIsMobileSidebarOpen(true)}
                className="md:hidden w-10 h-10 rounded-xl bg-slate-50 text-slate-600 flex items-center justify-center border border-slate-100"
              >
                <i className="fas fa-bars"></i>
              </button>
              <div>
                <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tight leading-tight">CÔNG VIỆC HIỆN TẠI</h2>
                <div className="flex items-center gap-2 mt-0.5">
                  <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                  <p className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest truncate max-w-[150px] md:max-w-none">
                    {currentTime.toLocaleDateString('vi-VN', { weekday: 'short', day: 'numeric', month: 'short' })}
                  </p>
                </div>
              </div>
            </div>
            <div className="md:hidden text-right">
               <p className="text-xl font-mono font-bold text-slate-800 leading-tight">
                {currentTime.toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' })}
              </p>
            </div>
          </div>

          <div className="flex items-center justify-between md:justify-end gap-4 md:gap-8">
            <div className="text-left md:text-right border-r md:border-r-0 border-slate-100 pr-4 md:pr-0">
              <p className="text-[8px] md:text-[9px] font-black text-slate-400 uppercase tracking-widest">Đang làm</p>
              <p className="text-xl md:text-2xl font-black text-rose-500 leading-tight">{activeCount}</p>
            </div>
            <div className="text-left md:text-right">
              <p className="text-[8px] md:text-[9px] font-black text-slate-400 uppercase tracking-widest">Xong hôm nay</p>
              <p className="text-xl md:text-2xl font-black text-emerald-500 leading-tight">{doneTodayCount}</p>
            </div>
            <div className="hidden md:block h-10 w-px bg-slate-100"></div>
            <div className="hidden md:block text-right">
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Giờ hệ thống</p>
              <p className="text-2xl font-mono font-bold text-slate-800 leading-tight">{currentTime.toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' })}</p>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar">
          {currentViewTasks.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-300 opacity-50 px-6 text-center">
              <div className="w-20 h-20 md:w-24 md:h-24 bg-white rounded-full flex items-center justify-center mb-6 shadow-sm border border-slate-100">
                <i className="fas fa-clipboard-check text-3xl md:text-4xl"></i>
              </div>
              <p className="font-black uppercase tracking-widest text-xs md:text-sm">Mọi thứ đã hoàn thành tốt đẹp!</p>
            </div>
          ) : (
            <div className="max-w-4xl mx-auto space-y-4 pb-24">
              {currentViewTasks.map((task) => (
                <TaskItem 
                  key={task.id} 
                  task={task} 
                  onStatusChange={updateTaskStatus} 
                  onDelete={(id) => setConfirmDelete(id)} 
                />
              ))}
            </div>
          )}
        </div>

        <div className="absolute bottom-6 right-6 md:right-10 flex items-center gap-2 px-4 py-2 bg-white border border-slate-100 rounded-full shadow-lg text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest">
           <i className="fas fa-database text-blue-500"></i> <span className="hidden sm:inline">Kho lưu trữ:</span> {state.tasks.filter(t => !t.deletedAt).length} mục
        </div>
      </main>

      {isHistoryOpen && (
        <HistoryModal 
          tasks={state.tasks.filter(t => !t.deletedAt)} 
          onClose={() => setIsHistoryOpen(false)} 
        />
      )}
      {isExportOpen && (
        <ExportModal 
          tasks={state.tasks.filter(t => !t.deletedAt)} 
          templates={state.reportTemplates || []}
          onSaveTemplate={saveReportTemplate}
          onDeleteTemplate={deleteReportTemplate}
          onClose={() => setIsExportOpen(false)} 
        />
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { Task, TaskStatus } from '../types';
import { STATUS_LABELS, getCompanyColor } from '../constants';

interface TaskItemProps {
  task: Task;
  onStatusChange?: (id: string, status: TaskStatus) => void;
  onDelete?: (id: string) => void;
  readOnly?: boolean;
}

const TaskItem: React.FC<TaskItemProps> = ({ task, onStatusChange, onDelete, readOnly = false }) => {
  const formattedTime = new Date(task.createdAt).toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' });
  const cpColor = getCompanyColor(task.company);
  const isDone = task.status === TaskStatus.DONE;
  const isInProgress = task.status === TaskStatus.IN_PROGRESS;

  // CSS class cho viền trái: Ưu tiên màu đỏ nếu là việc gấp
  const borderLeftColor = task.isPriority ? 'border-l-rose-500' : `border-l-${cpColor.badge.replace('bg-', '')}`;

  return (
    <div className={`group p-4 md:p-6 rounded-[1.2rem] md:rounded-[1.5rem] border-l-[6px] border-t border-r border-b transition-all flex flex-col items-start gap-4 md:gap-6 ${
      isDone ? 'opacity-50 bg-slate-50 border-slate-200' : 
      task.isPriority ? 'bg-rose-50/70 border-rose-200' : 
      `${cpColor.bg} ${cpColor.border}`
    } ${borderLeftColor} ${!isDone && !readOnly && 'hover:shadow-lg active:scale-[0.99]'}`}>

      <div className="w-full min-w-0">
        <div className="flex items-center gap-2 mb-3 flex-wrap">
          {isInProgress && (
            <span className="flex items-center gap-1.5 text-[8px] md:text-[9px] font-black px-2 py-0.5 md:px-2.5 md:py-1 rounded-full bg-blue-600 text-white uppercase tracking-widest animate-pulse">
              <i className="fas fa-spinner fa-spin text-[7px] md:text-[8px]"></i> Đang làm
            </span>
          )}
          {task.isPriority && (
            <span className="flex items-center gap-1.5 text-[8px] md:text-[9px] font-black px-2 py-0.5 md:px-2.5 md:py-1 rounded-full bg-rose-600 text-white uppercase tracking-widest shadow-sm">
              <i className="fas fa-bolt text-[7px] md:text-[8px]"></i> Gấp
            </span>
          )}
          <span className={`text-[9px] md:text-[10px] font-black px-2.5 py-0.5 md:px-3 md:py-1 rounded-full uppercase tracking-widest ${
            task.isPriority ? 'bg-rose-100 text-rose-700' : `${cpColor.light} ${cpColor.text}`
          }`}>
            {task.company}
          </span>
          <span className="text-[9px] md:text-[10px] text-slate-400 font-bold uppercase tracking-tight ml-auto">
            <i className="far fa-clock mr-1"></i> {formattedTime}
          </span>
        </div>
        <p className={`text-slate-800 font-bold text-base md:text-lg leading-snug break-words ${isDone ? 'line-through opacity-40 text-slate-400' : ''}`}>
          {task.content}
        </p>
      </div>

      {!readOnly && (
        <div className="flex items-center justify-between w-full mt-2 md:mt-0">
          <div className={`flex p-1 rounded-xl md:rounded-2xl border bg-white/80 backdrop-blur-sm ${task.isPriority ? 'border-rose-100' : cpColor.border}`}>
            {(Object.values(TaskStatus) as TaskStatus[]).map((status) => (
              <button
                key={status}
                onClick={() => onStatusChange?.(task.id, status)}
                className={`px-3 py-1.5 md:px-4 md:py-2 rounded-lg md:rounded-xl text-[8px] md:text-[10px] font-black uppercase tracking-widest transition-all ${
                  task.status === status
                    ? STATUS_LABELS[status].color + " shadow-sm scale-105"
                    : 'text-slate-400 hover:text-slate-600'
                }`}
              >
                {STATUS_LABELS[status].label}
              </button>
            ))}
          </div>
          <button
            onClick={() => onDelete?.(task.id)}
            className="w-9 h-9 md:w-10 md:h-10 rounded-lg md:rounded-xl flex items-center justify-center text-slate-300 hover:text-rose-500 hover:bg-rose-50 transition-all"
          >
            <i className="fas fa-trash-alt text-sm"></i>
          </button>
        </div>
      )}

      {readOnly && (
        <div className="flex items-center gap-2 text-[9px] md:text-[10px] font-black uppercase tracking-widest text-slate-400 ml-auto">
           <i className="fas fa-lock text-[8px]"></i> {STATUS_LABELS[task.status].label}
        </div>
      )}
    </div>
  );
};

export default TaskItem;

{
  "name": "ZenTask Manager Pro",
  "description": "Task management with multi-language, dark mode, and smart notifications.",
  "requestFramePermissions": []
}

export enum TaskStatus {
  NOT_STARTED = 'NOT_STARTED',
  IN_PROGRESS = 'IN_PROGRESS',
  DONE = 'DONE'
}

export type Language = 'vi' | 'en' | 'zh' | 'ru';
export type Theme = 'light' | 'dark';

export interface Task {
  id: string;
  content: string;
  company: string;
  createdAt: string; 
  updatedAt: string; // Theo dõi thời điểm chuyển trạng thái
  status: TaskStatus;
  isPriority: boolean;
  deletedAt?: string;
}

export interface ReportTemplate {
  id: string;
  name: string;
  layout: 'FLAT' | 'GROUPED_BY_COMPANY';
  columns: {
    company: boolean;
    content: boolean;
    status: boolean;
    priority: boolean;
    date: boolean;
    pendingTasks: boolean;
  };
}

export interface AppState {
  email: string;
  tasks: Task[];
  companies: string[];
  lastLaunchDate: string;
  reportTemplates?: ReportTemplate[];
  settings: {
    language: Language;
    theme: Theme;
  };
}

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import TaskItem from './components/TaskItem';
import Login from './components/Login';
import Setup from './components/Setup';
import HistoryModal from './components/HistoryModal';
import ExportModal from './components/ExportModal';
import SettingsModal from './components/SettingsModal';
import { Task, TaskStatus, AppState, ReportTemplate, Language, Theme } from './types';
import { loadStateSecure, saveStateSecure } from './services/storageService';
import { translations } from './translations';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<{email: string, pass: string} | null>(null);
  const [state, setState] = useState<AppState | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [loading, setLoading] = useState(false);
  const [modals, setModals] = useState({
    history: false,
    export: false,
    settings: false,
    delete: null as string | null
  });
  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);

  const t = translations[state?.settings?.language || 'vi'];

  // Cập nhật Theme class trên document
  useEffect(() => {
    if (state?.settings?.theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [state?.settings?.theme]);

  // Request notification permission
  useEffect(() => {
    if ("Notification" in window && Notification.permission === "default") {
      Notification.requestPermission();
    }
  }, []);

  // Timer cho đồng hồ và thông báo
  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now);

      // 1. Nhắc nhở cố định 8h sáng và 13h chiều
      const hours = now.getHours();
      const mins = now.getMinutes();
      const secs = now.getSeconds();

      if (secs === 0 && mins === 0 && (hours === 8 || hours === 13)) {
        const unfinished = state?.tasks.filter(tk => !tk.deletedAt && tk.status !== TaskStatus.DONE).length || 0;
        if (unfinished > 0) {
          new Notification(t.appName, { body: t.unfinishedNotify(unfinished) });
        }
      }

      // 2. Nhắc nhở tiến độ 3 tiếng
      if (secs === 0 && state) {
        state.tasks.forEach(task => {
          if (!task.deletedAt && task.status === TaskStatus.IN_PROGRESS) {
            const lastUpdate = new Date(task.updatedAt);
            const diffHours = (now.getTime() - lastUpdate.getTime()) / (1000 * 60 * 60);
            if (diffHours >= 3) {
              new Notification(t.appName, { body: `${task.content}: ${t.progressReminder}` });
            }
          }
        });
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [state, t]);

  const handleLogin = async (email: string, pass: string) => {
    setLoading(true);
    try {
      const loaded = await loadStateSecure(email, pass);
      // Đảm bảo settings tồn tại
      if (!loaded.settings) {
        loaded.settings = { language: 'vi', theme: 'light' };
      }
      setCurrentUser({ email, pass });
      setState(loaded);
    } catch (e: any) { alert(e.message); }
    finally { setLoading(false); }
  };

  const handleSetupComplete = (companies: string[]) => {
    setState(prev => prev ? ({ ...prev, companies }) : null);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setState(null);
  };

  useEffect(() => {
    if (state && state.tasks) {
      const now = new Date();
      const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
      const cleanedTasks = state.tasks.filter(t => !t.deletedAt || new Date(t.deletedAt) > thirtyDaysAgo);
      if (cleanedTasks.length !== state.tasks.length) {
        setState(prev => prev ? ({ ...prev, tasks: cleanedTasks }) : null);
      }
    }
  }, [state?.lastLaunchDate]);

  useEffect(() => {
    if (currentUser && state) saveStateSecure(currentUser.email, currentUser.pass, state);
  }, [state, currentUser]);

  const addTask = useCallback((content: string, company: string, isPriority: boolean) => {
    if (!state) return;
    const now = new Date().toISOString();
    const newTask: Task = {
      id: crypto.randomUUID(),
      content,
      company,
      createdAt: now,
      updatedAt: now,
      status: TaskStatus.NOT_STARTED,
      isPriority
    };
    setState(prev => prev ? ({ ...prev, tasks: [newTask, ...prev.tasks] }) : null);
    setIsMobileSidebarOpen(false);
  }, [state]);

  const updateTaskStatus = useCallback((id: string, status: TaskStatus) => {
    setState(prev => prev ? ({ 
      ...prev, 
      tasks: prev.tasks.map(t => t.id === id ? { ...t, status, updatedAt: new Date().toISOString() } : t) 
    }) : null);
  }, []);

  const deleteTask = useCallback((id: string) => {
    setState(prev => prev ? ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === id ? { ...t, deletedAt: new Date().toISOString() } : t)
    }) : null);
    setModals(m => ({ ...m, delete: null }));
  }, []);

  const updateSettings = useCallback((lang: Language, theme: Theme) => {
    setState(prev => prev ? ({ ...prev, settings: { language: lang, theme } }) : null);
  }, []);

  const currentViewTasks = useMemo(() => {
    if (!state) return [];
    const today = new Date().toISOString().split('T')[0];
    return state.tasks.filter(t => !t.deletedAt).filter(t => {
      if (t.status !== TaskStatus.DONE) return true;
      return t.createdAt.startsWith(today);
    }).sort((a, b) => {
      const getRank = (task: Task) => {
        if (task.status === TaskStatus.IN_PROGRESS) return 0;
        if (task.isPriority) return 1;
        if (task.status === TaskStatus.NOT_STARTED) return 2;
        return 3;
      };
      return getRank(a) - getRank(b) || new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
    });
  }, [state]);

  if (loading) return (
    <div className="h-screen bg-white dark:bg-slate-950 flex flex-col items-center justify-center text-blue-600 p-6 text-center">
      <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
      <p className="font-black uppercase tracking-[0.2em] text-[10px]">ZenTask Loading...</p>
    </div>
  );

  if (!currentUser || !state) return <Login onLogin={handleLogin} />;
  if (state.companies.length === 0) return <Setup onComplete={handleSetupComplete} onLogout={handleLogout} />;

  const activeCount = state.tasks.filter(t => !t.deletedAt && t.status !== TaskStatus.DONE).length;
  const doneTodayCount = state.tasks.filter(t => !t.deletedAt && t.status === TaskStatus.DONE && t.createdAt.startsWith(new Date().toISOString().split('T')[0])).length;

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-white dark:bg-slate-950 transition-colors duration-300">
      {/* Delete Confirmation */}
      {modals.delete && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-200">
           <div className="bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] shadow-2xl max-w-sm w-full text-center border border-slate-100 dark:border-slate-800">
              <div className="w-16 h-16 bg-rose-50 dark:bg-rose-950/30 text-rose-500 rounded-full flex items-center justify-center mx-auto mb-6">
                 <i className="fas fa-trash-alt text-2xl"></i>
              </div>
              <h3 className="text-xl font-black text-slate-800 dark:text-white uppercase mb-2">{t.confirmDelete}</h3>
              <p className="text-sm text-slate-500 dark:text-slate-400 mb-8">{t.confirmDeleteDesc}</p>
              <div className="flex gap-3">
                 <button onClick={() => setModals(m => ({ ...m, delete: null }))} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 rounded-2xl font-black text-[10px] uppercase tracking-widest">{t.cancel}</button>
                 <button onClick={() => deleteTask(modals.delete!)} className="flex-1 py-4 bg-rose-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest">{t.confirm}</button>
              </div>
           </div>
        </div>
      )}

      {isMobileSidebarOpen && <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-40 md:hidden" onClick={() => setIsMobileSidebarOpen(false)} />}

      <div className={`fixed inset-y-0 left-0 z-50 transform ${isMobileSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0 transition-transform duration-300 ease-in-out md:flex-shrink-0`}>
        <Sidebar 
          email={currentUser.email}
          companies={state.companies}
          language={state.settings.language}
          onAddTask={addTask} 
          onAddCompany={c => setState(p => p ? ({...p, companies: [...p.companies, c]}) : null)}
          onClearAll={() => { if(confirm("Format Storage?")) setState({...state, tasks: []}); }} 
          onLogout={handleLogout}
          onOpenHistory={() => { setModals(m => ({...m, history: true})); setIsMobileSidebarOpen(false); }}
          onOpenExport={() => { setModals(m => ({...m, export: true})); setIsMobileSidebarOpen(false); }}
          onOpenSettings={() => { setModals(m => ({...m, settings: true})); setIsMobileSidebarOpen(false); }}
          onCloseMobile={() => setIsMobileSidebarOpen(false)}
        />
      </div>

      <main className="flex-1 flex flex-col min-w-0 bg-slate-50 dark:bg-slate-900 relative h-screen overflow-hidden">
        <header className="min-h-[96px] py-4 px-6 md:px-10 bg-white dark:bg-slate-950 border-b border-slate-100 dark:border-slate-800 flex flex-col md:flex-row md:items-center justify-between z-10 shadow-sm gap-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <button onClick={() => setIsMobileSidebarOpen(true)} className="md:hidden w-10 h-10 rounded-xl bg-slate-50 dark:bg-slate-900 text-slate-600 dark:text-slate-400 flex items-center justify-center"><i className="fas fa-bars"></i></button>
              <div>
