}

const SettingsModal: React.FC<SettingsModalProps> = ({ language, theme: initialTheme, onUpdate, onClose }) => {
  const [tempLanguage, setTempLanguage] = useState<Language>(language);
  const [tempTheme, setTempTheme] = useState<Theme>(initialTheme);
  const t = translations[tempLanguage];

  // Áp dụng theme tạm thời lên document để xem trước
  useEffect(() => {
    if (tempTheme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [tempTheme]);

  const handleSave = () => {
    onUpdate(tempLanguage, tempTheme);
    onClose();
  };

  const handleCancel = () => {
    // Hoàn tác theme về trạng thái ban đầu trước khi đóng
    if (initialTheme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-200">
      <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-[2.5rem] shadow-2xl border border-slate-100 dark:border-slate-800 overflow-hidden transform animate-in zoom-in-95 duration-200">
        <header className="p-8 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center">
          <h2 className="text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.settings}</h2>
          <button onClick={handleCancel} className="text-slate-300 hover:text-slate-500 transition-colors">
            <i className="fas fa-times text-xl"></i>
          </button>
        </header>

        <div className="p-8 space-y-8">
          {/* Language Selection */}
          <div className="space-y-4">
            <label className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">{t.language}</label>
            <div className="grid grid-cols-2 gap-3">
              {(['vi', 'en', 'zh', 'ru'] as Language[]).map(lang => (
                <button
                  key={lang}
                  onClick={() => setTempLanguage(lang)}
                  className={`py-4 rounded-2xl border-2 font-black text-[10px] uppercase tracking-widest transition-all ${
                    tempLanguage === lang 
                      ? 'border-blue-600 bg-blue-50 dark:bg-blue-900/40 text-blue-600 dark:text-blue-400' 
                      : 'border-slate-50 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-950/50 text-slate-400'
                  }`}
                >
                  {lang === 'vi' ? 'Tiếng Việt' : lang === 'en' ? 'English' : lang === 'zh' ? '中文' : 'Русский'}
                </button>
              ))}
            </div>
          </div>

          {/* Theme Selection */}
          <div className="space-y-4">
            <label className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">{t.theme}</label>
            <div className="flex gap-3">
              <button
                onClick={() => setTempTheme('light')}
                className={`flex-1 py-4 rounded-2xl border-2 font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-2 transition-all ${
                  tempTheme === 'light' 
                    ? 'border-amber-400 bg-amber-50 text-amber-700 shadow-lg shadow-amber-100' 
                    : 'border-slate-50 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-950/50 text-slate-400'
                }`}
              >
                <i className="fas fa-sun"></i> {t.light}
              </button>
              <button
                onClick={() => setTempTheme('dark')}
                className={`flex-1 py-4 rounded-2xl border-2 font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-2 transition-all ${
                  tempTheme === 'dark' 
                    ? 'border-indigo-600 bg-indigo-900/40 text-indigo-400 shadow-lg shadow-indigo-950/50' 
                    : 'border-slate-50 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-950/50 text-slate-400'
                }`}
              >
                <i className="fas fa-moon"></i> {t.dark}
              </button>
            </div>
          </div>
        </div>

        <footer className="p-8 bg-slate-50 dark:bg-slate-950/50 flex gap-3">
           <button 
             onClick={handleCancel} 
             className="flex-1 py-4 bg-white dark:bg-slate-800 text-slate-500 dark:text-slate-300 border border-slate-200 dark:border-slate-700 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-100 dark:hover:bg-slate-700 transition-all"
           >
             {t.cancel}
           </button>
           <button 
             onClick={handleSave} 
             className="flex-1 py-4 bg-slate-900 dark:bg-blue-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:opacity-90 transition-all"
           >
             {t.save}
           </button>
        </footer>
      </div>
    </div>
  );
};

export default SettingsModal;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import TaskItem from './components/TaskItem';
import Login from './components/Login';
import Setup from './components/Setup';
import HistoryModal from './components/HistoryModal';
import ExportModal from './components/ExportModal';
import SettingsModal from './components/SettingsModal';
import { Task, TaskStatus, AppState, ReportTemplate, Language, Theme } from './types';
import { loadStateSecure, saveStateSecure } from './services/storageService';
import { translations } from './translations';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<{email: string, pass: string} | null>(null);
  const [state, setState] = useState<AppState | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [loading, setLoading] = useState(false);
  const [modals, setModals] = useState({
    history: false,
    export: false,
    settings: false,
    delete: null as string | null
  });
  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);

  const currentLanguage = state?.settings?.language || 'vi';
  const t = translations[currentLanguage];

  // Áp dụng Theme class lên document root
  useEffect(() => {
    if (state?.settings?.theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [state?.settings?.theme]);

  // Request notification permission
  useEffect(() => {
    if ("Notification" in window && Notification.permission === "default") {
      Notification.requestPermission();
    }
  }, []);

  // Hệ thống thông báo thông minh
  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now);

      const hours = now.getHours();
      const mins = now.getMinutes();
      const secs = now.getSeconds();

      // 1. Nhắc nhở 8h sáng và 13h chiều
      if (secs === 0 && mins === 0 && (hours === 8 || hours === 13)) {
        const unfinished = state?.tasks.filter(tk => !tk.deletedAt && tk.status !== TaskStatus.DONE).length || 0;
        if (unfinished > 0 && Notification.permission === "granted") {
          new Notification(t.appName, { body: t.unfinishedNotify(unfinished) });
        }
      }

      // 2. Nhắc nhở 3 tiếng cho việc "Đang làm"
      if (secs === 0 && state) {
        state.tasks.forEach(task => {
          if (!task.deletedAt && task.status === TaskStatus.IN_PROGRESS) {
            const lastUpdate = new Date(task.updatedAt);
            const diffHours = (now.getTime() - lastUpdate.getTime()) / (1000 * 60 * 60);
            // Thông báo mỗi khi đạt mốc 3h, 6h, 9h...
            if (diffHours >= 3 && Math.floor(diffHours) % 3 === 0 && mins === 0) {
              if (Notification.permission === "granted") {
                new Notification(t.appName, { body: `${task.content}: ${t.progressReminder}` });
              }
            }
          }
        });
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [state, t]);

  const handleLogin = async (email: string, pass: string) => {
    setLoading(true);
    try {
      const loaded = await loadStateSecure(email, pass);
      if (!loaded.settings) {
        loaded.settings = { language: 'vi', theme: 'light' };
      }
      setCurrentUser({ email, pass });
      setState(loaded);
    } catch (e: any) { alert(e.message); }
    finally { setLoading(false); }
  };

  const handleSetupComplete = (companies: string[]) => {
    setState(prev => prev ? ({ ...prev, companies }) : null);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setState(null);
  };

  useEffect(() => {
    if (state && state.tasks) {
      const now = new Date();
      const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
      const cleanedTasks = state.tasks.filter(t => !t.deletedAt || new Date(t.deletedAt) > thirtyDaysAgo);
      if (cleanedTasks.length !== state.tasks.length) {
        setState(prev => prev ? ({ ...prev, tasks: cleanedTasks }) : null);
      }
    }
  }, [state?.lastLaunchDate]);

  useEffect(() => {
    if (currentUser && state) saveStateSecure(currentUser.email, currentUser.pass, state);
  }, [state, currentUser]);

  const addTask = useCallback((content: string, company: string, isPriority: boolean) => {
    if (!state) return;
    const now = new Date().toISOString();
    const newTask: Task = {
      id: crypto.randomUUID(),
      content,
      company,
      createdAt: now,
      updatedAt: now,
      status: TaskStatus.NOT_STARTED,
      isPriority
    };
    setState(prev => prev ? ({ ...prev, tasks: [newTask, ...prev.tasks] }) : null);
    setIsMobileSidebarOpen(false);
  }, [state]);

  const updateTaskStatus = useCallback((id: string, status: TaskStatus) => {
    setState(prev => prev ? ({ 
      ...prev, 
      tasks: prev.tasks.map(t => t.id === id ? { ...t, status, updatedAt: new Date().toISOString() } : t) 
    }) : null);
  }, []);

  const deleteTask = useCallback((id: string) => {
    setState(prev => prev ? ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === id ? { ...t, deletedAt: new Date().toISOString() } : t)
    }) : null);
    setModals(m => ({ ...m, delete: null }));
  }, []);

  const updateSettings = useCallback((lang: Language, theme: Theme) => {
    setState(prev => prev ? ({ ...prev, settings: { language: lang, theme } }) : null);
  }, []);

  const currentViewTasks = useMemo(() => {
    if (!state) return [];
    const today = new Date().toISOString().split('T')[0];
    return state.tasks.filter(t => !t.deletedAt).filter(t => {
      if (t.status !== TaskStatus.DONE) return true;
      return t.createdAt.startsWith(today);
    }).sort((a, b) => {
      const getRank = (task: Task) => {
        if (task.status === TaskStatus.IN_PROGRESS) return 0;
        if (task.isPriority) return 1;
        if (task.status === TaskStatus.NOT_STARTED) return 2;
        return 3;
      };
      return getRank(a) - getRank(b) || new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
    });
  }, [state]);

  if (loading) return (
    <div className="h-screen bg-white dark:bg-slate-950 flex flex-col items-center justify-center text-blue-600 p-6 text-center">
      <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
      <p className="font-black uppercase tracking-[0.2em] text-[10px] dark:text-blue-400">ZenTask Loading...</p>
    </div>
  );

  if (!currentUser || !state) return <Login onLogin={handleLogin} />;
  if (state.companies.length === 0) return <Setup onComplete={handleSetupComplete} onLogout={handleLogout} />;

  const activeCount = state.tasks.filter(t => !t.deletedAt && t.status !== TaskStatus.DONE).length;
  const doneTodayCount = state.tasks.filter(t => !t.deletedAt && t.status === TaskStatus.DONE && t.createdAt.startsWith(new Date().toISOString().split('T')[0])).length;

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-white dark:bg-slate-950 transition-colors duration-500">
      {/* Delete Confirmation */}
      {modals.delete && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-200">
           <div className="bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] shadow-2xl max-w-sm w-full text-center border border-slate-100 dark:border-slate-800 animate-in zoom-in-95">
              <div className="w-16 h-16 bg-rose-50 dark:bg-rose-950/30 text-rose-500 rounded-full flex items-center justify-center mx-auto mb-6">
                 <i className="fas fa-trash-alt text-2xl"></i>
              </div>
              <h3 className="text-xl font-black text-slate-800 dark:text-white uppercase mb-2">{t.confirmDelete}</h3>
              <p className="text-sm text-slate-500 dark:text-slate-400 mb-8">{t.confirmDeleteDesc}</p>
              <div className="flex gap-3">
                 <button onClick={() => setModals(m => ({ ...m, delete: null }))} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-200 dark:hover:bg-slate-700 transition-all">{t.cancel}</button>
                 <button onClick={() => deleteTask(modals.delete!)} className="flex-1 py-4 bg-rose-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-rose-200 dark:shadow-rose-950/40 hover:bg-rose-700 transition-all">{t.confirm}</button>
              </div>
           </div>
        </div>
      )}

      {isMobileSidebarOpen && <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-40 md:hidden" onClick={() => setIsMobileSidebarOpen(false)} />}

      <div className={`fixed inset-y-0 left-0 z-50 transform ${isMobileSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0 transition-transform duration-300 ease-in-out md:flex-shrink-0`}>
        <Sidebar 
          email={currentUser.email}
          companies={state.companies}
          language={state.settings.language}
          onAddTask={addTask} 
          onAddCompany={c => setState(p => p ? ({...p, companies: [...p.companies, c]}) : null)}
          onClearAll={() => { if(confirm("Format Storage?")) setState({...state, tasks: []}); }} 
          onLogout={handleLogout}
          onOpenHistory={() => { setModals(m => ({...m, history: true})); setIsMobileSidebarOpen(false); }}
          onOpenExport={() => { setModals(m => ({...m, export: true})); setIsMobileSidebarOpen(false); }}
          onOpenSettings={() => { setModals(m => ({...m, settings: true})); setIsMobileSidebarOpen(false); }}
          onCloseMobile={() => setIsMobileSidebarOpen(false)}
        />
      </div>

      <main className="flex-1 flex flex-col min-w-0 bg-slate-50 dark:bg-slate-900 relative h-screen overflow-hidden transition-colors duration-500">
        <header className="min-h-[96px] py-4 px-6 md:px-10 bg-white dark:bg-slate-950 border-b border-slate-100 dark:border-slate-800 flex flex-col md:flex-row md:items-center justify-between z-10 shadow-sm gap-4 transition-colors duration-500">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <button onClick={() => setIsMobileSidebarOpen(true)} className="md:hidden w-10 h-10 rounded-xl bg-slate-50 dark:bg-slate-900 text-slate-600 dark:text-slate-400 flex items-center justify-center border border-slate-100 dark:border-slate-800"><i className="fas fa-bars"></i></button>
              <div>
                <h2 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white tracking-tight uppercase">{t.currentTasks}</h2>
                <div className="flex items-center gap-2 mt-0.5">
                  <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                  <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{currentTime.toLocaleDateString(state.settings.language, { weekday: 'long', day: 'numeric', month: 'long' })}</p>
                </div>
              </div>
            </div>
          </div>

          <div className="flex items-center justify-between md:justify-end gap-4 md:gap-8">
            <div className="text-left md:text-right">
              <p className="text-[8px] md:text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t.doing}</p>
              <p className="text-xl md:text-2xl font-black text-rose-500 leading-tight">{activeCount}</p>
            </div>
            <div className="text-left md:text-right">
              <p className="text-[8px] md:text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t.doneToday}</p>
              <p className="text-xl md:text-2xl font-black text-emerald-500 leading-tight">{doneTodayCount}</p>
            </div>
            <div className="hidden md:block text-right border-l border-slate-100 dark:border-slate-800 pl-8">
              <p className="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t.systemTime}</p>
              <p className="text-2xl font-mono font-bold text-slate-800 dark:text-white leading-tight">{currentTime.toLocaleTimeString(state.settings.language, { hour: '2-digit', minute: '2-digit' })}</p>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar">
          {currentViewTasks.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-300 dark:text-slate-700 opacity-50 text-center">
              <div className="w-24 h-24 bg-white dark:bg-slate-800 rounded-full flex items-center justify-center mb-6 shadow-sm border border-slate-100 dark:border-slate-800">
                <i className="fas fa-clipboard-check text-4xl"></i>
              </div>
              <p className="font-black uppercase tracking-widest text-xs">{t.noTasks}</p>
            </div>
          ) : (
            <div className="max-w-4xl mx-auto space-y-4 pb-24">
              {currentViewTasks.map(task => (
                <TaskItem key={task.id} task={task} language={state.settings.language} onStatusChange={updateTaskStatus} onDelete={id => setModals(m => ({...m, delete: id}))} />
              ))}
            </div>
          )}
        </div>

        <div className="absolute bottom-6 right-6 flex items-center gap-2 px-4 py-2 bg-white dark:bg-slate-950 border border-slate-100 dark:border-slate-800 rounded-full shadow-lg text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest transition-all duration-500">
           <i className="fas fa-database text-blue-500"></i> {t.totalStorage}: {state.tasks.filter(t => !t.deletedAt).length}
        </div>
      </main>

      {modals.history && <HistoryModal tasks={state.tasks.filter(t => !t.deletedAt)} language={state.settings.language} onClose={() => setModals(m => ({...m, history: false}))} />}
      {modals.export && <ExportModal tasks={state.tasks.filter(t => !t.deletedAt)} templates={state.reportTemplates || []} onSaveTemplate={tp => setState(s => s ? ({...s, reportTemplates: [...(s.reportTemplates || []), tp]}) : null)} onDeleteTemplate={() => {}} onClose={() => setModals(m => ({...m, export: false}))} />}
      {modals.settings && <SettingsModal language={state.settings.language} theme={state.settings.theme} onUpdate={updateSettings} onClose={() => setModals(m => ({...m, settings: false}))} />}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Language, Theme } from '../types';
import { translations } from '../translations';

interface SettingsModalProps {
  language: Language;
  theme: Theme;
  onUpdate: (lang: Language, theme: Theme) => void;
  onClose: () => void;
}

const SettingsModal: React.FC<SettingsModalProps> = ({ language, theme: initialTheme, onUpdate, onClose }) => {
  const [tempLanguage, setTempLanguage] = useState<Language>(language);
  const [tempTheme, setTempTheme] = useState<Theme>(initialTheme);
  const t = translations[tempLanguage];

  // Hiệu ứng xem trước (Preview) - Tác động trực tiếp vào DOM
  useEffect(() => {
    const root = document.documentElement;
    if (tempTheme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  }, [tempTheme]);

  const handleSave = () => {
    onUpdate(tempLanguage, tempTheme);
    onClose();
  };

  const handleCancel = () => {
    // Khôi phục lại theme ban đầu nếu không lưu
    const root = document.documentElement;
    if (initialTheme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-[2.5rem] shadow-2xl border border-slate-100 dark:border-slate-800 overflow-hidden transform animate-in zoom-in-95 duration-200">
        <header className="p-8 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-white dark:bg-slate-900">
          <h2 className="text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.settings}</h2>
          <button onClick={handleCancel} className="text-slate-300 hover:text-rose-500 transition-colors">
            <i className="fas fa-times text-xl"></i>
          </button>
        </header>

        <div className="p-8 space-y-8 bg-white dark:bg-slate-900">
          {/* Language Selection */}
          <div className="space-y-4">
            <label className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">{t.language}</label>
            <div className="grid grid-cols-2 gap-3">
              {(['vi', 'en', 'zh', 'ru'] as Language[]).map(lang => (
                <button
                  key={lang}
                  onClick={() => setTempLanguage(lang)}
                  className={`py-4 rounded-2xl border-2 font-black text-[10px] uppercase tracking-widest transition-all ${
                    tempLanguage === lang 
                      ? 'border-blue-600 bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400' 
                      : 'border-slate-50 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/50 text-slate-400'
                  }`}
                >
                  {lang === 'vi' ? 'Tiếng Việt' : lang === 'en' ? 'English' : lang === 'zh' ? '中文' : 'Русский'}
                </button>
              ))}
            </div>
          </div>

          {/* Theme Selection */}
          <div className="space-y-4">
            <label className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">{t.theme}</label>
            <div className="flex gap-4">
              <button
                onClick={() => setTempTheme('light')}
                className={`flex-1 py-5 rounded-2xl border-2 font-black text-[10px] uppercase tracking-widest flex flex-col items-center justify-center gap-3 transition-all ${
                  tempTheme === 'light' 
                    ? 'border-amber-400 bg-amber-50 text-amber-700 shadow-lg shadow-amber-100' 
                    : 'border-slate-50 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/50 text-slate-400'
                }`}
              >
                <div className={`w-10 h-10 rounded-full flex items-center justify-center ${tempTheme === 'light' ? 'bg-amber-400 text-white' : 'bg-slate-200 dark:bg-slate-700'}`}>
                  <i className="fas fa-sun text-lg"></i>
                </div>
                {t.light}
              </button>
              <button
                onClick={() => setTempTheme('dark')}
                className={`flex-1 py-5 rounded-2xl border-2 font-black text-[10px] uppercase tracking-widest flex flex-col items-center justify-center gap-3 transition-all ${
                  tempTheme === 'dark' 
                    ? 'border-indigo-600 bg-indigo-900/40 text-indigo-400 shadow-lg shadow-indigo-950/50' 
                    : 'border-slate-50 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/50 text-slate-400'
                }`}
              >
                <div className={`w-10 h-10 rounded-full flex items-center justify-center ${tempTheme === 'dark' ? 'bg-indigo-600 text-white' : 'bg-slate-200 dark:bg-slate-700'}`}>
                  <i className="fas fa-moon text-lg"></i>
                </div>
                {t.dark}
              </button>
            </div>
          </div>
        </div>

        <footer className="p-8 bg-slate-50 dark:bg-slate-950/50 flex gap-4">
           <button 
             onClick={handleCancel} 
             className="flex-1 py-4 bg-white dark:bg-slate-800 text-slate-500 dark:text-slate-400 border border-slate-200 dark:border-slate-700 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-100 dark:hover:bg-slate-700 transition-all"
           >
             {t.cancel}
           </button>
           <button 
             onClick={handleSave} 
             className="flex-1 py-4 bg-slate-900 dark:bg-blue-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:opacity-90 transition-all active:scale-95"
           >
             {t.save}
           </button>
        </footer>
      </div>
    </div>
  );
};

export default SettingsModal;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import TaskItem from './components/TaskItem';
import Login from './components/Login';
import Setup from './components/Setup';
import HistoryModal from './components/HistoryModal';
import ExportModal from './components/ExportModal';
import SettingsModal from './components/SettingsModal';
import { Task, TaskStatus, AppState, ReportTemplate, Language, Theme } from './types';
import { loadStateSecure, saveStateSecure } from './services/storageService';
import { translations } from './translations';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<{email: string, pass: string} | null>(null);
  const [state, setState] = useState<AppState | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [loading, setLoading] = useState(false);
  const [modals, setModals] = useState({
    history: false,
    export: false,
    settings: false,
    delete: null as string | null
  });
  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);

  const currentLanguage = state?.settings?.language || 'vi';
  const t = translations[currentLanguage];

  // Áp dụng Theme class lên document root khi state thay đổi
  useEffect(() => {
    const root = document.documentElement;
    if (state?.settings?.theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  }, [state?.settings?.theme]);

  // Request notification permission
  useEffect(() => {
    if ("Notification" in window && Notification.permission === "default") {
      Notification.requestPermission();
    }
  }, []);

  // Hệ thống thông báo thông minh
  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now);

      const hours = now.getHours();
      const mins = now.getMinutes();
      const secs = now.getSeconds();

      // 1. Nhắc nhở 8h sáng và 13h chiều
      if (secs === 0 && mins === 0 && (hours === 8 || hours === 13)) {
        const unfinished = state?.tasks.filter(tk => !tk.deletedAt && tk.status !== TaskStatus.DONE).length || 0;
        if (unfinished > 0 && Notification.permission === "granted") {
          new Notification(t.appName, { body: t.unfinishedNotify(unfinished) });
        }
      }

      // 2. Nhắc nhở 3 tiếng cho việc "Đang làm"
      if (secs === 0 && state) {
        state.tasks.forEach(task => {
          if (!task.deletedAt && task.status === TaskStatus.IN_PROGRESS) {
            const lastUpdate = new Date(task.updatedAt);
            const diffHours = (now.getTime() - lastUpdate.getTime()) / (1000 * 60 * 60);
            if (diffHours >= 3 && Math.floor(diffHours) % 3 === 0 && mins === 0) {
              if (Notification.permission === "granted") {
                new Notification(t.appName, { body: `${task.content}: ${t.progressReminder}` });
              }
            }
          }
        });
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [state, t]);

  const handleLogin = async (email: string, pass: string) => {
    setLoading(true);
    try {
      const loaded = await loadStateSecure(email, pass);
      if (!loaded.settings) {
        loaded.settings = { language: 'vi', theme: 'light' };
      }
      setCurrentUser({ email, pass });
      setState(loaded);
    } catch (e: any) { alert(e.message); }
    finally { setLoading(false); }
  };

  const handleSetupComplete = (companies: string[]) => {
    setState(prev => prev ? ({ ...prev, companies }) : null);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setState(null);
  };

  useEffect(() => {
    if (state && state.tasks) {
      const now = new Date();
      const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
      const cleanedTasks = state.tasks.filter(t => !t.deletedAt || new Date(t.deletedAt) > thirtyDaysAgo);
      if (cleanedTasks.length !== state.tasks.length) {
        setState(prev => prev ? ({ ...prev, tasks: cleanedTasks }) : null);
      }
    }
  }, [state?.lastLaunchDate]);

  useEffect(() => {
    if (currentUser && state) saveStateSecure(currentUser.email, currentUser.pass, state);
  }, [state, currentUser]);

  const addTask = useCallback((content: string, company: string, isPriority: boolean) => {
    if (!state) return;
    const now = new Date().toISOString();
    const newTask: Task = {
      id: crypto.randomUUID(),
      content,
      company,
      createdAt: now,
      updatedAt: now,
      status: TaskStatus.NOT_STARTED,
      isPriority
    };
    setState(prev => prev ? ({ ...prev, tasks: [newTask, ...prev.tasks] }) : null);
    setIsMobileSidebarOpen(false);
  }, [state]);

  const updateTaskStatus = useCallback((id: string, status: TaskStatus) => {
    setState(prev => prev ? ({ 
      ...prev, 
      tasks: prev.tasks.map(t => t.id === id ? { ...t, status, updatedAt: new Date().toISOString() } : t) 
    }) : null);
  }, []);

  const deleteTask = useCallback((id: string) => {
    setState(prev => prev ? ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === id ? { ...t, deletedAt: new Date().toISOString() } : t)
    }) : null);
    setModals(m => ({ ...m, delete: null }));
  }, []);

  const updateSettings = useCallback((lang: Language, theme: Theme) => {
    setState(prev => prev ? ({ ...prev, settings: { language: lang, theme } }) : null);
  }, []);

  const currentViewTasks = useMemo(() => {
    if (!state) return [];
    const today = new Date().toISOString().split('T')[0];
    return state.tasks.filter(t => !t.deletedAt).filter(t => {
      if (t.status !== TaskStatus.DONE) return true;
      return t.createdAt.startsWith(today);
    }).sort((a, b) => {
      const getRank = (task: Task) => {
        if (task.status === TaskStatus.IN_PROGRESS) return 0;
        if (task.isPriority) return 1;
        if (task.status === TaskStatus.NOT_STARTED) return 2;
        return 3;
      };
      return getRank(a) - getRank(b) || new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
    });
  }, [state]);

  if (loading) return (
    <div className="h-screen bg-white dark:bg-slate-950 flex flex-col items-center justify-center text-blue-600 p-6 text-center">
      <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
      <p className="font-black uppercase tracking-[0.2em] text-[10px] dark:text-blue-400">ZenTask Loading...</p>
    </div>
  );

  if (!currentUser || !state) return <Login onLogin={handleLogin} />;
  if (state.companies.length === 0) return <Setup onComplete={handleSetupComplete} onLogout={handleLogout} />;

  const activeCount = state.tasks.filter(t => !t.deletedAt && t.status !== TaskStatus.DONE).length;
  const doneTodayCount = state.tasks.filter(t => !t.deletedAt && t.status === TaskStatus.DONE && t.createdAt.startsWith(new Date().toISOString().split('T')[0])).length;

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-white dark:bg-slate-950 theme-transition">
      {/* Delete Confirmation */}
      {modals.delete && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-200">
           <div className="bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] shadow-2xl max-w-sm w-full text-center border border-slate-100 dark:border-slate-800 animate-in zoom-in-95">
              <div className="w-16 h-16 bg-rose-50 dark:bg-rose-900/30 text-rose-500 rounded-full flex items-center justify-center mx-auto mb-6">
                 <i className="fas fa-trash-alt text-2xl"></i>
              </div>
              <h3 className="text-xl font-black text-slate-800 dark:text-white uppercase mb-2">{t.confirmDelete}</h3>
              <p className="text-sm text-slate-500 dark:text-slate-400 mb-8">{t.confirmDeleteDesc}</p>
              <div className="flex gap-3">
                 <button onClick={() => setModals(m => ({ ...m, delete: null }))} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-200 dark:hover:bg-slate-700 transition-all">{t.cancel}</button>
                 <button onClick={() => deleteTask(modals.delete!)} className="flex-1 py-4 bg-rose-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-rose-200 dark:shadow-rose-950/40 hover:bg-rose-700 transition-all">{t.confirm}</button>
              </div>
           </div>
        </div>
      )}

      {isMobileSidebarOpen && <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-40 md:hidden" onClick={() => setIsMobileSidebarOpen(false)} />}

      <div className={`fixed inset-y-0 left-0 z-50 transform ${isMobileSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0 transition-transform duration-300 ease-in-out md:flex-shrink-0`}>
        <Sidebar 
          email={currentUser.email}
          companies={state.companies}
          language={state.settings.language}
          onAddTask={addTask} 
          onAddCompany={c => setState(p => p ? ({...p, companies: [...p.companies, c]}) : null)}
          onClearAll={() => { if(confirm("Format Storage?")) setState({...state, tasks: []}); }} 
          onLogout={handleLogout}
          onOpenHistory={() => { setModals(m => ({...m, history: true})); setIsMobileSidebarOpen(false); }}
          onOpenExport={() => { setModals(m => ({...m, export: true})); setIsMobileSidebarOpen(false); }}
          onOpenSettings={() => { setModals(m => ({...m, settings: true})); setIsMobileSidebarOpen(false); }}
          onCloseMobile={() => setIsMobileSidebarOpen(false)}
        />
      </div>

      <main className="flex-1 flex flex-col min-w-0 bg-slate-50 dark:bg-slate-950 relative h-screen overflow-hidden theme-transition">
        <header className="min-h-[96px] py-4 px-6 md:px-10 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex flex-col md:flex-row md:items-center justify-between z-10 shadow-sm gap-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <button onClick={() => setIsMobileSidebarOpen(true)} className="md:hidden w-10 h-10 rounded-xl bg-slate-50 dark:bg-slate-800 text-slate-600 dark:text-slate-400 flex items-center justify-center border border-slate-100 dark:border-slate-700"><i className="fas fa-bars"></i></button>
              <div>
                <h2 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white tracking-tight uppercase">{t.currentTasks}</h2>
                <div className="flex items-center gap-2 mt-0.5">
                  <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                  <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{currentTime.toLocaleDateString(state.settings.language, { weekday: 'long', day: 'numeric', month: 'long' })}</p>
                </div>
              </div>
            </div>
          </div>

          <div className="flex items-center justify-between md:justify-end gap-4 md:gap-8">
            <div className="text-left md:text-right">
              <p className="text-[8px] md:text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t.doing}</p>
              <p className="text-xl md:text-2xl font-black text-rose-500 leading-tight">{activeCount}</p>
            </div>
            <div className="text-left md:text-right">
              <p className="text-[8px] md:text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t.doneToday}</p>
              <p className="text-xl md:text-2xl font-black text-emerald-500 leading-tight">{doneTodayCount}</p>
            </div>
            <div className="hidden md:block text-right border-l border-slate-100 dark:border-slate-800 pl-8">
              <p className="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t.systemTime}</p>
              <p className="text-2xl font-mono font-bold text-slate-800 dark:text-white leading-tight">{currentTime.toLocaleTimeString(state.settings.language, { hour: '2-digit', minute: '2-digit' })}</p>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar">
          {currentViewTasks.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-300 dark:text-slate-700 opacity-50 text-center">
              <div className="w-24 h-24 bg-white dark:bg-slate-800 rounded-full flex items-center justify-center mb-6 shadow-sm border border-slate-100 dark:border-slate-800">
                <i className="fas fa-clipboard-check text-4xl"></i>
              </div>
              <p className="font-black uppercase tracking-widest text-xs">{t.noTasks}</p>
            </div>
          ) : (
            <div className="max-w-4xl mx-auto space-y-4 pb-24">
              {currentViewTasks.map(task => (
                <TaskItem key={task.id} task={task} language={state.settings.language} onStatusChange={updateTaskStatus} onDelete={id => setModals(m => ({...m, delete: id}))} />
              ))}
            </div>
          )}
        </div>

        <div className="absolute bottom-6 right-6 flex items-center gap-2 px-4 py-2 bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-full shadow-lg text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest transition-all">
           <i className="fas fa-database text-blue-500"></i> {t.totalStorage}: {state.tasks.filter(t => !t.deletedAt).length}
        </div>
      </main>

      {modals.history && <HistoryModal tasks={state.tasks.filter(t => !t.deletedAt)} language={state.settings.language} onClose={() => setModals(m => ({...m, history: false}))} />}
      {modals.export && <ExportModal tasks={state.tasks.filter(t => !t.deletedAt)} templates={state.reportTemplates || []} onSaveTemplate={tp => setState(s => s ? ({...s, reportTemplates: [...(s.reportTemplates || []), tp]}) : null)} onDeleteTemplate={() => {}} onClose={() => setModals(m => ({...m, export: false}))} />}
      {modals.settings && <SettingsModal language={state.settings.language} theme={state.settings.theme} onUpdate={updateSettings} onClose={() => setModals(m => ({...m, settings: false}))} />}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Language } from '../types';
import { translations } from '../translations';

interface ManageCompaniesModalProps {
  companies: string[];
  language: Language;
  onRename: (oldName: string, newName: string) => void;
  onDelete: (name: string) => void;
  onClose: () => void;
}

const ManageCompaniesModal: React.FC<ManageCompaniesModalProps> = ({ companies, language, onRename, onDelete, onClose }) => {
  const t = translations[language];
  const [editingName, setEditingName] = useState<string | null>(null);
  const [newName, setNewName] = useState('');

  const handleStartEdit = (name: string) => {
    setEditingName(name);
    setNewName(name);
  };

  const handleSave = (oldName: string) => {
    const trimmed = newName.trim();
    if (!trimmed || trimmed === oldName) {
      setEditingName(null);
      return;
    }
    if (companies.includes(trimmed)) {
      alert("Tên công ty đã tồn tại!");
      return;
    }
    if (confirm(t.renameConfirm)) {
      onRename(oldName, trimmed);
      setEditingName(null);
    }
  };

  return (
    <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-200">
      <div className="bg-white dark:bg-slate-900 w-full max-w-lg rounded-[2.5rem] shadow-2xl border border-slate-100 dark:border-slate-800 overflow-hidden transform animate-in zoom-in-95 duration-200">
        <header className="p-8 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-white dark:bg-slate-900">
          <h2 className="text-xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.manageCompanies}</h2>
          <button onClick={onClose} className="text-slate-300 hover:text-rose-500 transition-colors">
            <i className="fas fa-times text-xl"></i>
          </button>
        </header>

        <div className="p-6 max-h-[60vh] overflow-y-auto custom-scrollbar bg-white dark:bg-slate-900 space-y-3">
          {companies.map(company => (
            <div key={company} className="flex items-center gap-3 p-4 bg-slate-50 dark:bg-slate-800/50 rounded-2xl border border-slate-100 dark:border-slate-800 transition-all">
              {editingName === company ? (
                <div className="flex-1 flex gap-2">
                  <input
                    autoFocus
                    value={newName}
                    onChange={(e) => setNewName(e.target.value)}
                    className="flex-1 px-4 py-2 bg-white dark:bg-slate-900 border border-blue-200 dark:border-slate-700 rounded-xl font-bold text-slate-700 dark:text-white text-sm outline-none ring-2 ring-blue-500/20"
                  />
                  <button onClick={() => handleSave(company)} className="px-4 bg-blue-600 text-white rounded-xl font-black text-[10px] uppercase">{t.save}</button>
                  <button onClick={() => setEditingName(null)} className="px-4 bg-slate-200 dark:bg-slate-700 text-slate-500 dark:text-slate-400 rounded-xl font-black text-[10px] uppercase">{t.cancel}</button>
                </div>
              ) : (
                <>
                  <div className="flex-1">
                    <p className="font-black text-slate-700 dark:text-slate-200 text-sm uppercase tracking-wide">{company}</p>
                  </div>
                  <div className="flex gap-1">
                    <button 
                      onClick={() => handleStartEdit(company)} 
                      className="w-10 h-10 flex items-center justify-center rounded-xl bg-white dark:bg-slate-800 text-blue-500 hover:bg-blue-50 dark:hover:bg-blue-900/30 transition-all border border-slate-100 dark:border-slate-700"
                      title={t.edit}
                    >
                      <i className="fas fa-pencil-alt text-xs"></i>
                    </button>
                    <button 
                      onClick={() => { if(confirm(t.confirmDelete)) onDelete(company); }} 
                      className="w-10 h-10 flex items-center justify-center rounded-xl bg-white dark:bg-slate-800 text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/30 transition-all border border-slate-100 dark:border-slate-700"
                      title={t.delete}
                    >
                      <i className="fas fa-trash-alt text-xs"></i>
                    </button>
                  </div>
                </>
              )}
            </div>
          ))}
        </div>

        <footer className="p-6 bg-slate-50 dark:bg-slate-950/50 flex justify-end">
          <button onClick={onClose} className="px-8 py-4 bg-slate-900 dark:bg-blue-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg active:scale-95 transition-all">
            {t.doneToday}
          </button>
        </footer>
      </div>
    </div>
  );
};

export default ManageCompaniesModal;

import React, { useState } from 'react';
import { Language } from '../types';
import { translations } from '../translations';

interface SidebarProps {
  email: string;
  companies: string[];
  language: Language;
  onAddTask: (content: string, company: string, isPriority: boolean) => void;
  onAddCompany: (company: string) => void;
  onOpenManageCompanies: () => void; // Thêm prop mới
  onClearAll: () => void;
  onLogout: () => void;
  onOpenHistory: () => void;
  onOpenExport: () => void;
  onOpenSettings: () => void;
  onCloseMobile?: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  email, companies, language, onAddTask, onAddCompany, onOpenManageCompanies, onClearAll, onLogout, onOpenHistory, onOpenExport, onOpenSettings, onCloseMobile
}) => {
  const [content, setContent] = useState('');
  const [selectedCompany, setSelectedCompany] = useState(companies[0] || '');
  const [isPriority, setIsPriority] = useState(false);
  const [newCompanyName, setNewCompanyName] = useState('');
  const [isAddingCompany, setIsAddingCompany] = useState(false);

  const t = translations[language];

  React.useEffect(() => {
    if (!selectedCompany && companies.length > 0) setSelectedCompany(companies[0]);
    // Nếu công ty đang chọn bị xóa hoặc đổi tên, cập nhật lại selectedCompany
    if (selectedCompany && !companies.includes(selectedCompany)) {
      setSelectedCompany(companies[0] || '');
    }
  }, [companies]);

  const handleSubmitTask = (e: React.FormEvent) => {
    e.preventDefault();
    if (!content.trim() || !selectedCompany) return;
    onAddTask(content, selectedCompany, isPriority);
    setContent('');
    setIsPriority(false);
  };

  const handleAddCompany = (e: React.FormEvent) => {
    e.preventDefault();
    const trimmed = newCompanyName.trim();
    if (!trimmed || companies.includes(trimmed)) return;
    onAddCompany(trimmed);
    setSelectedCompany(trimmed);
    setNewCompanyName('');
    setIsAddingCompany(false);
  };

  return (
    <div className="w-[300px] sm:w-[350px] md:w-[400px] lg:w-[450px] bg-white dark:bg-slate-950 h-screen md:h-full flex flex-col p-6 sm:p-10 flex-shrink-0 border-r border-slate-100 dark:border-slate-800 shadow-2xl md:shadow-none overflow-y-auto custom-scrollbar transition-colors duration-300">
      <div className="mb-8 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg"><i className="fas fa-layer-group"></i></div>
          <h1 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white tracking-tighter leading-tight">{t.appName}</h1>
        </div>
        <div className="flex gap-2">
          <button onClick={onOpenSettings} className="w-10 h-10 rounded-xl bg-slate-50 dark:bg-slate-900 text-slate-400 flex items-center justify-center border border-slate-100 dark:border-slate-800 transition-all hover:bg-slate-100 dark:hover:bg-slate-800"><i className="fas fa-cog"></i></button>
          <button onClick={onLogout} className="w-10 h-10 rounded-xl bg-slate-50 dark:bg-slate-900 hover:bg-red-50 text-slate-400 hover:text-red-500 flex items-center justify-center border border-slate-100 dark:border-slate-800 transition-all"><i className="fas fa-sign-out-alt"></i></button>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-3 mb-8">
        <button onClick={onOpenHistory} className="p-4 rounded-2xl bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 border border-indigo-100 dark:border-indigo-800 flex flex-col items-center gap-2 group transition-all">
          <i className="fas fa-history group-hover:scale-110"></i>
          <span className="text-[9px] font-black uppercase tracking-widest">{t.history}</span>
        </button>
        <button onClick={onOpenExport} className="p-4 rounded-2xl bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400 border border-emerald-100 dark:border-emerald-800 flex flex-col items-center gap-2 group transition-all">
          <i className="fas fa-file-export group-hover:scale-110"></i>
          <span className="text-[9px] font-black uppercase tracking-widest">{t.report}</span>
        </button>
      </div>

      <div className="flex-1 space-y-6">
        <form onSubmit={handleSubmitTask} className="space-y-6">
          <div className="space-y-2">
            <div className="flex items-center justify-between ml-1">
              <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">{t.company}</label>
              <div className="flex gap-3">
                <button type="button" onClick={onOpenManageCompanies} className="text-[9px] font-black text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 uppercase tracking-widest">
                  {t.manage}
                </button>
                <button type="button" onClick={() => setIsAddingCompany(!isAddingCompany)} className="text-[9px] font-black text-blue-600 uppercase tracking-widest">
                  {isAddingCompany ? t.cancel : t.newCompany}
                </button>
              </div>
            </div>
            {isAddingCompany ? (
              <div className="flex gap-2">
                <input autoFocus value={newCompanyName} onChange={(e) => setNewCompanyName(e.target.value)} placeholder="..." className="flex-1 p-3 bg-blue-50 dark:bg-slate-900 border border-blue-200 dark:border-slate-800 rounded-xl font-bold text-slate-700 dark:text-white text-xs" />
                <button type="button" onClick={handleAddCompany} className="px-4 bg-blue-600 text-white rounded-xl font-black text-[10px] uppercase">{t.save}</button>
              </div>
            ) : (
              <div className="relative">
                <select value={selectedCompany} onChange={(e) => setSelectedCompany(e.target.value)} className="w-full p-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl outline-none font-bold text-slate-700 dark:text-white appearance-none text-xs focus:ring-2 focus:ring-blue-500/20 transition-all">
                  {companies.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
                <i className="fas fa-chevron-down absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none text-[10px]"></i>
              </div>
            )}
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-1">{t.taskContent}</label>
            <textarea value={content} onChange={(e) => setContent(e.target.value)} placeholder={t.placeholderContent} className="w-full p-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl outline-none h-32 resize-none text-slate-800 dark:text-white font-medium text-xs focus:ring-2 focus:ring-blue-500/20 transition-all" />
          </div>

          <div onClick={() => setIsPriority(!isPriority)} className={`flex items-center gap-3 p-3 rounded-xl border transition-all cursor-pointer ${isPriority ? 'bg-rose-50 dark:bg-rose-950/30 border-rose-200 dark:border-rose-900 shadow-sm' : 'bg-slate-50 dark:bg-slate-900 border-slate-100 dark:border-slate-800'}`}>
            <div className={`w-5 h-5 rounded-lg border-2 flex items-center justify-center transition-all ${isPriority ? 'bg-rose-500 border-rose-500 text-white' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700'}`}>
              {isPriority && <i className="fas fa-check text-[8px]"></i>}
            </div>
            <span className={`text-[10px] font-black uppercase tracking-widest ${isPriority ? 'text-rose-600' : 'text-slate-600 dark:text-slate-400'}`}>{t.isPriority}</span>
          </div>

          <button type="submit" className="w-full bg-slate-900 dark:bg-blue-600 hover:opacity-90 text-white font-black py-4 rounded-xl shadow-xl transition-all flex items-center justify-center gap-3 text-xs tracking-widest uppercase active:scale-95">
            {t.update}
          </button>
        </form>
      </div>

      <div className="mt-8 pt-6 border-t border-slate-100 dark:border-slate-800 flex items-center justify-between flex-shrink-0">
        <p className="text-[8px] text-slate-300 font-bold uppercase tracking-[0.2em]">Zen v5.2</p>
        <button onClick={onClearAll} className="text-slate-300 hover:text-red-500 transition-colors p-2"><i className="far fa-trash-alt"></i></button>
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import TaskItem from './components/TaskItem';
import Login from './components/Login';
import Setup from './components/Setup';
import HistoryModal from './components/HistoryModal';
import ExportModal from './components/ExportModal';
import SettingsModal from './components/SettingsModal';
import ManageCompaniesModal from './components/ManageCompaniesModal';
import { Task, TaskStatus, AppState, ReportTemplate, Language, Theme } from './types';
import { loadStateSecure, saveStateSecure } from './services/storageService';
import { translations } from './translations';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<{email: string, pass: string} | null>(null);
  const [state, setState] = useState<AppState | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [loading, setLoading] = useState(false);
  const [modals, setModals] = useState({
    history: false,
    export: false,
    settings: false,
    manageCompanies: false,
    delete: null as string | null
  });
  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);

  const currentLanguage = state?.settings?.language || 'vi';
  const t = translations[currentLanguage];

  // Áp dụng Theme class lên document root khi state thay đổi
  useEffect(() => {
    const root = document.documentElement;
    if (state?.settings?.theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  }, [state?.settings?.theme]);

  // Request notification permission
  useEffect(() => {
    if ("Notification" in window && Notification.permission === "default") {
      Notification.requestPermission();
    }
  }, []);

  // Hệ thống thông báo thông minh
  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now);

      const hours = now.getHours();
      const mins = now.getMinutes();
      const secs = now.getSeconds();

      if (secs === 0 && mins === 0 && (hours === 8 || hours === 13)) {
        const unfinished = state?.tasks.filter(tk => !tk.deletedAt && tk.status !== TaskStatus.DONE).length || 0;
        if (unfinished > 0 && Notification.permission === "granted") {
          new Notification(t.appName, { body: t.unfinishedNotify(unfinished) });
        }
      }

      if (secs === 0 && state) {
        state.tasks.forEach(task => {
          if (!task.deletedAt && task.status === TaskStatus.IN_PROGRESS) {
            const lastUpdate = new Date(task.updatedAt);
            const diffHours = (now.getTime() - lastUpdate.getTime()) / (1000 * 60 * 60);
            if (diffHours >= 3 && Math.floor(diffHours) % 3 === 0 && mins === 0) {
              if (Notification.permission === "granted") {
                new Notification(t.appName, { body: `${task.content}: ${t.progressReminder}` });
              }
            }
          }
        });
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [state, t]);

  const handleLogin = async (email: string, pass: string) => {
    setLoading(true);
    try {
      const loaded = await loadStateSecure(email, pass);
      if (!loaded.settings) {
        loaded.settings = { language: 'vi', theme: 'light' };
      }
      setCurrentUser({ email, pass });
      setState(loaded);
    } catch (e: any) { alert(e.message); }
    finally { setLoading(false); }
  };

  const handleSetupComplete = (companies: string[]) => {
    setState(prev => prev ? ({ ...prev, companies }) : null);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setState(null);
  };

  useEffect(() => {
    if (state && state.tasks) {
      const now = new Date();
      const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
      const cleanedTasks = state.tasks.filter(t => !t.deletedAt || new Date(t.deletedAt) > thirtyDaysAgo);
      if (cleanedTasks.length !== state.tasks.length) {
        setState(prev => prev ? ({ ...prev, tasks: cleanedTasks }) : null);
      }
    }
  }, [state?.lastLaunchDate]);

  useEffect(() => {
    if (currentUser && state) saveStateSecure(currentUser.email, currentUser.pass, state);
  }, [state, currentUser]);

  const addTask = useCallback((content: string, company: string, isPriority: boolean) => {
    if (!state) return;
    const now = new Date().toISOString();
    const newTask: Task = {
      id: crypto.randomUUID(),
      content,
      company,
      createdAt: now,
      updatedAt: now,
      status: TaskStatus.NOT_STARTED,
      isPriority
    };
    setState(prev => prev ? ({ ...prev, tasks: [newTask, ...prev.tasks] }) : null);
    setIsMobileSidebarOpen(false);
  }, [state]);

  const updateTaskStatus = useCallback((id: string, status: TaskStatus) => {
    setState(prev => prev ? ({ 
      ...prev, 
      tasks: prev.tasks.map(t => t.id === id ? { ...t, status, updatedAt: new Date().toISOString() } : t) 
    }) : null);
  }, []);

  const deleteTask = useCallback((id: string) => {
    setState(prev => prev ? ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === id ? { ...t, deletedAt: new Date().toISOString() } : t)
    }) : null);
    setModals(m => ({ ...m, delete: null }));
  }, []);

  const updateSettings = useCallback((lang: Language, theme: Theme) => {
    setState(prev => prev ? ({ ...prev, settings: { language: lang, theme } }) : null);
  }, []);

  const renameCompany = useCallback((oldName: string, newName: string) => {
    setState(prev => {
      if (!prev) return null;
      return {
        ...prev,
        companies: prev.companies.map(c => c === oldName ? newName : c),
        tasks: prev.tasks.map(t => t.company === oldName ? { ...t, company: newName } : t)
      };
    });
  }, []);

  const deleteCompany = useCallback((name: string) => {
    setState(prev => {
      if (!prev) return null;
      return {
        ...prev,
        companies: prev.companies.filter(c => c !== name),
        // Chuyển tasks của công ty bị xóa sang "Khác" hoặc giữ nguyên tùy ý, ở đây tôi giữ nguyên công ty trong task để không mất data nhưng xóa khỏi list gợi ý
      };
    });
  }, []);

  const currentViewTasks = useMemo(() => {
    if (!state) return [];
    const today = new Date().toISOString().split('T')[0];
    return state.tasks.filter(t => !t.deletedAt).filter(t => {
      if (t.status !== TaskStatus.DONE) return true;
      return t.createdAt.startsWith(today);
    }).sort((a, b) => {
      const getRank = (task: Task) => {
        if (task.status === TaskStatus.IN_PROGRESS) return 0;
        if (task.isPriority) return 1;
        if (task.status === TaskStatus.NOT_STARTED) return 2;
        return 3;
      };
      return getRank(a) - getRank(b) || new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
    });
  }, [state]);

  if (loading) return (
    <div className="h-screen bg-white dark:bg-slate-950 flex flex-col items-center justify-center text-blue-600 p-6 text-center">
      <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
      <p className="font-black uppercase tracking-[0.2em] text-[10px] dark:text-blue-400">ZenTask Loading...</p>
    </div>
  );

  if (!currentUser || !state) return <Login onLogin={handleLogin} />;
  if (state.companies.length === 0) return <Setup onComplete={handleSetupComplete} onLogout={handleLogout} />;

  const activeCount = state.tasks.filter(t => !t.deletedAt && t.status !== TaskStatus.DONE).length;
  const doneTodayCount = state.tasks.filter(t => !t.deletedAt && t.status === TaskStatus.DONE && t.createdAt.startsWith(new Date().toISOString().split('T')[0])).length;

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-white dark:bg-slate-950 theme-transition">
      {/* Delete Confirmation */}
      {modals.delete && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-200">
           <div className="bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] shadow-2xl max-sm w-full text-center border border-slate-100 dark:border-slate-800 animate-in zoom-in-95">
              <div className="w-16 h-16 bg-rose-50 dark:bg-rose-900/30 text-rose-500 rounded-full flex items-center justify-center mx-auto mb-6">
                 <i className="fas fa-trash-alt text-2xl"></i>
              </div>
              <h3 className="text-xl font-black text-slate-800 dark:text-white uppercase mb-2">{t.confirmDelete}</h3>
              <p className="text-sm text-slate-500 dark:text-slate-400 mb-8">{t.confirmDeleteDesc}</p>
              <div className="flex gap-3">
                 <button onClick={() => setModals(m => ({ ...m, delete: null }))} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-200 dark:hover:bg-slate-700 transition-all">{t.cancel}</button>
                 <button onClick={() => deleteTask(modals.delete!)} className="flex-1 py-4 bg-rose-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-rose-200 dark:shadow-rose-950/40 hover:bg-rose-700 transition-all">{t.confirm}</button>
              </div>
           </div>
        </div>
      )}

      {isMobileSidebarOpen && <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-40 md:hidden" onClick={() => setIsMobileSidebarOpen(false)} />}

      <div className={`fixed inset-y-0 left-0 z-50 transform ${isMobileSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0 transition-transform duration-300 ease-in-out md:flex-shrink-0`}>
        <Sidebar 
          email={currentUser.email}
          companies={state.companies}
          language={state.settings.language}
          onAddTask={addTask} 
          onAddCompany={c => setState(p => p ? ({...p, companies: [...p.companies, c]}) : null)}
          onOpenManageCompanies={() => { setModals(m => ({...m, manageCompanies: true})); setIsMobileSidebarOpen(false); }}
          onClearAll={() => { if(confirm("Format Storage?")) setState({...state, tasks: []}); }} 
          onLogout={handleLogout}
          onOpenHistory={() => { setModals(m => ({...m, history: true})); setIsMobileSidebarOpen(false); }}
          onOpenExport={() => { setModals(m => ({...m, export: true})); setIsMobileSidebarOpen(false); }}
          onOpenSettings={() => { setModals(m => ({...m, settings: true})); setIsMobileSidebarOpen(false); }}
          onCloseMobile={() => setIsMobileSidebarOpen(false)}
        />
      </div>

      <main className="flex-1 flex flex-col min-w-0 bg-slate-50 dark:bg-slate-950 relative h-screen overflow-hidden theme-transition">
        <header className="min-h-[96px] py-4 px-6 md:px-10 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex flex-col md:flex-row md:items-center justify-between z-10 shadow-sm gap-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <button onClick={() => setIsMobileSidebarOpen(true)} className="md:hidden w-10 h-10 rounded-xl bg-slate-50 dark:bg-slate-800 text-slate-600 dark:text-slate-400 flex items-center justify-center border border-slate-100 dark:border-slate-700"><i className="fas fa-bars"></i></button>
              <div>
                <h2 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white tracking-tight uppercase">{t.currentTasks}</h2>
                <div className="flex items-center gap-2 mt-0.5">
                  <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                  <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{currentTime.toLocaleDateString(state.settings.language, { weekday: 'long', day: 'numeric', month: 'long' })}</p>
                </div>
              </div>
            </div>
          </div>

          <div className="flex items-center justify-between md:justify-end gap-4 md:gap-8">
            <div className="text-left md:text-right">
              <p className="text-[8px] md:text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t.doing}</p>
              <p className="text-xl md:text-2xl font-black text-rose-500 leading-tight">{activeCount}</p>
            </div>
            <div className="text-left md:text-right">
              <p className="text-[8px] md:text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t.doneToday}</p>
              <p className="text-xl md:text-2xl font-black text-emerald-500 leading-tight">{doneTodayCount}</p>
            </div>
            <div className="hidden md:block text-right border-l border-slate-100 dark:border-slate-800 pl-8">
              <p className="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t.systemTime}</p>
              <p className="text-2xl font-mono font-bold text-slate-800 dark:text-white leading-tight">{currentTime.toLocaleTimeString(state.settings.language, { hour: '2-digit', minute: '2-digit' })}</p>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar">
          {currentViewTasks.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-300 dark:text-slate-700 opacity-50 text-center">
              <div className="w-24 h-24 bg-white dark:bg-slate-800 rounded-full flex items-center justify-center mb-6 shadow-sm border border-slate-100 dark:border-slate-800">
                <i className="fas fa-clipboard-check text-4xl"></i>
              </div>
              <p className="font-black uppercase tracking-widest text-xs">{t.noTasks}</p>
            </div>
          ) : (
            <div className="max-w-4xl mx-auto space-y-4 pb-24">
              {currentViewTasks.map(task => (
                <TaskItem key={task.id} task={task} language={state.settings.language} onStatusChange={updateTaskStatus} onDelete={id => setModals(m => ({...m, delete: id}))} />
              ))}
            </div>
          )}
        </div>

        <div className="absolute bottom-6 right-6 flex items-center gap-2 px-4 py-2 bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-full shadow-lg text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest transition-all">
           <i className="fas fa-database text-blue-500"></i> {t.totalStorage}: {state.tasks.filter(t => !t.deletedAt).length}
        </div>
      </main>

      {modals.history && <HistoryModal tasks={state.tasks.filter(t => !t.deletedAt)} language={state.settings.language} onClose={() => setModals(m => ({...m, history: false}))} />}
      {modals.export && <ExportModal tasks={state.tasks.filter(t => !t.deletedAt)} templates={state.reportTemplates || []} onSaveTemplate={tp => setState(s => s ? ({...s, reportTemplates: [...(s.reportTemplates || []), tp]}) : null)} onDeleteTemplate={() => {}} onClose={() => setModals(m => ({...m, export: false}))} />}
      {modals.settings && <SettingsModal language={state.settings.language} theme={state.settings.theme} onUpdate={updateSettings} onClose={() => setModals(m => ({...m, settings: false}))} />}
      {modals.manageCompanies && <ManageCompaniesModal companies={state.companies} language={state.settings.language} onRename={renameCompany} onDelete={deleteCompany} onClose={() => setModals(m => ({...m, manageCompanies: false}))} />}
    </div>
  );
};

export default App;

export enum TaskStatus {
  NOT_STARTED = 'NOT_STARTED',
  IN_PROGRESS = 'IN_PROGRESS',
  DONE = 'DONE'
}

export type UserRole = 'ADMIN' | 'DEPT_HEAD' | 'MANAGER' | 'EMPLOYEE';
export type Language = 'vi' | 'en' | 'zh' | 'ru';
export type Theme = 'light' | 'dark';
export type ReportLayout = 'FLAT' | 'GROUPED_BY_COMPANY';

export interface User {
  id: string;
  email: string;
  password?: string;
  fullName: string;
  role: UserRole;
  reportsTo?: string; // ID của quản lý cấp trên
  department?: string;
}

export interface Task {
  id: string;
  userId: string; // ID của nhân viên sở hữu công việc
  content: string;
  company: string;
  createdAt: string; 
  updatedAt: string;
  status: TaskStatus;
  isPriority: boolean;
  deletedAt?: string;
}

export interface AppState {
  currentUser: User;
  users: User[]; // Danh sách toàn bộ nhân sự (chỉ Admin/Manager thấy một phần)
  tasks: Task[]; // Danh sách công việc (lọc theo quyền)
  companies: string[];
  settings: {
    language: Language;
    theme: Theme;
  };
}

import React, { useState } from 'react';
import { User, UserRole, Language } from '../types';
import { translations } from '../translations';

interface AdminUserModalProps {
  currentUser: User;
  users: User[];
  language: Language;
  onAddUser: (user: User) => void;
  onUpdateUser: (user: User) => void;
  onDeleteUser: (id: string) => void;
  onClose: () => void;
}

const AdminUserModal: React.FC<AdminUserModalProps> = ({ currentUser, users, language, onAddUser, onUpdateUser, onDeleteUser, onClose }) => {
  const t = translations[language];
  const [editingUser, setEditingUser] = useState<Partial<User> | null>(null);

  const roles: UserRole[] = ['ADMIN', 'DEPT_HEAD', 'MANAGER', 'EMPLOYEE'];

  // Chỉ hiện những người có thể làm quản lý
  const potentialManagers = users.filter(u => u.role !== 'EMPLOYEE');

  const handleSave = () => {
    if (!editingUser?.email || !editingUser?.fullName || !editingUser?.role) return;

    if (editingUser.id) {
      onUpdateUser(editingUser as User);
    } else {
      onAddUser({
        ...editingUser,
        id: crypto.randomUUID(),
      } as User);
    }
    setEditingUser(null);
  };

  return (
    <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-xl animate-in fade-in duration-300">
      <div className="bg-white dark:bg-slate-900 w-full max-w-4xl rounded-[3rem] shadow-2xl border border-slate-100 dark:border-slate-800 flex flex-col max-h-[90vh] overflow-hidden">
        <header className="p-8 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center shrink-0">
          <div>
            <h2 className="text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.manageUsers}</h2>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Hệ thống: {users.length}/200 Nhân sự</p>
          </div>
          <button onClick={onClose} className="text-slate-300 hover:text-rose-500 transition-colors">
            <i className="fas fa-times text-2xl"></i>
          </button>
        </header>

        <div className="flex-1 overflow-hidden flex flex-col md:flex-row">
          {/* List Users */}
          <div className="flex-1 p-6 overflow-y-auto custom-scrollbar border-r border-slate-100 dark:border-slate-800">
            <div className="space-y-3">
              {users.map(u => (
                <div key={u.id} className="group flex items-center gap-4 p-4 bg-slate-50 dark:bg-slate-800/40 rounded-2xl border border-slate-100 dark:border-slate-800 hover:border-blue-500 transition-all">
                  <div className={`w-12 h-12 rounded-full flex items-center justify-center font-black text-white shadow-lg ${
                    u.role === 'ADMIN' ? 'bg-rose-500' : u.role === 'DEPT_HEAD' ? 'bg-amber-500' : u.role === 'MANAGER' ? 'bg-indigo-500' : 'bg-slate-400'
                  }`}>
                    {u.fullName.charAt(0)}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="font-black text-slate-800 dark:text-white truncate uppercase text-sm tracking-tight">{u.fullName}</p>
                    <div className="flex items-center gap-2 mt-0.5">
                      <span className="text-[9px] font-black px-2 py-0.5 rounded-md bg-white dark:bg-slate-900 text-slate-500 dark:text-slate-400 border border-slate-200 dark:border-slate-700 uppercase tracking-widest">
                        {t[`role_${u.role}` as keyof typeof t]}
                      </span>
                      {u.reportsTo && (
                        <span className="text-[9px] text-slate-400 font-bold">
                          <i className="fas fa-chevron-up mr-1 opacity-50"></i> {users.find(m => m.id === u.reportsTo)?.fullName}
                        </span>
                      )}
                    </div>
                  </div>
                  <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-all">
