import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import TaskItem from './components/TaskItem';
import Login from './components/Login';
import Setup from './components/Setup';
import HistoryModal from './components/HistoryModal';
import ExportModal from './components/ExportModal';
import SettingsModal from './components/SettingsModal';
import ManageCompaniesModal from './components/ManageCompaniesModal';
import AdminUserModal from './components/AdminUserModal';
import { Task, TaskStatus, AppState, Language, Theme, User, UserRole } from './types';
import { loadStateSecure, saveStateSecure } from './services/storageService';
import { translations } from './translations';

const App: React.FC = () => {
  const [state, setState] = useState<AppState | null>(null);
  const [loading, setLoading] = useState(false);
  const [modals, setModals] = useState({
    history: false,
    export: false,
    settings: false,
    manageCompanies: false,
    manageUsers: false,
    delete: null as string | null
  });
  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);
  const [currentView, setCurrentView] = useState<'PERSONAL' | 'TEAM'>('PERSONAL');

  const currentLanguage = state?.settings?.language || 'vi';
  const t = translations[currentLanguage];

  // Theme effect
  useEffect(() => {
    const root = document.documentElement;
    if (state?.settings?.theme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
  }, [state?.settings?.theme]);

  // Login handler (Simulated system auth)
  const handleLogin = async (email: string, pass: string) => {
    setLoading(true);
    try {
      // Trong thực tế, đây sẽ là call API đến server để lấy data dùng chung
      const loaded = await loadStateSecure(email, pass);
      setState(loaded);
    } catch (e: any) { alert(e.message); }
    finally { setLoading(false); }
  };

  const handleLogout = () => setState(null);

  // Persistence - Trong thực tế sẽ đẩy lên API
  useEffect(() => {
    if (state) saveStateSecure(state.currentUser.email, 'password_mock', state);
  }, [state]);

  // Logic phân cấp dữ liệu
  const isSupervisorOf = (supervisorId: string, subordinateId: string): boolean => {
    if (!state) return false;
    const subordinate = state.users.find(u => u.id === subordinateId);
    if (!subordinate) return false;

    // Nếu subordinate trực tiếp
    if (subordinate.reportsTo === supervisorId) return true;

    // Nếu là DEPT_HEAD hoặc ADMIN, kiểm tra đệ quy (Recursive search in tree)
    const supervisor = state.users.find(u => u.id === supervisorId);
    if (supervisor?.role === 'ADMIN') return true;
    if (supervisor?.role === 'DEPT_HEAD') {
      // Dept head thấy hết mọi người trong cùng Dept hoặc cấp dưới đệ quy
      // Ở đây đơn giản hóa: thấy mọi người không phải Admin
      return subordinate.role !== 'ADMIN';
    }

    // Kiểm tra đệ quy cho Manager
    if (subordinate.reportsTo) {
      return isSupervisorOf(supervisorId, subordinate.reportsTo);
    }

    return false;
  };

  const filteredTasks = useMemo(() => {
    if (!state) return [];
    if (currentView === 'PERSONAL') {
      return state.tasks.filter(tk => tk.userId === state.currentUser.id && !tk.deletedAt);
    } else {
      // Xem công việc của đội ngũ
      return state.tasks.filter(tk => tk.userId !== state.currentUser.id && !tk.deletedAt && isSupervisorOf(state.currentUser.id, tk.userId));
    }
  }, [state, currentView]);

  const stats = useMemo(() => {
    if (!state) return { active: 0, doneToday: 0 };
    const today = new Date().toISOString().split('T')[0];
    const pool = currentView === 'PERSONAL' 
      ? state.tasks.filter(tk => tk.userId === state.currentUser.id)
      : state.tasks.filter(tk => isSupervisorOf(state.currentUser.id, tk.userId));

    return {
      active: pool.filter(tk => !tk.deletedAt && tk.status !== TaskStatus.DONE).length,
      doneToday: pool.filter(tk => !tk.deletedAt && tk.status === TaskStatus.DONE && tk.updatedAt.startsWith(today)).length
    };
  }, [state, currentView]);

  // Actions
  const handleAddTask = (content: string, company: string, isPriority: boolean) => {
    if (!state) return;
    const newTask: Task = {
      id: crypto.randomUUID(),
      userId: state.currentUser.id,
      content,
      company,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      status: TaskStatus.NOT_STARTED,
      isPriority
    };
    setState(prev => prev ? ({ ...prev, tasks: [newTask, ...prev.tasks] }) : null);
  };

  const handleUpdateUser = (updatedUser: User) => {
    setState(prev => prev ? ({
      ...prev,
      users: prev.users.map(u => u.id === updatedUser.id ? updatedUser : u)
    }) : null);
  };

  const handleAddUser = (newUser: User) => {
    setState(prev => prev ? ({
      ...prev,
      users: [...prev.users, newUser]
    }) : null);
  };

  if (loading) return (
    <div className="h-screen bg-white dark:bg-slate-950 flex flex-col items-center justify-center text-blue-600 p-6 text-center">
      <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
      <p className="font-black uppercase tracking-widest text-[10px] dark:text-blue-400">Zen Enterprise System...</p>
    </div>
  );

  if (!state) return <Login onLogin={handleLogin} />;

  const canManageUsers = ['ADMIN', 'DEPT_HEAD', 'MANAGER'].includes(state.currentUser.role);
  const canViewTeam = state.currentUser.role !== 'EMPLOYEE';

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-white dark:bg-slate-950 theme-transition">
      <Sidebar 
        email={state.currentUser.fullName}
        companies={state.companies}
        language={state.settings.language}
        onAddTask={handleAddTask} 
        onAddCompany={c => setState(p => p ? ({...p, companies: [...p.companies, c]}) : null)}
        onOpenManageCompanies={() => setModals(m => ({...m, manageCompanies: true}))}
        onClearAll={() => {}} 
        onLogout={handleLogout}
        onOpenHistory={() => setModals(m => ({...m, history: true}))}
        onOpenExport={() => setModals(m => ({...m, export: true}))}
        onOpenSettings={() => setModals(m => ({...m, settings: true}))}
        onOpenManageUsers={() => canManageUsers && setModals(m => ({...m, manageUsers: true}))}
      />

      <main className="flex-1 flex flex-col min-w-0 bg-slate-50 dark:bg-slate-950 relative h-screen overflow-hidden theme-transition">
        <header className="min-h-[110px] py-4 px-6 md:px-10 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex flex-col md:flex-row md:items-center justify-between z-10 shadow-sm gap-4 transition-all">
          <div className="flex items-center gap-6">
            <button 
              onClick={() => setCurrentView('PERSONAL')}
              className={`flex flex-col items-start transition-all ${currentView === 'PERSONAL' ? 'opacity-100' : 'opacity-40 hover:opacity-70'}`}
            >
              <h2 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.currentTasks}</h2>
              <span className="text-[10px] font-black uppercase text-blue-500 tracking-widest">{state.currentUser.fullName}</span>
            </button>

            {canViewTeam && (
              <button 
                onClick={() => setCurrentView('TEAM')}
                className={`flex flex-col items-start transition-all ${currentView === 'TEAM' ? 'opacity-100' : 'opacity-40 hover:opacity-70'}`}
              >
                <h2 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.teamTasks}</h2>
                <span className="text-[10px] font-black uppercase text-amber-500 tracking-widest">{t[`role_${state.currentUser.role}` as keyof typeof t]}</span>
              </button>
            )}
          </div>

          <div className="flex items-center gap-6 md:gap-10">
            <div className="text-right">
              <p className="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t.doing}</p>
              <p className="text-2xl font-black text-rose-500 leading-tight">{stats.active}</p>
            </div>
            <div className="text-right">
              <p className="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t.doneToday}</p>
              <p className="text-2xl font-black text-emerald-500 leading-tight">{stats.doneToday}</p>
            </div>
            <div className="hidden lg:flex flex-col items-end border-l border-slate-100 dark:border-slate-800 pl-8">
              <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Hệ thống phân cấp</span>
              <div className="flex items-center gap-2 mt-1">
                 <div className="px-3 py-1 bg-slate-100 dark:bg-slate-800 rounded-full text-[10px] font-black uppercase text-slate-600 dark:text-slate-300">
                    {t[`role_${state.currentUser.role}` as keyof typeof t]}
                 </div>
              </div>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar">
          <div className="max-w-4xl mx-auto space-y-4 pb-24">
            {filteredTasks.length === 0 ? (
              <div className="h-96 flex flex-col items-center justify-center opacity-30 italic text-slate-400 font-bold uppercase tracking-widest">
                <i className="fas fa-tasks text-6xl mb-4"></i>
                {t.noTasks}
              </div>
            ) : (
              filteredTasks.map(task => {
                const owner = state.users.find(u => u.id === task.userId);
                return (
                  <div key={task.id} className="relative">
                    {currentView === 'TEAM' && owner && (
                       <div className="absolute -top-2 left-6 px-3 py-0.5 bg-indigo-600 text-white text-[8px] font-black uppercase tracking-widest rounded-full z-10 shadow-lg">
                          BY: {owner.fullName}
                       </div>
                    )}
                    <TaskItem 
                      task={task} 
                      language={state.settings.language} 
                      readOnly={currentView === 'TEAM'}
                      onStatusChange={(id, status) => {
                        setState(prev => prev ? ({
                          ...prev,
                          tasks: prev.tasks.map(t => t.id === id ? {...t, status, updatedAt: new Date().toISOString()} : t)
                        }) : null)
                      }}
                      onDelete={id => setModals(m => ({...m, delete: id}))} 
                    />
                  </div>
                )
              })
            )}
          </div>
        </div>

        {canManageUsers && (
           <div className="absolute bottom-6 left-6">
              <button 
                onClick={() => setModals(m => ({...m, manageUsers: true}))}
                className="px-6 py-4 bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-3xl shadow-xl flex items-center gap-3 hover:-translate-y-1 transition-all active:scale-95"
              >
                <div className="w-8 h-8 bg-blue-600 rounded-xl flex items-center justify-center text-white"><i className="fas fa-users-cog text-xs"></i></div>
                <span className="text-[10px] font-black uppercase tracking-widest text-slate-600 dark:text-slate-300">{t.manageUsers}</span>
              </button>
           </div>
        )}
      </main>

      {modals.manageUsers && canManageUsers && (
        <AdminUserModal 
          currentUser={state.currentUser}
          users={state.users}
          language={state.settings.language}
          onAddUser={handleAddUser}
          onUpdateUser={handleUpdateUser}
          onDeleteUser={id => setState(prev => prev ? ({...prev, users: prev.users.filter(u => u.id !== id)}) : null)}
          onClose={() => setModals(m => ({...m, manageUsers: false}))}
        />
      )}

      {/* Các Modals khác giữ nguyên và update theme tương tự */}
      {modals.settings && <SettingsModal language={state.settings.language} theme={state.settings.theme} onUpdate={(l, theme) => setState(p => p ? ({...p, settings: {language: l, theme}}) : null)} onClose={() => setModals(m => ({...m, settings: false}))} />}
    </div>
  );
};

export default App;

import { AppState, TaskStatus, User, UserRole } from '../types';

const STORAGE_KEY = 'zentask_enterprise_db';

export const saveStateSecure = async (email: string, password: string, state: AppState) => {
  // Trong mô hình Enterprise, ta lưu toàn bộ DB vào một key duy nhất (Simulated Server)
  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
};

export const loadStateSecure = async (email: string, password: string): Promise<AppState> => {
  const raw = localStorage.getItem(STORAGE_KEY);

  if (raw) {
    const fullState: AppState = JSON.parse(raw);
    // Tìm user đang đăng nhập
    const user = fullState.users.find(u => u.email === email);
    if (user) {
      return { ...fullState, currentUser: user };
    }
  }

  // Khởi tạo mặc định nếu chưa có DB (Lần đầu chạy ứng dụng)
  const adminId = crypto.randomUUID();
  const defaultAdmin: User = {
    id: adminId,
    email: email || 'admin@zen.com',
    fullName: 'System Administrator',
    role: 'ADMIN',
  };

  const defaultState: AppState = {
    currentUser: defaultAdmin,
    users: [defaultAdmin],
    tasks: [],
    companies: ["Internal", "Agriviet", "TechFlow"],
    settings: { language: 'vi', theme: 'light' }
  };

  localStorage.setItem(STORAGE_KEY, JSON.stringify(defaultState));
  return defaultState;
};

import React, { useState } from 'react';
import { Language } from '../types';
import { translations } from '../translations';

interface SidebarProps {
  email: string;
  companies: string[];
  language: Language;
  onAddTask: (content: string, company: string, isPriority: boolean) => void;
  onAddCompany: (company: string) => void;
  onOpenManageCompanies: () => void;
  onClearAll: () => void;
  onLogout: () => void;
  onOpenHistory: () => void;
  onOpenExport: () => void;
  onOpenSettings: () => void;
  onOpenManageUsers: () => void;
  onCloseMobile?: () => void;
}

