export const loadStateSecure = async (email: string, password: string): Promise<AppState> => {
  const raw = localStorage.getItem(STORAGE_KEY);

  if (raw) {
    const fullState: AppState = JSON.parse(raw);
    // Tìm user đang đăng nhập
    const user = fullState.users.find(u => u.email === email);
    if (user) {
      return { ...fullState, currentUser: user };
    }
  }

  // Khởi tạo mặc định nếu chưa có DB (Lần đầu chạy ứng dụng)
  const adminId = crypto.randomUUID();
  // Fix: Added missing jobTitle property to satisfy User interface requirements
  const defaultAdmin: User = {
    id: adminId,
    email: email || 'admin@zen.com',
    fullName: 'System Administrator',
    jobTitle: 'System Administrator',
    role: 'ADMIN',
  };

  const defaultState: AppState = {
    currentUser: defaultAdmin,
    users: [defaultAdmin],
    tasks: [],
    companies: ["Internal", "Agriviet", "TechFlow"],
    settings: { language: 'vi', theme: 'light' }
  };

  localStorage.setItem(STORAGE_KEY, JSON.stringify(defaultState));
  return defaultState;
};

// Added authenticateUser to fix missing member error in Login.tsx
export const authenticateUser = async (credentials: { email: string; password: string }) => {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (!raw) return { success: false, message: 'Hệ thống chưa khởi tạo. Vui lòng đăng ký tài khoản.' };

  const state: AppState = JSON.parse(raw);
  const user = state.users.find(u => u.email === credentials.email);
  if (user) {
    // Trong bản mô phỏng, chấp nhận đăng nhập nếu user tồn tại
    return { success: true };
  }
  return { success: false, message: 'Email không tồn tại trong hệ thống.' };
};

// Added registerUser to fix missing member error in Login.tsx
export const registerUser = async (credentials: { email: string; password: string }) => {
  const raw = localStorage.getItem(STORAGE_KEY);
