const App: React.FC = () => {
  const [state, setState] = useState<AppState | null>(null);
  const [loading, setLoading] = useState(false);
  const [modals, setModals] = useState({
    history: false,
    export: false,
    settings: false,
    manageCompanies: false,
    manageUsers: false,
    delete: null as string | null
  });
  const [currentView, setCurrentView] = useState<'PERSONAL' | 'TEAM'>('PERSONAL');

  const currentLanguage = state?.settings?.language || 'vi';
  const currentTheme = state?.settings?.theme || 'light';
  const t = translations[currentLanguage] || translations.vi;

  // Theme effect
  useEffect(() => {
    const root = document.documentElement;
    if (currentTheme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
  }, [currentTheme]);

  // Login handler
  const handleLogin = async (email: string, pass: string) => {
    setLoading(true);
    try {
      const loaded = await loadStateSecure(email, pass);
      setState(loaded);
    } catch (e: any) { 
      alert(e.message || "Lỗi đăng nhập"); 
    }
    finally { setLoading(false); }
  };

  const handleLogout = () => setState(null);

  const handleSetupComplete = (fullName: string, jobTitle: string, companies: string[]) => {
    setState(prev => {
      if (!prev) return null;
      const updatedUser = { ...prev.currentUser, fullName, jobTitle };
      return {
        ...prev,
        currentUser: updatedUser,
        users: prev.users.map(u => u.id === updatedUser.id ? updatedUser : u),
        companies: companies
      };
    });
  };

  // Persistence
  useEffect(() => {
    if (state && state.currentUser) {
      saveStateSecure(state.currentUser.email, 'password_mock', state);
    }
  }, [state]);

  // Logic phân cấp dữ liệu
  const isSupervisorOf = (supervisorId: string, subordinateId: string): boolean => {
    if (!state || !state.users) return false;
    const subordinate = state.users.find(u => u.id === subordinateId);
    if (!subordinate) return false;
    if (subordinate.reportsTo === supervisorId) return true;
    const supervisor = state.users.find(u => u.id === supervisorId);
    if (supervisor?.role === 'ADMIN') return true;
    if (supervisor?.role === 'DEPT_HEAD') return subordinate.role !== 'ADMIN';
    if (subordinate.reportsTo) return isSupervisorOf(supervisorId, subordinate.reportsTo);
    return false;
  };

  const filteredTasks = useMemo(() => {
    if (!state || !state.tasks) return [];
    if (currentView === 'PERSONAL') {
      return state.tasks.filter(tk => tk.userId === state.currentUser.id && !tk.deletedAt);
    } else {
      return state.tasks.filter(tk => tk.userId !== state.currentUser.id && !tk.deletedAt && isSupervisorOf(state.currentUser.id, tk.userId));
    }
  }, [state, currentView]);

  const stats = useMemo(() => {
    if (!state || !state.tasks) return { active: 0, doneToday: 0 };
    const today = new Date().toISOString().split('T')[0];
    const pool = currentView === 'PERSONAL' 
      ? state.tasks.filter(tk => tk.userId === state.currentUser.id)
      : state.tasks.filter(tk => isSupervisorOf(state.currentUser.id, tk.userId));

    return {
      active: pool.filter(tk => !tk.deletedAt && tk.status !== TaskStatus.DONE).length,
      doneToday: pool.filter(tk => !tk.deletedAt && tk.status === TaskStatus.DONE && tk.updatedAt.startsWith(today)).length
    };
  }, [state, currentView]);

  const managerName = useMemo(() => {
    if (!state || !state.users || !state.currentUser?.reportsTo) return undefined;
    const manager = state.users.find(u => u.id === state.currentUser.reportsTo);
    return manager?.fullName;
  }, [state]);

  // Actions
  const handleAddTask = (content: string, company: string, isPriority: boolean) => {
    if (!state) return;
    const newTask: Task = {
      id: crypto.randomUUID(),
      userId: state.currentUser.id,
      content,
      company,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      status: TaskStatus.NOT_STARTED,
      isPriority
    };
    setState(prev => prev ? ({ ...prev, tasks: [newTask, ...prev.tasks] }) : null);
  };

  if (loading) return (
    <div className="h-screen bg-white dark:bg-slate-950 flex flex-col items-center justify-center text-blue-600 p-6 text-center">
      <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
      <p className="font-black uppercase tracking-widest text-[10px] dark:text-blue-400">Zen Enterprise System...</p>
    </div>
  );

  if (!state) return <Login onLogin={handleLogin} />;

  // Kiểm tra xem user đã nhập họ tên và chức danh chưa
  const hasSetup = state.currentUser.fullName && state.currentUser.fullName !== state.currentUser.email.split('@')[0];
  if (!hasSetup) {
    return <Setup onComplete={handleSetupComplete} onLogout={handleLogout} />;
  }

  const canManageUsers = ['ADMIN', 'DEPT_HEAD', 'MANAGER'].includes(state.currentUser.role);
  const canViewTeam = state.currentUser.role !== 'EMPLOYEE';

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-white dark:bg-slate-950 theme-transition">
      <Sidebar 
        currentUser={state.currentUser}
        managerName={managerName}
        companies={state.companies}
        language={currentLanguage}
        onAddTask={handleAddTask} 
        onAddCompany={c => setState(p => p ? ({...p, companies: [...p.companies, c]}) : null)}
        onOpenManageCompanies={() => setModals(m => ({...m, manageCompanies: true}))}
        onClearAll={() => {}} 
        onLogout={handleLogout}
        onOpenHistory={() => setModals(m => ({...m, history: true}))}
        onOpenExport={() => setModals(m => ({...m, export: true}))}
        onOpenSettings={() => setModals(m => ({...m, settings: true}))}
        onOpenManageUsers={() => canManageUsers && setModals(m => ({...m, manageUsers: true}))}
      />

      <main className="flex-1 flex flex-col min-w-0 bg-slate-50 dark:bg-slate-950 relative h-screen overflow-hidden theme-transition">
        <header className="min-h-[110px] py-4 px-6 md:px-10 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex flex-col md:flex-row md:items-center justify-between z-10 shadow-sm gap-4 transition-all">
          <div className="flex items-center gap-6">
            <button 
              onClick={() => setCurrentView('PERSONAL')}
              className={`flex flex-col items-start transition-all ${currentView === 'PERSONAL' ? 'opacity-100' : 'opacity-40 hover:opacity-70'}`}
            >
              <h2 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.currentTasks}</h2>
              <span className="text-[10px] font-black uppercase text-blue-500 tracking-widest">{state.currentUser.fullName}</span>
            </button>

            {canViewTeam && (
              <button 
                onClick={() => setCurrentView('TEAM')}
                className={`flex flex-col items-start transition-all ${currentView === 'TEAM' ? 'opacity-100' : 'opacity-40 hover:opacity-70'}`}
              >
                <h2 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.teamTasks}</h2>
                <span className="text-[10px] font-black uppercase text-amber-500 tracking-widest">{t[`role_${state.currentUser.role}` as keyof typeof t]}</span>
              </button>
            )}
          </div>

          <div className="flex items-center gap-6 md:gap-10">
            <div className="text-right">
              <p className="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t.doing}</p>
              <p className="text-2xl font-black text-rose-500 leading-tight">{stats.active}</p>
            </div>
            <div className="text-right">
              <p className="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t.doneToday}</p>
              <p className="text-2xl font-black text-emerald-500 leading-tight">{stats.doneToday}</p>
            </div>
            <div className="hidden lg:flex flex-col items-end border-l border-slate-100 dark:border-slate-800 pl-8">
              <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Hệ thống phân cấp</span>
              <div className="flex items-center gap-2 mt-1">
                 <div className="px-3 py-1 bg-slate-100 dark:bg-slate-800 rounded-full text-[10px] font-black uppercase text-slate-600 dark:text-slate-300">
                    {t[`role_${state.currentUser.role}` as keyof typeof t]}
                 </div>
              </div>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar">
          <div className="max-w-4xl mx-auto space-y-4 pb-24">
            {filteredTasks.length === 0 ? (
              <div className="h-96 flex flex-col items-center justify-center opacity-30 italic text-slate-400 font-bold uppercase tracking-widest">
                <i className="fas fa-tasks text-6xl mb-4"></i>
                {t.noTasks}
              </div>
            ) : (
              filteredTasks.map(task => {
                const owner = state.users.find(u => u.id === task.userId);
                return (
                  <div key={task.id} className="relative">
                    {currentView === 'TEAM' && owner && (
                       <div className="absolute -top-2 left-6 px-3 py-0.5 bg-indigo-600 text-white text-[8px] font-black uppercase tracking-widest rounded-full z-10 shadow-lg">
                          {owner.fullName} - {owner.jobTitle}
                       </div>
                    )}
                    <TaskItem 
                      task={task} 
                      language={currentLanguage} 
                      readOnly={currentView === 'TEAM'}
                      onStatusChange={(id, status) => {
                        setState(prev => prev ? ({
                          ...prev,
                          tasks: prev.tasks.map(t => t.id === id ? {...t, status, updatedAt: new Date().toISOString()} : t)
                        }) : null)
                      }}
                      onDelete={id => setState(p => p ? ({...p, tasks: p.tasks.map(t => t.id === id ? {...t, deletedAt: new Date().toISOString()} : t)}) : null)} 
                    />
                  </div>
                )
              })
            )}
          </div>
        </div>

        {canManageUsers && (
           <div className="absolute bottom-6 left-6">
              <button 
                onClick={() => setModals(m => ({...m, manageUsers: true}))}
                className="px-6 py-4 bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-3xl shadow-xl flex items-center gap-3 hover:-translate-y-1 transition-all active:scale-95"
              >
                <div className="w-8 h-8 bg-blue-600 rounded-xl flex items-center justify-center text-white"><i className="fas fa-users-cog text-xs"></i></div>
                <span className="text-[10px] font-black uppercase tracking-widest text-slate-600 dark:text-slate-300">{t.manageUsers}</span>
              </button>
           </div>
        )}
      </main>

      {modals.manageUsers && canManageUsers && (
        <AdminUserModal 
          currentUser={state.currentUser}
          users={state.users}
          language={currentLanguage}
          onAddUser={u => setState(p => p ? ({...p, users: [...p.users, u]}) : null)}
          onUpdateUser={u => setState(p => p ? ({...p, users: p.users.map(old => old.id === u.id ? u : old)}) : null)}
          onDeleteUser={id => setState(prev => prev ? ({...prev, users: prev.users.filter(u => u.id !== id)}) : null)}
          onClose={() => setModals(m => ({...m, manageUsers: false}))}
        />
      )}

      {modals.manageCompanies && <ManageCompaniesModal companies={state.companies} language={currentLanguage} onRename={(old, cur) => setState(p => p ? ({...p, companies: p.companies.map(c => c === old ? cur : c), tasks: p.tasks.map(t => t.company === old ? {...t, company: cur} : t)}) : null)} onDelete={c => setState(p => p ? ({...p, companies: p.companies.filter(x => x !== c)}) : null)} onClose={() => setModals(m => ({...m, manageCompanies: false}))} />}
      {modals.settings && <SettingsModal language={currentLanguage} theme={currentTheme} onUpdate={(l, theme) => setState(p => p ? ({...p, settings: {language: l, theme}}) : null)} onClose={() => setModals(m => ({...m, settings: false}))} />}
      {modals.history && <HistoryModal tasks={state.tasks.filter(t => !t.deletedAt && t.userId === state.currentUser.id)} onClose={() => setModals(m => ({...m, history: false}))} />}
      {modals.export && <ExportModal tasks={state.tasks.filter(t => !t.deletedAt)} templates={state.templates || []} onSaveTemplate={tpl => setState(p => p ? ({...p, templates: [...(p.templates || []), tpl]}) : null)} onDeleteTemplate={id => setState(p => p ? ({...p, templates: (p.templates || []).filter(x => x.id !== id)}) : null)} onClose={() => setModals(m => ({...m, export: false}))} />}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Language, User } from '../types';
import { translations } from '../translations';

interface SidebarProps {
  currentUser: User;
  managerName?: string;
  companies: string[];
  language: Language;
  onAddTask: (content: string, company: string, isPriority: boolean) => void;
  onAddCompany: (company: string) => void;
  onOpenManageCompanies: () => void;
  onClearAll: () => void;
  onLogout: () => void;
  onOpenHistory: () => void;
  onOpenExport: () => void;
  onOpenSettings: () => void;
  onOpenManageUsers: () => void;
  onCloseMobile?: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  currentUser, managerName, companies, language, onAddTask, onAddCompany, onOpenManageCompanies, onClearAll, onLogout, onOpenHistory, onOpenExport, onOpenSettings, onOpenManageUsers, onCloseMobile
}) => {
  const [content, setContent] = useState('');
  const [selectedCompany, setSelectedCompany] = useState(companies[0] || '');
  const [isPriority, setIsPriority] = useState(false);

  // Safe translation lookup
  const t = translations[language] || translations.vi;

  const handleSubmitTask = (e: React.FormEvent) => {
    e.preventDefault();
    if (!content.trim() || !selectedCompany) return;
    onAddTask(content, selectedCompany, isPriority);
    setContent('');
    setIsPriority(false);
  };

  return (
    <div className="w-[320px] md:w-[400px] bg-white dark:bg-slate-950 h-full flex flex-col p-8 md:p-10 flex-shrink-0 border-r border-slate-100 dark:border-slate-800 shadow-2xl md:shadow-none overflow-y-auto custom-scrollbar transition-colors">
      <div className="mb-8 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-blue-600 rounded-[1.2rem] flex items-center justify-center text-white shadow-xl shadow-blue-500/20"><i className="fas fa-shield-halved text-xl"></i></div>
          <div>
            <h1 className="text-xl font-black text-slate-800 dark:text-white tracking-tighter leading-tight uppercase">{t.appName}</h1>
            <p className="text-[10px] font-black text-blue-500 uppercase tracking-widest">Enterprise Edition</p>
          </div>
        </div>
        <button onClick={onLogout} className="w-10 h-10 rounded-xl bg-slate-50 dark:bg-slate-900 text-slate-400 hover:text-rose-500 transition-all border border-slate-100 dark:border-slate-800"><i className="fas fa-power-off"></i></button>
      </div>

      {/* User Info & Manager Info */}
      <div className="mb-8 p-5 bg-slate-50 dark:bg-slate-900/50 rounded-3xl border border-slate-100 dark:border-slate-800 space-y-3">
        <div>
          <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{t.fullName}</p>
          <p className="font-black text-slate-800 dark:text-white text-sm">{currentUser.fullName}</p>
          <p className="text-[10px] font-bold text-blue-600 dark:text-blue-400 uppercase">{currentUser.jobTitle}</p>
        </div>
        {managerName && (
          <div className="pt-3 border-t border-slate-100 dark:border-slate-800">
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{t.directManager}</p>
            <div className="flex items-center gap-2 mt-1">
              <div className="w-5 h-5 bg-indigo-500 rounded-full flex items-center justify-center text-[8px] text-white"><i className="fas fa-user-tie"></i></div>
              <p className="font-bold text-slate-700 dark:text-slate-300 text-xs">{managerName}</p>
            </div>
          </div>
        )}
      </div>

      <div className="grid grid-cols-2 gap-3 mb-8">
        <button onClick={onOpenHistory} className="p-4 rounded-2xl bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 border border-indigo-100 dark:border-indigo-800 flex flex-col items-center gap-2 hover:scale-105 transition-all">
          <i className="fas fa-chart-line"></i>
          <span className="text-[9px] font-black uppercase tracking-widest">{t.history}</span>
        </button>
        <button onClick={onOpenExport} className="p-4 rounded-2xl bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400 border border-emerald-100 dark:border-emerald-800 flex flex-col items-center gap-2 hover:scale-105 transition-all">
          <i className="fas fa-file-invoice"></i>
          <span className="text-[9px] font-black uppercase tracking-widest">{t.report}</span>
        </button>
      </div>

      <div className="flex-1">
        <form onSubmit={handleSubmitTask} className="space-y-6">
          <div className="space-y-2">
            <div className="flex items-center justify-between px-1">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{t.company}</label>
              <button type="button" onClick={onOpenManageCompanies} className="text-[10px] font-black text-blue-500 hover:text-blue-700 uppercase tracking-widest">{t.manage}</button>
            </div>
            <select value={selectedCompany} onChange={(e) => setSelectedCompany(e.target.value)} className="w-full p-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl outline-none font-bold text-slate-700 dark:text-white appearance-none text-xs focus:ring-2 focus:ring-blue-500/20">
              {companies.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">{t.taskContent}</label>
            <textarea value={content} onChange={(e) => setContent(e.target.value)} placeholder={t.placeholderContent} className="w-full p-5 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl outline-none h-40 resize-none text-slate-800 dark:text-white font-medium text-xs focus:ring-2 focus:ring-blue-500/20" />
          </div>

          <div onClick={() => setIsPriority(!isPriority)} className={`flex items-center gap-4 p-4 rounded-2xl border transition-all cursor-pointer ${isPriority ? 'bg-rose-50 dark:bg-rose-950/30 border-rose-200 dark:border-rose-900' : 'bg-slate-50 dark:bg-slate-900 border-slate-100 dark:border-slate-800'}`}>
            <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${isPriority ? 'bg-rose-500 border-rose-500 text-white shadow-lg' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700'}`}>
              {isPriority && <i className="fas fa-check text-[10px]"></i>}
            </div>
            <span className={`text-[11px] font-black uppercase tracking-widest ${isPriority ? 'text-rose-600' : 'text-slate-500 dark:text-slate-400'}`}>{t.isPriority}</span>
          </div>

          <button type="submit" className="w-full bg-slate-900 dark:bg-blue-600 hover:opacity-90 text-white font-black py-5 rounded-2xl shadow-2xl transition-all flex items-center justify-center gap-3 text-xs tracking-widest uppercase active:scale-95">
            <i className="fas fa-plus-circle"></i> {t.update}
          </button>
        </form>
      </div>

      <div className="mt-10 pt-6 border-t border-slate-100 dark:border-slate-800 flex items-center justify-between">
        <button onClick={onOpenSettings} className="flex items-center gap-2 text-slate-400 hover:text-slate-600 dark:hover:text-white transition-colors">
          <i className="fas fa-sliders-h text-sm"></i>
          <span className="text-[10px] font-black uppercase tracking-widest">{t.settings}</span>
        </button>
        <p className="text-[9px] text-slate-300 font-bold uppercase tracking-widest">v5.5-ENT</p>
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import { Language, Theme } from '../types';
import { translations } from '../translations';

interface SettingsModalProps {
  language: Language;
  theme: Theme;
  onUpdate: (lang: Language, theme: Theme) => void;
  onClose: () => void;
}

const SettingsModal: React.FC<SettingsModalProps> = ({ language, theme: initialTheme, onUpdate, onClose }) => {
  const [tempLanguage, setTempLanguage] = useState<Language>(language);
  const [tempTheme, setTempTheme] = useState<Theme>(initialTheme);

  // Safe translation lookup
  const t = translations[tempLanguage] || translations.vi;

  // Hiệu ứng xem trước (Preview) - Tác động trực tiếp vào DOM
  useEffect(() => {
    const root = document.documentElement;
    if (tempTheme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  }, [tempTheme]);

  const handleSave = () => {
    onUpdate(tempLanguage, tempTheme);
    onClose();
  };

  const handleCancel = () => {
    // Khôi phục lại theme ban đầu nếu không lưu
    const root = document.documentElement;
    if (initialTheme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-[2.5rem] shadow-2xl border border-slate-100 dark:border-slate-800 overflow-hidden transform animate-in zoom-in-95 duration-200">
        <header className="p-8 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-white dark:bg-slate-900">
          <h2 className="text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.settings}</h2>
          <button onClick={handleCancel} className="text-slate-300 hover:text-rose-500 transition-colors">
            <i className="fas fa-times text-xl"></i>
          </button>
        </header>

        <div className="p-8 space-y-8 bg-white dark:bg-slate-900">
          {/* Language Selection */}
          <div className="space-y-4">
            <label className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">{t.language}</label>
            <div className="grid grid-cols-2 gap-3">
              {(['vi', 'en', 'zh', 'ru'] as Language[]).map(lang => (
                <button
                  key={lang}
                  onClick={() => setTempLanguage(lang)}
                  className={`py-4 rounded-2xl border-2 font-black text-[10px] uppercase tracking-widest transition-all ${
                    tempLanguage === lang 
                      ? 'border-blue-600 bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400' 
                      : 'border-slate-50 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/50 text-slate-400'
                  }`}
                >
                  {lang === 'vi' ? 'Tiếng Việt' : lang === 'en' ? 'English' : lang === 'zh' ? '中文' : 'Русский'}
                </button>
              ))}
            </div>
          </div>

          {/* Theme Selection */}
          <div className="space-y-4">
            <label className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">{t.theme}</label>
            <div className="flex gap-4">
              <button
                onClick={() => setTempTheme('light')}
                className={`flex-1 py-5 rounded-2xl border-2 font-black text-[10px] uppercase tracking-widest flex flex-col items-center justify-center gap-3 transition-all ${
                  tempTheme === 'light' 
                    ? 'border-amber-400 bg-amber-50 text-amber-700 shadow-lg shadow-amber-100' 
                    : 'border-slate-50 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/50 text-slate-400'
                }`}
              >
                <div className={`w-10 h-10 rounded-full flex items-center justify-center ${tempTheme === 'light' ? 'bg-amber-400 text-white' : 'bg-slate-200 dark:bg-slate-700'}`}>
                  <i className="fas fa-sun text-lg"></i>
                </div>
                {t.light}
              </button>
              <button
                onClick={() => setTempTheme('dark')}
                className={`flex-1 py-5 rounded-2xl border-2 font-black text-[10px] uppercase tracking-widest flex flex-col items-center justify-center gap-3 transition-all ${
                  tempTheme === 'dark' 
                    ? 'border-indigo-600 bg-indigo-900/40 text-indigo-400 shadow-lg shadow-indigo-950/50' 
                    : 'border-slate-50 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/50 text-slate-400'
                }`}
              >
                <div className={`w-10 h-10 rounded-full flex items-center justify-center ${tempTheme === 'dark' ? 'bg-indigo-600 text-white' : 'bg-slate-200 dark:bg-slate-700'}`}>
                  <i className="fas fa-moon text-lg"></i>
                </div>
                {t.dark}
              </button>
            </div>
          </div>
        </div>

        <footer className="p-8 bg-slate-50 dark:bg-slate-950/50 flex gap-4">
           <button 
             onClick={handleCancel} 
             className="flex-1 py-4 bg-white dark:bg-slate-800 text-slate-500 dark:text-slate-400 border border-slate-200 dark:border-slate-700 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-100 dark:hover:bg-slate-700 transition-all"
           >
             {t.cancel}
           </button>
           <button 
             onClick={handleSave} 
             className="flex-1 py-4 bg-slate-900 dark:bg-blue-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:opacity-90 transition-all active:scale-95"
           >
             {t.save}
           </button>
        </footer>
      </div>
    </div>
  );
};

export default SettingsModal;

import { AppState, TaskStatus, User, UserRole } from '../types';

const STORAGE_KEY = 'zentask_enterprise_db';

/**
 * Hàm khởi tạo trạng thái mặc định an toàn
 */
const createDefaultState = (email: string): AppState => {
  const adminId = crypto.randomUUID();
  const defaultAdmin: User = {
    id: adminId,
    email: email || 'admin@zen.com',
    fullName: email ? email.split('@')[0] : 'System Administrator',
    jobTitle: 'System Administrator',
    role: 'ADMIN',
  };

  return {
    currentUser: defaultAdmin,
    users: [defaultAdmin],
    tasks: [],
    companies: ["Internal", "Agriviet", "TechFlow"],
    settings: { language: 'vi', theme: 'light' }
  };
};

export const saveStateSecure = async (email: string, password: string, state: AppState) => {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  } catch (e) {
    console.error("Failed to save state:", e);
  }
};

export const loadStateSecure = async (email: string, password: string): Promise<AppState> => {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);

    if (raw) {
      let fullState: AppState = JSON.parse(raw);

      // Kiểm tra tính hợp lệ cơ bản của dữ liệu cũ
      if (!fullState || typeof fullState !== 'object') {
        throw new Error("Invalid storage format");
      }

      // Đảm bảo các mảng và settings luôn tồn tại (Migration an toàn)
      const sanitizedState: AppState = {
        ...fullState,
        users: Array.isArray(fullState.users) ? fullState.users : [],
        tasks: Array.isArray(fullState.tasks) ? fullState.tasks : [],
        companies: Array.isArray(fullState.companies) ? fullState.companies : ["Internal"],
        settings: fullState.settings || { language: 'vi', theme: 'light' }
      };

      // Đảm bảo các cài đặt mặc định có giá trị
      if (!sanitizedState.settings.language) sanitizedState.settings.language = 'vi';
      if (!sanitizedState.settings.theme) sanitizedState.settings.theme = 'light';

      // Tìm user đang đăng nhập
      const user = sanitizedState.users.find(u => u.email === email);
      if (user) {
        return { ...sanitizedState, currentUser: user };
      }
    }
  } catch (e) {
    console.warn("Could not load state, creating fresh DB:", e);
  }

  // Nếu không có dữ liệu hoặc lỗi, khởi tạo mới
  const defaultState = createDefaultState(email);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(defaultState));
  return defaultState;
};

export const authenticateUser = async (credentials: { email: string; password: string }) => {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return { success: false, message: 'Hệ thống chưa khởi tạo. Vui lòng đăng ký tài khoản.' };

    const state: AppState = JSON.parse(raw);
    const user = state.users?.find(u => u.email === credentials.email);
    if (user) {
      return { success: true };
    }
    return { success: false, message: 'Email không tồn tại trong hệ thống.' };
  } catch (e) {
    return { success: false, message: 'Lỗi truy cập dữ liệu.' };
  }
};

export const registerUser = async (credentials: { email: string; password: string }) => {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    let state: AppState;

    if (raw) {
      state = JSON.parse(raw);
    } else {
      state = createDefaultState(credentials.email);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
      return { success: true };
    }

    if (state.users.some(u => u.email === credentials.email)) {
      return { success: false, message: 'Email đã được sử dụng.' };
    }

    const newUser: User = {
      id: crypto.randomUUID(),
      email: credentials.email,
      fullName: credentials.email.split('@')[0],
      jobTitle: 'Staff',
      role: state.users.length === 0 ? 'ADMIN' : 'EMPLOYEE'
    };

    state.users.push(newUser);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
    return { success: true };
  } catch (e) {
    return { success: false, message: 'Lỗi đăng ký tài khoản.' };
  }
};

import React, { useState, useMemo } from 'react';
import { User, UserRole, Language, Task, TaskStatus } from '../types';
import { translations } from '../translations';
import { STATUS_LABELS, getCompanyColor } from '../constants';

interface AdminUserModalProps {
  currentUser: User;
  users: User[];
  tasks: Task[]; // Cần truyền tasks vào để lọc
  language: Language;
  onAddUser: (user: User) => void;
  onUpdateUser: (user: User) => void;
  onDeleteUser: (id: string) => void;
  onClose: () => void;
}

const AdminUserModal: React.FC<AdminUserModalProps> = ({ currentUser, users, tasks, language, onAddUser, onUpdateUser, onDeleteUser, onClose }) => {
  const t = translations[language] || translations.vi;
  const [editingUser, setEditingUser] = useState<Partial<User> | null>(null);
  const [selectedUserForTasks, setSelectedUserForTasks] = useState<User | null>(null);
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);

  const roles: UserRole[] = ['ADMIN', 'DEPT_HEAD', 'MANAGER', 'EMPLOYEE'];

  // Logic kiểm tra quyền giám sát (tương tự như App.tsx nhưng áp dụng tại đây)
  const isSupervisorOf = (supervisorId: string, subordinateId: string): boolean => {
    const subordinate = users.find(u => u.id === subordinateId);
    if (!subordinate) return false;
    if (subordinate.reportsTo === supervisorId) return true;
    const supervisor = users.find(u => u.id === supervisorId);
    if (supervisor?.role === 'ADMIN') return true;
    if (supervisor?.role === 'DEPT_HEAD') return subordinate.role !== 'ADMIN';
    if (subordinate.reportsTo) return isSupervisorOf(supervisorId, subordinate.reportsTo);
    return false;
  };

  // Chỉ hiển thị những người mà currentUser có quyền quản lý
  const manageableUsers = useMemo(() => {
    return users.filter(u => u.id === currentUser.id || isSupervisorOf(currentUser.id, u.id));
  }, [users, currentUser]);

  const potentialManagers = useMemo(() => {
    return users.filter(u => u.role !== 'EMPLOYEE');
  }, [users]);

  // Lọc task cho nhân viên được chọn tại ngày được chọn
  const employeeTasksOnDate = useMemo(() => {
    if (!selectedUserForTasks) return [];
    return tasks.filter(tk => 
      tk.userId === selectedUserForTasks.id && 
      tk.createdAt.startsWith(selectedDate) &&
      !tk.deletedAt
    );
  }, [tasks, selectedUserForTasks, selectedDate]);

  const handleSave = () => {
    if (!editingUser?.email || !editingUser?.fullName || !editingUser?.role || !editingUser?.jobTitle) return;

    if (editingUser.id) {
      onUpdateUser(editingUser as User);
    } else {
      onAddUser({
        ...editingUser,
        id: crypto.randomUUID(),
      } as User);
    }
    setEditingUser(null);
  };

