    theme: Theme;
  };
}

import { AppState, User } from '../types';

const STORAGE_KEY = 'zentask_enterprise_db';
const ADMIN_EMAIL = 'tam.agriviet@gmail.com';
const ADMIN_PASS = '123456789';

const createDefaultState = (): AppState => {
  const admin: User = {
    id: 'root-admin',
    email: ADMIN_EMAIL,
    password: ADMIN_PASS,
    fullName: 'Tam Agriviet',
    jobTitle: 'Hệ thống Quản trị',
    role: 'ADMIN',
    mustChangePassword: false
  };

  return {
    currentUser: admin,
    users: [admin],
    tasks: [],
    companies: ["Agriviet"],
    settings: { language: 'vi', theme: 'light' }
  };
};

export const saveStateSecure = async (state: AppState) => {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  } catch (e) {
    console.error("Failed to save state:", e);
  }
};

export const loadStateSecure = async (email: string, password?: string): Promise<AppState> => {
  const raw = localStorage.getItem(STORAGE_KEY);
  let state: AppState;

  if (!raw) {
    state = createDefaultState();
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  } else {
    state = JSON.parse(raw);
  }

  // Tự động thêm admin nếu bị xóa nhầm
  if (!state.users.find(u => u.email === ADMIN_EMAIL)) {
     const root = createDefaultState().users[0];
     state.users.push(root);
  }

  const user = state.users.find(u => u.email === email && u.password === password);
  if (user) {
    return { ...state, currentUser: user };
  }

  throw new Error("Thông tin đăng nhập không chính xác");
};

export const authenticateUser = async (credentials: { email: string; password: string }) => {
  try {
    await loadStateSecure(credentials.email, credentials.password);
    return { success: true };
  } catch (e: any) {
    return { success: false, message: e.message };
  }
};

import React, { useState } from 'react';
import { authenticateUser } from '../services/storageService';

interface LoginProps {
  onLogin: (email: string, pass: string) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const result = await authenticateUser({ email, password });
      if (result.success) {
        onLogin(email, password);
      } else {
        setError(result.message);
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6">
      <div className="w-full max-w-[440px] bg-white p-12 rounded-[3.5rem] shadow-2xl relative overflow-hidden">
