                <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white dark:bg-slate-800 p-6 rounded-[2rem] border border-slate-100 dark:border-slate-800 shadow-sm">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Lịch sử công việc (30 ngày)</label>
                    <input 
                      type="date" 
                      min={minDate} max={maxDate}
                      value={selectedDate}
                      onChange={(e) => setSelectedDate(e.target.value)}
                      className="w-full px-6 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-2xl font-black text-slate-700 dark:text-white text-xs outline-none"
                    />
                  </div>
                  <div className="flex gap-6">
                     <div className="text-center">
                        <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Tổng việc</p>
                        <p className="text-xl font-black text-slate-800 dark:text-white">{employeeTasksOnDate.length}</p>
                     </div>
                     <div className="text-center">
                        <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Đã Xong</p>
                        <p className="text-xl font-black text-emerald-500">{employeeTasksOnDate.filter(t => t.status === TaskStatus.DONE).length}</p>
                     </div>
                  </div>
                </div>

                <div className="space-y-3">
                  {employeeTasksOnDate.length === 0 ? (
                    <div className="py-20 text-center opacity-30 italic font-bold text-slate-400 uppercase tracking-widest">
                      Không có công việc trong ngày này
                    </div>
                  ) : (
                    employeeTasksOnDate.map(task => {
                      const cpColor = getCompanyColor(task.company);
                      const statusLabel = STATUS_LABELS[task.status];
                      return (
                        <div key={task.id} className={`p-5 rounded-3xl border-l-4 bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 flex items-start gap-4 transition-all hover:shadow-md border-l-${cpColor.badge.replace('bg-', '')}`}>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 mb-2">
                               <span className={`text-[8px] font-black px-2 py-1 rounded-lg uppercase tracking-widest ${cpColor.light} ${cpColor.text}`}>
                                  {task.company}
                               </span>
                            </div>
                            <p className={`font-bold text-sm text-slate-800 dark:text-white leading-tight mb-3 ${task.status === TaskStatus.DONE ? 'line-through opacity-40' : ''}`}>
                              {task.content}
                            </p>
                            <div className={`inline-flex px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${statusLabel.color}`}>
                               {statusLabel.label}
                            </div>
                          </div>
                        </div>
                      );
                    })
                  )}
                </div>
              </div>
            )}
          </div>

          <div className="w-full lg:w-96 p-8 bg-slate-50 dark:bg-slate-950/30 flex flex-col gap-6 border-t lg:border-t-0 shrink-0">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em]">{editingUser?.id ? 'CHỈNH SỬA' : 'TẠO MỚI NHÂN SỰ'}</h3>
            <div className="space-y-4">
              <input value={editingUser?.fullName || ''} onChange={e => setEditingUser(p => ({...p, fullName: e.target.value}))} placeholder="Họ và tên" className="w-full p-4 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl outline-none font-bold text-xs" />
              <input value={editingUser?.email || ''} onChange={e => setEditingUser(p => ({...p, email: e.target.value}))} placeholder="Email công ty" className="w-full p-4 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl outline-none font-bold text-xs" />
              <input value={editingUser?.jobTitle || ''} onChange={e => setEditingUser(p => ({...p, jobTitle: e.target.value}))} placeholder="Chức danh" className="w-full p-4 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl outline-none font-bold text-xs" />
              <input type="password" value={editingUser?.password || ''} onChange={e => setEditingUser(p => ({...p, password: e.target.value}))} placeholder="Mật khẩu khởi tạo" className="w-full p-4 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl outline-none font-bold text-xs" />

              <select value={editingUser?.role || ''} onChange={e => setEditingUser(p => ({...p, role: e.target.value as UserRole}))} className="w-full p-4 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl outline-none font-bold text-xs uppercase">
                <option value="">Chọn Vai trò</option>
                {roles.map(r => <option key={r} value={r}>{t[`role_${r}` as keyof typeof t]}</option>)}
              </select>

              <select value={editingUser?.reportsTo || ''} onChange={e => setEditingUser(p => ({...p, reportsTo: e.target.value}))} className="w-full p-4 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl outline-none font-bold text-xs uppercase">
                <option value="">Quản lý trực tiếp</option>
                {potentialManagers.filter(u => u.id !== editingUser?.id).map(u => <option key={u.id} value={u.id}>{u.fullName}</option>)}
              </select>
            </div>
            <div className="pt-4 space-y-3">
              <button onClick={handleSave} className="w-full bg-blue-600 text-white font-black py-4 rounded-2xl shadow-xl uppercase text-[10px] tracking-widest active:scale-95">
                {editingUser?.id ? 'CẬP NHẬT' : 'KHỞI TẠO TÀI KHOẢN'}
              </button>
              {editingUser && (
                <button onClick={() => setEditingUser(null)} className="w-full text-[10px] font-black text-slate-400 uppercase tracking-widest py-2">Hủy</button>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminUserModal;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import TaskItem from './components/TaskItem';
import Login from './components/Login';
import Setup from './components/Setup';
import HistoryModal from './components/HistoryModal';
import ExportModal from './components/ExportModal';
import SettingsModal from './components/SettingsModal';
import ManageCompaniesModal from './components/ManageCompaniesModal';
import AdminUserModal from './components/AdminUserModal';
import { Task, TaskStatus, AppState, User } from './types';
import { loadStateSecure, saveStateSecure } from './services/storageService';
import { translations } from './translations';

const App: React.FC = () => {
  const [state, setState] = useState<AppState | null>(null);
  const [loading, setLoading] = useState(false);
  const [newPassword, setNewPassword] = useState('');
  const [modals, setModals] = useState({
    history: false,
    export: false,
    settings: false,
    manageCompanies: false,
    manageUsers: false,
    delete: null as string | null
  });
  const [currentView, setCurrentView] = useState<'PERSONAL' | 'TEAM'>('PERSONAL');

  const currentLanguage = state?.settings?.language || 'vi';
  const currentTheme = state?.settings?.theme || 'light';
  const t = translations[currentLanguage] || translations.vi;

  useEffect(() => {
    const root = document.documentElement;
    if (currentTheme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
  }, [currentTheme]);

  const handleLogin = async (email: string, pass: string) => {
    setLoading(true);
    try {
      const loaded = await loadStateSecure(email, pass);
      setState(loaded);
    } catch (e: any) { 
      alert(e.message); 
    }
    finally { setLoading(false); }
  };

  const handleChangePassword = () => {
    if (newPassword.length < 6) {
      alert("Mật khẩu mới phải từ 6 ký tự");
      return;
    }
    setState(prev => {
      if (!prev) return null;
      const updatedUser = { ...prev.currentUser, password: newPassword, mustChangePassword: false };
      return {
        ...prev,
        currentUser: updatedUser,
        users: prev.users.map(u => u.id === updatedUser.id ? updatedUser : u)
      };
    });
  };

  const handleLogout = () => setState(null);

  const handleSetupComplete = (fullName: string, jobTitle: string, companies: string[]) => {
    setState(prev => {
      if (!prev) return null;
      const updatedUser = { ...prev.currentUser, fullName, jobTitle };
      return {
        ...prev,
        currentUser: updatedUser,
        users: prev.users.map(u => u.id === updatedUser.id ? updatedUser : u),
        companies: companies
      };
    });
  };

  useEffect(() => {
    if (state && state.currentUser) {
      saveStateSecure(state);
    }
  }, [state]);

  const isSupervisorOf = (supervisorId: string, subordinateId: string): boolean => {
    if (!state) return false;
    const subordinate = state.users.find(u => u.id === subordinateId);
    if (!subordinate) return false;
    if (subordinate.reportsTo === supervisorId) return true;
    const supervisor = state.users.find(u => u.id === supervisorId);
    if (supervisor?.role === 'ADMIN') return true;
    if (supervisor?.role === 'DEPT_HEAD') return subordinate.role !== 'ADMIN';
    if (subordinate.reportsTo) return isSupervisorOf(supervisorId, subordinate.reportsTo);
    return false;
  };

  const filteredTasks = useMemo(() => {
    if (!state) return [];
    if (currentView === 'PERSONAL') {
      return state.tasks.filter(tk => tk.userId === state.currentUser.id && !tk.deletedAt);
    } else {
      return state.tasks.filter(tk => tk.userId !== state.currentUser.id && !tk.deletedAt && isSupervisorOf(state.currentUser.id, tk.userId));
    }
  }, [state, currentView]);

  const stats = useMemo(() => {
    if (!state) return { active: 0, doneToday: 0 };
    const today = new Date().toISOString().split('T')[0];
    const pool = currentView === 'PERSONAL' 
      ? state.tasks.filter(tk => tk.userId === state.currentUser.id)
      : state.tasks.filter(tk => isSupervisorOf(state.currentUser.id, tk.userId));

    return {
      active: pool.filter(tk => !tk.deletedAt && tk.status !== TaskStatus.DONE).length,
      doneToday: pool.filter(tk => !tk.deletedAt && tk.status === TaskStatus.DONE && tk.updatedAt.startsWith(today)).length
    };
  }, [state, currentView]);

  if (!state) return <Login onLogin={handleLogin} />;

  // Màn hình bắt buộc đổi mật khẩu lần đầu
  if (state.currentUser.mustChangePassword) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6">
        <div className="w-full max-w-md bg-white p-12 rounded-[3.5rem] shadow-2xl text-center">
          <div className="w-20 h-20 bg-amber-500 rounded-full flex items-center justify-center text-white text-3xl mx-auto mb-6 shadow-xl shadow-amber-500/20">
            <i className="fas fa-key"></i>
          </div>
          <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tighter mb-2">Đổi mật khẩu</h2>
          <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-8 leading-relaxed">Đây là lần đầu bạn đăng nhập.<br/>Hãy đặt mật khẩu bảo mật mới.</p>
          <input 
            type="password" 
            value={newPassword} 
            onChange={e => setNewPassword(e.target.value)}
            placeholder="Mật khẩu mới..."
            className="w-full px-6 py-5 bg-slate-50 border border-slate-200 rounded-2xl mb-6 font-bold"
          />
          <button onClick={handleChangePassword} className="w-full bg-blue-600 text-white font-black py-6 rounded-2xl shadow-xl uppercase text-xs tracking-widest active:scale-95">Xác nhận thay đổi</button>
        </div>
      </div>
    );
  }

  // Admin có thể bỏ qua setup ban đầu
  const isAdmin = state.currentUser.email === 'tam.agriviet@gmail.com';
  const needsSetup = !state.currentUser.fullName || state.currentUser.fullName === state.currentUser.email.split('@')[0];

  if (needsSetup && !isAdmin) {
    return <Setup onComplete={handleSetupComplete} onLogout={handleLogout} />;
  }

  const canManageUsers = ['ADMIN', 'DEPT_HEAD', 'MANAGER'].includes(state.currentUser.role);
  const canViewTeam = state.currentUser.role !== 'EMPLOYEE';

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-white dark:bg-slate-950 theme-transition">
      <Sidebar 
        currentUser={state.currentUser}
        companies={state.companies}
        language={currentLanguage}
        onAddTask={(content, company, isPriority) => {
          const newTask: Task = {
            id: crypto.randomUUID(),
            userId: state.currentUser.id,
            content, company,
            createdAt: new Date().toISOString(),
            updatedAt: new Date().toISOString(),
            status: TaskStatus.NOT_STARTED,
            isPriority
          };
          setState(prev => prev ? ({ ...prev, tasks: [newTask, ...prev.tasks] }) : null);
        }} 
        onAddCompany={c => setState(p => p ? ({...p, companies: [...p.companies, c]}) : null)}
        onOpenManageCompanies={() => setModals(m => ({...m, manageCompanies: true}))}
        onClearAll={() => {}} 
        onLogout={handleLogout}
        onOpenHistory={() => setModals(m => ({...m, history: true}))}
        onOpenExport={() => setModals(m => ({...m, export: true}))}
        onOpenSettings={() => setModals(m => ({...m, settings: true}))}
        onOpenManageUsers={() => canManageUsers && setModals(m => ({...m, manageUsers: true}))}
      />

      <main className="flex-1 flex flex-col min-w-0 bg-slate-50 dark:bg-slate-950 relative h-screen overflow-hidden theme-transition">
        <header className="min-h-[110px] py-4 px-6 md:px-10 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex flex-col md:flex-row md:items-center justify-between z-10 shadow-sm gap-4 transition-all">
          <div className="flex items-center gap-6">
            <button onClick={() => setCurrentView('PERSONAL')} className={`flex flex-col items-start ${currentView === 'PERSONAL' ? 'opacity-100' : 'opacity-40'}`}>
              <h2 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.currentTasks}</h2>
              <span className="text-[10px] font-black uppercase text-blue-500 tracking-widest">{state.currentUser.fullName}</span>
            </button>
            {canViewTeam && (
              <button onClick={() => setCurrentView('TEAM')} className={`flex flex-col items-start ${currentView === 'TEAM' ? 'opacity-100' : 'opacity-40'}`}>
                <h2 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.teamTasks}</h2>
                <span className="text-[10px] font-black uppercase text-amber-500 tracking-widest">Team Monitor</span>
              </button>
            )}
          </div>

          <div className="flex items-center gap-10">
            <div className="text-right">
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{t.doing}</p>
              <p className="text-2xl font-black text-rose-500 leading-tight">{stats.active}</p>
            </div>
            <div className="text-right">
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{t.doneToday}</p>
              <p className="text-2xl font-black text-emerald-500 leading-tight">{stats.doneToday}</p>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar">
          <div className="max-w-4xl mx-auto space-y-4 pb-24">
            {filteredTasks.map(task => (
              <TaskItem 
                key={task.id} 
                task={task} 
                language={currentLanguage} 
                readOnly={currentView === 'TEAM'}
                onStatusChange={(id, status) => {
                  setState(prev => prev ? ({
                    ...prev,
                    tasks: prev.tasks.map(t => t.id === id ? {...t, status, updatedAt: new Date().toISOString()} : t)
                  }) : null)
                }}
                onDelete={id => setState(p => p ? ({...p, tasks: p.tasks.map(t => t.id === id ? {...t, deletedAt: new Date().toISOString()} : t)}) : null)} 
              />
            ))}
          </div>
        </div>

        {canManageUsers && (
           <div className="absolute bottom-6 left-6">
              <button onClick={() => setModals(m => ({...m, manageUsers: true}))} className="px-6 py-4 bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-3xl shadow-xl flex items-center gap-3 hover:-translate-y-1 transition-all">
                <div className="w-8 h-8 bg-blue-600 rounded-xl flex items-center justify-center text-white"><i className="fas fa-users-cog text-xs"></i></div>
                <span className="text-[10px] font-black uppercase tracking-widest text-slate-600 dark:text-slate-300">Quản trị nhân sự</span>
              </button>
           </div>
        )}
      </main>

      {modals.manageUsers && (
        <AdminUserModal 
          currentUser={state.currentUser}
          users={state.users}
          tasks={state.tasks}
          language={currentLanguage}
          onAddUser={u => setState(p => p ? ({...p, users: [...p.users, u]}) : null)}
          onUpdateUser={u => setState(p => p ? ({...p, users: p.users.map(old => old.id === u.id ? u : old)}) : null)}
          onDeleteUser={id => setState(prev => prev ? ({...prev, users: prev.users.filter(u => u.id !== id)}) : null)}
          onClose={() => setModals(m => ({...m, manageUsers: false}))}
        />
      )}

      {modals.manageCompanies && <ManageCompaniesModal companies={state.companies} language={currentLanguage} onRename={(old, cur) => setState(p => p ? ({...p, companies: p.companies.map(c => c === old ? cur : c), tasks: p.tasks.map(t => t.company === old ? {...t, company: cur} : t)}) : null)} onDelete={c => setState(p => p ? ({...p, companies: p.companies.filter(x => x !== c)}) : null)} onClose={() => setModals(m => ({...m, manageCompanies: false}))} />}
      {modals.settings && <SettingsModal language={currentLanguage} theme={currentTheme} onUpdate={(l, theme) => setState(p => p ? ({...p, settings: {language: l, theme}}) : null)} onClose={() => setModals(m => ({...m, settings: false}))} />}
      {modals.history && <HistoryModal tasks={state.tasks.filter(t => !t.deletedAt && t.userId === state.currentUser.id)} onClose={() => setModals(m => ({...m, history: false}))} />}
      {modals.export && <ExportModal tasks={state.tasks.filter(t => !t.deletedAt)} templates={state.templates || []} onSaveTemplate={tpl => setState(p => p ? ({...p, templates: [...(p.templates || []), tpl]}) : null)} onDeleteTemplate={id => setState(p => p ? ({...p, templates: (p.templates || []).filter(x => x.id !== id)}) : null)} onClose={() => setModals(m => ({...m, export: false}))} />}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Language, User } from '../types';
import { translations } from '../translations';

interface SidebarProps {
  currentUser: User;
  managerName?: string;
  companies: string[];
  language: Language;
  onAddTask: (content: string, company: string, isPriority: boolean) => void;
  onAddCompany: (company: string) => void;
  onOpenManageCompanies: () => void;
  onClearAll: () => void;
  onLogout: () => void;
  onOpenHistory: () => void;
  onOpenExport: () => void;
  onOpenSettings: () => void;
  onOpenManageUsers: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  currentUser, managerName, companies, language, onAddTask, onAddCompany, onOpenManageCompanies, onClearAll, onLogout, onOpenHistory, onOpenExport, onOpenSettings, onOpenManageUsers
}) => {
  const [content, setContent] = useState('');
  const [selectedCompany, setSelectedCompany] = useState(companies[0] || '');
  const [isPriority, setIsPriority] = useState(false);

  const t = translations[language] || translations.vi;
  const isRootAdmin = currentUser.email === 'tam.agriviet@gmail.com';

  const handleSubmitTask = (e: React.FormEvent) => {
    e.preventDefault();
    if (!content.trim() || !selectedCompany) return;
    onAddTask(content, selectedCompany, isPriority);
    setContent('');
    setIsPriority(false);
  };

  return (
    <div className="w-[320px] md:w-[380px] bg-white dark:bg-slate-950 h-full flex flex-col p-8 md:p-10 flex-shrink-0 border-r border-slate-100 dark:border-slate-800 shadow-2xl md:shadow-none overflow-y-auto custom-scrollbar transition-colors">
      <div className="mb-10 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-blue-600 rounded-[1.2rem] flex items-center justify-center text-white shadow-xl shadow-blue-500/20"><i className="fas fa-shield-halved text-xl"></i></div>
          <div>
            <h1 className="text-xl font-black text-slate-800 dark:text-white tracking-tighter leading-tight uppercase">{t.appName}</h1>
            <p className="text-[10px] font-black text-blue-500 uppercase tracking-widest">{isRootAdmin ? t.systemAdmin : 'Enterprise Edition'}</p>
          </div>
        </div>
        <button onClick={onLogout} className="w-10 h-10 rounded-xl bg-slate-50 dark:bg-slate-900 text-slate-400 hover:text-rose-500 transition-all border border-slate-100 dark:border-slate-800"><i className="fas fa-power-off"></i></button>
      </div>

      <div className="mb-10 p-5 bg-slate-50 dark:bg-slate-900/50 rounded-3xl border border-slate-100 dark:border-slate-800 space-y-3">
        <div>
          <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{t.fullName}</p>
          <p className="font-black text-slate-800 dark:text-white text-sm">{currentUser.fullName}</p>
          <p className="text-[10px] font-bold text-blue-600 dark:text-blue-400 uppercase">{currentUser.jobTitle}</p>
        </div>
        {managerName && !isRootAdmin && (
          <div className="pt-3 border-t border-slate-100 dark:border-slate-800">
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{t.directManager}</p>
            <div className="flex items-center gap-2 mt-1">
              <div className="w-5 h-5 bg-indigo-500 rounded-full flex items-center justify-center text-[8px] text-white"><i className="fas fa-user-tie"></i></div>
              <p className="font-bold text-slate-700 dark:text-slate-300 text-xs">{managerName}</p>
            </div>
          </div>
        )}
      </div>

      {!isRootAdmin ? (
        <>
          <div className="grid grid-cols-2 gap-3 mb-8">
            <button onClick={onOpenHistory} className="p-4 rounded-2xl bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 border border-indigo-100 dark:border-indigo-800 flex flex-col items-center gap-2 hover:scale-105 transition-all">
              <i className="fas fa-chart-line"></i>
              <span className="text-[9px] font-black uppercase tracking-widest">{t.history}</span>
            </button>
            <button onClick={onOpenExport} className="p-4 rounded-2xl bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400 border border-emerald-100 dark:border-emerald-800 flex flex-col items-center gap-2 hover:scale-105 transition-all">
              <i className="fas fa-file-invoice"></i>
              <span className="text-[9px] font-black uppercase tracking-widest">{t.report}</span>
            </button>
          </div>

          <div className="flex-1">
            <form onSubmit={handleSubmitTask} className="space-y-6">
              <div className="space-y-2">
                <div className="flex items-center justify-between px-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{t.company}</label>
                  <button type="button" onClick={onOpenManageCompanies} className="text-[10px] font-black text-blue-500 hover:text-blue-700 uppercase tracking-widest">{t.manage}</button>
                </div>
