                  <h2 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.currentTasks}</h2>
                  <span className="text-[10px] font-black uppercase text-blue-500 tracking-widest">{state.currentUser.fullName}</span>
                </button>
                {state.currentUser.role !== 'EMPLOYEE' && (
                  <button onClick={() => { setCurrentView('TEAM'); setSelectedTeamMember(null); }} className={`flex flex-col items-start transition-all ${currentView === 'TEAM' ? 'opacity-100 scale-105' : 'opacity-30 hover:opacity-50'}`}>
                    <h2 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.teamTasks}</h2>
                    <span className="text-[10px] font-black uppercase text-amber-500 tracking-widest">Team Monitor</span>
                  </button>
                )}
              </div>

              <div className="flex items-center gap-8 md:gap-10">
                <div className="text-right">
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{t.doing}</p>
                  <p className="text-xl md:text-2xl font-black text-rose-500 leading-none">{stats.active}</p>
                </div>
                <div className="text-right">
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{t.doneToday}</p>
                  <p className="text-xl md:text-2xl font-black text-emerald-500 leading-none">{stats.doneToday}</p>
                </div>
              </div>
            </header>

            <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar">
              <div className="max-w-6xl mx-auto pb-24">
                {currentView === 'TEAM' && !selectedTeamMember ? (
                  /* MÀN HÌNH TÓM TẮT ĐỘI NGŨ */
                  <TeamSummary 
                    subordinates={subordinates}
                    tasks={state.tasks}
                    language={currentLanguage}
                    onSelectUser={setSelectedTeamMember}
                  />
                ) : (
                  /* MÀN HÌNH CHI TIẾT CÔNG VIỆC */
                  <div className="max-w-4xl mx-auto space-y-4">
                    {selectedTeamMember && (
                      <div className="mb-8 flex items-center justify-between bg-white dark:bg-slate-900 p-6 rounded-[2rem] border border-slate-100 dark:border-slate-800 shadow-sm animate-in fade-in zoom-in-95 duration-300">
                         <div className="flex items-center gap-4">
                            <div className="w-12 h-12 rounded-2xl bg-blue-600 flex items-center justify-center text-white font-black">{selectedTeamMember.fullName.charAt(0)}</div>
                            <div>
                               <h3 className="font-black text-slate-800 dark:text-white uppercase text-sm">{selectedTeamMember.fullName}</h3>
                               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{selectedTeamMember.jobTitle}</p>
                            </div>
                         </div>
                         <button 
                           onClick={() => setSelectedTeamMember(null)}
                           className="px-6 py-2 bg-slate-100 dark:bg-slate-800 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-200 transition-all"
                         >
                           <i className="fas fa-arrow-left mr-2"></i> Quay lại
                         </button>
                      </div>
                    )}

                    {filteredTasks.length === 0 ? (
                      <div className="py-20 text-center opacity-30 italic font-bold text-slate-400 uppercase tracking-[0.2em]">
                        {t.noTasks}
                      </div>
                    ) : (
                      filteredTasks.map(task => (
                        <TaskItem 
                          key={task.id} 
                          task={task} 
                          language={currentLanguage} 
                          readOnly={currentView === 'TEAM'}
                          onStatusChange={(id, status) => setState(p => p ? ({...p, tasks: p.tasks.map(t => t.id === id ? {...t, status, updatedAt: new Date().toISOString()} : t)}) : null)}
                          onDelete={id => setState(p => p ? ({...p, tasks: p.tasks.map(t => t.id === id ? {...t, deletedAt: new Date().toISOString()} : t)}) : null)} 
                        />
                      ))
                    )}
                  </div>
                )}
              </div>
            </div>
          </>
        )}
      </main>

      {modals.manageUsers && (
        <AdminUserModal 
          currentUser={state.currentUser}
          users={state.users}
          tasks={state.tasks}
          language={currentLanguage}
          onAddUser={u => setState(p => p ? ({...p, users: [...p.users, u]}) : null)}
          onUpdateUser={u => setState(p => p ? ({...p, users: p.users.map(old => old.id === u.id ? u : old)}) : null)}
          onDeleteUser={id => setState(prev => prev ? ({...prev, users: prev.users.filter(u => u.id !== id)}) : null)}
          onClose={() => setModals(m => ({...m, manageUsers: false, userToEdit: null, userToView: null}))}
        />
      )}

      {modals.settings && <SettingsModal language={currentLanguage} theme={currentTheme} onUpdate={(l, theme) => setState(p => p ? ({...p, settings: {language: l, theme}}) : null)} onClose={() => setModals(m => ({...m, settings: false}))} />}
      {modals.manageCompanies && <ManageCompaniesModal companies={state.companies} language={currentLanguage} onRename={(o, n) => setState(p => p ? ({...p, companies: p.companies.map(c => c === o ? n : c), tasks: p.tasks.map(t => t.company === o ? {...t, company: n} : t)}) : null)} onDelete={c => setState(p => p ? ({...p, companies: p.companies.filter(x => x !== c)}) : null)} onClose={() => setModals(m => ({...m, manageCompanies: false}))} />}
      {modals.history && <HistoryModal tasks={state.tasks.filter(t => !t.deletedAt && t.userId === state.currentUser.id)} onClose={() => setModals(m => ({...m, history: false}))} />}
      {modals.export && <ExportModal tasks={state.tasks.filter(t => !t.deletedAt)} templates={state.templates || []} onSaveTemplate={tpl => setState(p => p ? ({...p, templates: [...(p.templates || []), tpl]}) : null)} onDeleteTemplate={id => setState(p => p ? ({...p, templates: (p.templates || []).filter(x => x.id !== id)}) : null)} onClose={() => setModals(m => ({...m, export: false}))} />}
    </div>
  );
};

export default App;

import React, { useMemo } from 'react';
import { User, Language, Task } from '../types';
import { translations } from '../translations';

interface AdminDashboardProps {
  users: User[];
  tasks: Task[];
  language: Language;
  onSelectUser: (user: User) => void;
  onEditUser: (user: User) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ users, tasks, language, onSelectUser, onEditUser }) => {
  const t = translations[language] || translations.vi;

  // Xây dựng cây phân cấp
  const hierarchy = useMemo(() => {
    const userMap: Record<string, User[]> = {};
    users.forEach(u => {
      const parentId = u.reportsTo || 'root';
      if (!userMap[parentId]) userMap[parentId] = [];
      userMap[parentId].push(u);
    });
    return userMap;
  }, [users]);

  const renderNode = (parentId: string, level: number = 0) => {
    const children = hierarchy[parentId] || [];
    if (children.length === 0) return null;

    return (
      <div className={`flex flex-col gap-6 ${level > 0 ? 'ml-8 md:ml-12 border-l-2 border-slate-100 dark:border-slate-800 pl-8 md:pl-12' : ''}`}>
        {children.map(user => {
          // Ẩn chính người quản trị (Email root) khỏi sơ đồ nếu đang ở cấp cao nhất
          if (user.email === 'tam.agriviet@gmail.com') {
             return null;
          }

          const roleColors = {
            ADMIN: 'bg-rose-500 border-rose-200 text-rose-500',
            DEPT_HEAD: 'bg-amber-500 border-amber-200 text-amber-500',
            MANAGER: 'bg-indigo-500 border-indigo-200 text-indigo-500',
            EMPLOYEE: 'bg-slate-400 border-slate-200 text-slate-400'
          };

          const userTasksCount = tasks.filter(tk => tk.userId === user.id && !tk.deletedAt).length;

          return (
            <div key={user.id} className="relative">
              <div className="flex items-center gap-4 group">
                {/* Node Card */}
                <div className="bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 p-4 rounded-[1.8rem] shadow-sm flex items-center gap-4 min-w-[280px] hover:shadow-xl hover:border-blue-500 transition-all">
                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-white shadow-lg ${roleColors[user.role].split(' ')[0]}`}>
                    {user.fullName.charAt(0)}
                  </div>
                  <div className="flex-1 min-w-0">
                    <h4 className="font-black text-slate-800 dark:text-white text-xs uppercase truncate tracking-tight">{user.fullName}</h4>
                    <p className="text-[9px] font-bold text-blue-500 uppercase tracking-tighter truncate">{user.jobTitle}</p>
                  </div>
                  <div className="flex items-center gap-2 pr-2">
                     <button onClick={() => onSelectUser(user)} className="w-8 h-8 bg-slate-50 dark:bg-slate-800 text-slate-400 hover:text-blue-500 rounded-lg flex items-center justify-center transition-all">
                        <i className="fas fa-eye text-[10px]"></i>
                     </button>
                     <button onClick={() => onEditUser(user)} className="w-8 h-8 bg-slate-50 dark:bg-slate-800 text-slate-400 hover:text-amber-500 rounded-lg flex items-center justify-center transition-all">
                        <i className="fas fa-pen text-[10px]"></i>
                     </button>
                  </div>
                </div>

                {/* Badge thông tin công việc */}
                <div className="px-3 py-1 bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-full text-[9px] font-black text-slate-400">
                  {userTasksCount} TASKS
                </div>
              </div>

              {/* Render con đệ quy */}
              {renderNode(user.id, level + 1)}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="p-6 md:p-12 h-full overflow-auto custom-scrollbar bg-slate-50/50 dark:bg-slate-950/50">
      <div className="max-w-6xl mx-auto space-y-12 pb-20">
        <header className="flex items-center justify-between">
          <div>
            <h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tighter uppercase">{t.orgChart}</h2>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em] mt-2">{users.length - 1} THÀNH VIÊN TRONG HỆ THỐNG</p>
          </div>
          <div className="flex gap-4">
             <div className="px-6 py-4 bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-2xl flex items-center gap-3">
                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                <span className="text-[10px] font-black text-slate-600 dark:text-slate-400 uppercase tracking-widest">Hệ thống đang vận hành</span>
             </div>
          </div>
        </header>

        <div className="relative pt-8">
           {/* Không render nút root, chỉ render bắt đầu từ con của root-admin */}
           {renderNode('root-admin', 0)}
           {/* Dự phòng nếu có user không thuộc root-admin nhưng không phải admin gốc */}
           {renderNode('root', 0)}
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import TaskItem from './components/TaskItem';
import Login from './components/Login';
import Setup from './components/Setup';
import HistoryModal from './components/HistoryModal';
import ExportModal from './components/ExportModal';
import SettingsModal from './components/SettingsModal';
import ManageCompaniesModal from './components/ManageCompaniesModal';
import AdminUserModal from './components/AdminUserModal';
import AdminDashboard from './components/AdminDashboard';
import TeamSummary from './components/TeamSummary';
import { Task, TaskStatus, AppState, User, UserRole } from './types';
import { loadStateSecure, saveStateSecure } from './services/storageService';
import { translations } from './translations';

const App: React.FC = () => {
  const [state, setState] = useState<AppState | null>(null);
  const [loading, setLoading] = useState(false);
  const [newPassword, setNewPassword] = useState('');
  const [modals, setModals] = useState({
    history: false,
    export: false,
    settings: false,
    manageCompanies: false,
    manageUsers: false,
    userToEdit: null as User | null,
    userToView: null as User | null,
  });
  const [currentView, setCurrentView] = useState<'PERSONAL' | 'TEAM'>('PERSONAL');
  const [selectedTeamMember, setSelectedTeamMember] = useState<User | null>(null);

  const currentLanguage = state?.settings?.language || 'vi';
  const currentTheme = state?.settings?.theme || 'light';
  const t = translations[currentLanguage] || translations.vi;
  const isRootAdmin = state?.currentUser?.email === 'tam.agriviet@gmail.com';

  useEffect(() => {
    const root = document.documentElement;
    if (currentTheme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
  }, [currentTheme]);

  const handleLogin = async (email: string, pass: string) => {
    setLoading(true);
    try {
      const loaded = await loadStateSecure(email, pass);
      setState(loaded);
    } catch (e: any) { 
      alert(e.message); 
    }
    finally { setLoading(false); }
  };

  const handleLogout = () => {
    setState(null);
    setCurrentView('PERSONAL');
    setSelectedTeamMember(null);
  };

  useEffect(() => {
    if (state && state.currentUser) saveStateSecure(state);
  }, [state]);

  const isSupervisorOf = (supervisorId: string, subordinateId: string): boolean => {
    if (!state) return false;
    const subordinate = state.users.find(u => u.id === subordinateId);
    if (!subordinate) return false;
    if (subordinate.reportsTo === supervisorId) return true;
    const supervisor = state.users.find(u => u.id === supervisorId);
    if (supervisor?.role === 'ADMIN') return true;
    if (supervisor?.role === 'DEPT_HEAD') return subordinate.role !== 'ADMIN';
    if (subordinate.reportsTo) return isSupervisorOf(supervisorId, subordinate.reportsTo);
    return false;
  };

  const subordinates = useMemo(() => {
    if (!state) return [];
    return state.users.filter(u => u.id !== state.currentUser.id && isSupervisorOf(state.currentUser.id, u.id));
  }, [state]);

  const filteredTasks = useMemo(() => {
    if (!state) return [];
    let baseTasks: Task[] = [];
    if (currentView === 'PERSONAL') {
      baseTasks = state.tasks.filter(tk => tk.userId === state.currentUser.id && !tk.deletedAt);
    } else if (selectedTeamMember) {
      baseTasks = state.tasks.filter(tk => tk.userId === selectedTeamMember.id && !tk.deletedAt);
    }

    // Sắp xếp: Ưu tiên việc gấp (isPriority), sau đó đến thời gian tạo (mới nhất lên đầu)
    return baseTasks.sort((a, b) => {
      if (a.isPriority !== b.isPriority) return a.isPriority ? -1 : 1;
      return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
    });
  }, [state, currentView, selectedTeamMember]);

  const stats = useMemo(() => {
    if (!state) return { active: 0, doneToday: 0 };
    const today = new Date().toISOString().split('T')[0];
    const pool = currentView === 'PERSONAL' 
      ? state.tasks.filter(tk => tk.userId === state.currentUser.id)
      : (selectedTeamMember 
          ? state.tasks.filter(tk => tk.userId === selectedTeamMember.id)
          : state.tasks.filter(tk => isSupervisorOf(state.currentUser.id, tk.userId))
        );

    return {
      active: pool.filter(tk => !tk.deletedAt && tk.status !== TaskStatus.DONE).length,
      doneToday: pool.filter(tk => !tk.deletedAt && tk.status === TaskStatus.DONE && tk.updatedAt.startsWith(today)).length
    };
  }, [state, currentView, selectedTeamMember]);

  if (!state) return <Login onLogin={handleLogin} />;

  if (state.currentUser.mustChangePassword) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6">
        <div className="w-full max-w-md bg-white p-12 rounded-[3.5rem] shadow-2xl text-center">
          <div className="w-20 h-20 bg-amber-500 rounded-full flex items-center justify-center text-white text-3xl mx-auto mb-6"><i className="fas fa-key"></i></div>
          <h2 className="text-2xl font-black text-slate-800 uppercase mb-8">Đổi mật khẩu lần đầu</h2>
          <input type="password" value={newPassword} onChange={e => setNewPassword(e.target.value)} placeholder="Mật khẩu mới..." className="w-full px-6 py-5 bg-slate-50 border rounded-2xl mb-6 font-bold text-center" />
          <button onClick={() => {
             if(newPassword.length < 6) return alert("Mật khẩu tối thiểu 6 ký tự");
             setState(p => p ? ({...p, currentUser: {...p.currentUser, password: newPassword, mustChangePassword: false}, users: p.users.map(u => u.id === p.currentUser.id ? {...u, password: newPassword, mustChangePassword: false} : u)}) : null);
          }} className="w-full bg-blue-600 text-white font-black py-6 rounded-2xl shadow-xl uppercase">Cập nhật mật khẩu</button>
        </div>
      </div>
    );
  }

  // Chỉnh sửa logic NeedsSetup: Luôn yêu cầu nếu chưa có công ty hoặc chưa điền đủ họ tên
  const needsSetup = !isRootAdmin && (!state.currentUser.fullName || state.currentUser.fullName === state.currentUser.email.split('@')[0] || state.companies.length === 0);
  if (needsSetup) {
    return <Setup onComplete={(f, j, c) => setState(p => p ? ({...p, currentUser: {...p.currentUser, fullName: f, jobTitle: j}, users: p.users.map(u => u.id === p.currentUser.id ? {...u, fullName: f, jobTitle: j} : u), companies: c}) : null)} onLogout={handleLogout} />;
  }

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-white dark:bg-slate-950 theme-transition">
      <Sidebar 
        currentUser={state.currentUser}
        companies={state.companies}
        language={currentLanguage}
        onAddTask={(content, company, isPriority) => {
          const newTask: Task = { id: crypto.randomUUID(), userId: state.currentUser.id, content, company, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString(), status: TaskStatus.NOT_STARTED, isPriority };
          setState(prev => prev ? ({ ...prev, tasks: [newTask, ...prev.tasks] }) : null);
        }} 
        onAddCompany={c => setState(p => p ? ({...p, companies: [...p.companies, c]}) : null)}
        onOpenManageCompanies={() => setModals(m => ({...m, manageCompanies: true}))}
        onClearAll={() => {}} 
        onLogout={handleLogout}
        onOpenHistory={() => setModals(m => ({...m, history: true}))}
        onOpenExport={() => setModals(m => ({...m, export: true}))}
        onOpenSettings={() => setModals(m => ({...m, settings: true}))}
        onOpenManageUsers={() => setModals(m => ({...m, manageUsers: true}))}
      />

      <main className="flex-1 flex flex-col min-w-0 bg-slate-50 dark:bg-slate-950 relative h-screen overflow-hidden theme-transition">
        {isRootAdmin ? (
          <AdminDashboard 
            users={state.users} 
            tasks={state.tasks} 
            language={currentLanguage}
            onSelectUser={u => setModals(m => ({...m, manageUsers: true, userToView: u}))}
            onEditUser={u => setModals(m => ({...m, manageUsers: true, userToEdit: u}))}
          />
        ) : (
          <>
            <header className="min-h-[110px] py-4 px-6 md:px-10 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between z-10 shadow-sm transition-all">
              <div className="flex items-center gap-6">
                <button onClick={() => { setCurrentView('PERSONAL'); setSelectedTeamMember(null); }} className={`flex flex-col items-start transition-all ${currentView === 'PERSONAL' ? 'opacity-100 scale-105' : 'opacity-30 hover:opacity-50'}`}>
                  <h2 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.currentTasks}</h2>
                  <span className="text-[10px] font-black uppercase text-blue-500 tracking-widest">{state.currentUser.fullName}</span>
                </button>
                {state.currentUser.role !== 'EMPLOYEE' && (
                  <button onClick={() => { setCurrentView('TEAM'); setSelectedTeamMember(null); }} className={`flex flex-col items-start transition-all ${currentView === 'TEAM' ? 'opacity-100 scale-105' : 'opacity-30 hover:opacity-50'}`}>
                    <h2 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.teamTasks}</h2>
                    <span className="text-[10px] font-black uppercase text-amber-500 tracking-widest">Team Monitor</span>
                  </button>
                )}
              </div>

              <div className="flex items-center gap-8 md:gap-10">
                <div className="text-right">
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{t.doing}</p>
                  <p className="text-xl md:text-2xl font-black text-rose-500 leading-none">{stats.active}</p>
                </div>
                <div className="text-right">
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{t.doneToday}</p>
                  <p className="text-xl md:text-2xl font-black text-emerald-500 leading-none">{stats.doneToday}</p>
                </div>
              </div>
            </header>

            <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar">
              <div className="max-w-6xl mx-auto pb-24">
                {currentView === 'TEAM' && !selectedTeamMember ? (
                  <TeamSummary 
                    subordinates={subordinates}
                    tasks={state.tasks}
                    language={currentLanguage}
                    onSelectUser={setSelectedTeamMember}
                  />
                ) : (
                  <div className="max-w-4xl mx-auto space-y-4">
                    {selectedTeamMember && (
                      <div className="mb-8 flex items-center justify-between bg-white dark:bg-slate-900 p-6 rounded-[2rem] border border-slate-100 dark:border-slate-800 shadow-sm">
                         <div className="flex items-center gap-4">
                            <div className="w-12 h-12 rounded-2xl bg-blue-600 flex items-center justify-center text-white font-black">{selectedTeamMember.fullName.charAt(0)}</div>
                            <div>
                               <h3 className="font-black text-slate-800 dark:text-white uppercase text-sm">{selectedTeamMember.fullName}</h3>
                               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{selectedTeamMember.jobTitle}</p>
                            </div>
                         </div>
                         <button 
                           onClick={() => setSelectedTeamMember(null)}
                           className="px-6 py-2 bg-slate-100 dark:bg-slate-800 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-200 transition-all"
                         >
                           <i className="fas fa-arrow-left mr-2"></i> Quay lại
                         </button>
                      </div>
                    )}

                    {filteredTasks.length === 0 ? (
                      <div className="py-20 text-center opacity-30 italic font-bold text-slate-400 uppercase tracking-[0.2em]">
                        {t.noTasks}
                      </div>
                    ) : (
                      filteredTasks.map(task => (
                        <TaskItem 
                          key={task.id} 
                          task={task} 
                          language={currentLanguage} 
                          readOnly={currentView === 'TEAM'}
                          onStatusChange={(id, status) => setState(p => p ? ({...p, tasks: p.tasks.map(t => t.id === id ? {...t, status, updatedAt: new Date().toISOString()} : t)}) : null)}
                          onDelete={id => setState(p => p ? ({...p, tasks: p.tasks.map(t => t.id === id ? {...t, deletedAt: new Date().toISOString()} : t)}) : null)} 
                        />
                      ))
                    )}
                  </div>
                )}
              </div>
            </div>
          </>
        )}
      </main>

      {modals.manageUsers && (
        <AdminUserModal 
          currentUser={state.currentUser}
          users={state.users}
          tasks={state.tasks}
          language={currentLanguage}
          onAddUser={u => setState(p => p ? ({...p, users: [...p.users, u]}) : null)}
          onUpdateUser={u => setState(p => p ? ({...p, users: p.users.map(old => old.id === u.id ? u : old)}) : null)}
          onDeleteUser={id => setState(prev => prev ? ({...prev, users: prev.users.filter(u => u.id !== id)}) : null)}
          onClose={() => setModals(m => ({...m, manageUsers: false, userToEdit: null, userToView: null}))}
        />
      )}

      {modals.settings && <SettingsModal language={currentLanguage} theme={currentTheme} onUpdate={(l, theme) => setState(p => p ? ({...p, settings: {language: l, theme}}) : null)} onClose={() => setModals(m => ({...m, settings: false}))} />}
      {modals.manageCompanies && <ManageCompaniesModal companies={state.companies} language={currentLanguage} onRename={(o, n) => setState(p => p ? ({...p, companies: p.companies.map(c => c === o ? n : c), tasks: p.tasks.map(t => t.company === o ? {...t, company: n} : t)}) : null)} onDelete={c => setState(p => p ? ({...p, companies: p.companies.filter(x => x !== c)}) : null)} onClose={() => setModals(m => ({...m, manageCompanies: false}))} />}
      {modals.history && <HistoryModal tasks={state.tasks.filter(t => !t.deletedAt && t.userId === state.currentUser.id)} onClose={() => setModals(m => ({...m, history: false}))} />}
      {modals.export && <ExportModal tasks={state.tasks.filter(t => !t.deletedAt)} templates={state.templates || []} onSaveTemplate={tpl => setState(p => p ? ({...p, templates: [...(p.templates || []), tpl]}) : null)} onDeleteTemplate={id => setState(p => p ? ({...p, templates: (p.templates || []).filter(x => x.id !== id)}) : null)} onClose={() => setModals(m => ({...m, export: false}))} />}
    </div>
  );
};

export default App;

import React from 'react';
import { Task, TaskStatus, Language } from '../types';
import { STATUS_LABELS, getCompanyColor } from '../constants';
import { translations } from '../translations';

interface TaskItemProps {
  task: Task;
  language: Language;
  onStatusChange?: (id: string, status: TaskStatus) => void;
  onDelete?: (id: string) => void;
  readOnly?: boolean;
}

const TaskItem: React.FC<TaskItemProps> = ({ task, language, onStatusChange, onDelete, readOnly = false }) => {
  const t = translations[language] || translations.vi;
  const formattedTime = new Date(task.createdAt).toLocaleTimeString(language, { hour: '2-digit', minute: '2-digit' });
  const cpColor = getCompanyColor(task.company);
  const isDone = task.status === TaskStatus.DONE;
  const isInProgress = task.status === TaskStatus.IN_PROGRESS;

  return (
    <div className={`group p-4 md:p-6 rounded-[1.2rem] md:rounded-[1.5rem] border-l-[6px] border-t border-r border-b transition-all flex flex-col items-start gap-4 md:gap-6 ${
      isDone ? 'opacity-50 bg-slate-50 dark:bg-slate-900/50 border-slate-200 dark:border-slate-800' : 
      task.isPriority ? 'bg-rose-50/70 dark:bg-rose-950/20 border-rose-200 dark:border-rose-900 border-l-rose-500' : 
      `${cpColor.bg} dark:bg-slate-900/40 ${cpColor.border} dark:border-slate-800 border-l-${cpColor.badge.replace('bg-', '')}`
    } ${!isDone && !readOnly && 'hover:shadow-lg active:scale-[0.99]'}`}>

      <div className="w-full min-w-0">
        <div className="flex items-center gap-2 mb-3 flex-wrap">
          {isInProgress && (
            <span className="flex items-center gap-1.5 text-[8px] md:text-[9px] font-black px-2.5 py-1 rounded-full bg-blue-600 text-white uppercase tracking-widest animate-pulse">
              <i className="fas fa-spinner fa-spin text-[8px]"></i> {t.IN_PROGRESS}
            </span>
          )}
          {task.isPriority && (
            <span className="flex items-center gap-1.5 text-[8px] md:text-[9px] font-black px-2.5 py-1 rounded-full bg-rose-600 text-white uppercase tracking-widest shadow-sm">
              <i className="fas fa-bolt text-[8px]"></i> {t.isPriority}
            </span>
          )}
          <span className={`text-[9px] md:text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest ${
            task.isPriority ? 'bg-rose-100 dark:bg-rose-900/40 text-rose-700 dark:text-rose-400' : `${cpColor.light} dark:bg-slate-800 ${cpColor.text}`
          }`}>
            {task.company}
          </span>
          <span className="text-[10px] text-slate-400 font-bold uppercase tracking-tight ml-auto">
            <i className="far fa-clock mr-1"></i> {formattedTime}
          </span>
        </div>
        <p className={`text-slate-800 dark:text-white font-bold text-base md:text-lg leading-snug break-words ${isDone ? 'line-through opacity-40 text-slate-400' : ''}`}>
          {task.content}
        </p>
      </div>

      {!readOnly && (
        <div className="flex items-center justify-between w-full mt-2 md:mt-0">
          <div className={`flex p-1.5 rounded-2xl border bg-white/80 dark:bg-slate-950/80 backdrop-blur-sm ${task.isPriority ? 'border-rose-100 dark:border-rose-900' : cpColor.border + ' dark:border-slate-800'}`}>
            {/* Rút gọn chỉ còn 2 trạng thái: Đang làm và Đã xong */}
            {[TaskStatus.IN_PROGRESS, TaskStatus.DONE].map((status) => (
              <button
                key={status}
                onClick={() => onStatusChange?.(task.id, status)}
                className={`px-5 py-2.5 rounded-xl text-[9px] md:text-[11px] font-black uppercase tracking-widest transition-all ${
                  task.status === status
                    ? STATUS_LABELS[status].color + " shadow-md scale-105"
                    : 'text-slate-400 hover:text-slate-600 dark:text-slate-500'
                }`}
              >
                {t[status === 'IN_PROGRESS' ? 'IN_PROGRESS' : 'DONE']}
              </button>
            ))}
          </div>
          <button
            onClick={() => onDelete?.(task.id)}
            className="w-10 h-10 rounded-xl flex items-center justify-center text-slate-300 dark:text-slate-600 hover:text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-950/30 transition-all"
          >
            <i className="fas fa-trash-alt"></i>
          </button>
        </div>
      )}
    </div>
  );
};

export default TaskItem;

import React, { useMemo } from 'react';
import { User, Language, Task } from '../types';
import { translations } from '../translations';

interface AdminDashboardProps {
  users: User[];
  tasks: Task[];
  language: Language;
  onSelectUser: (user: User) => void;
  onEditUser: (user: User) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ users, tasks, language, onSelectUser, onEditUser }) => {
  const t = translations[language] || translations.vi;

  // Xây dựng cây phân cấp
  const hierarchy = useMemo(() => {
    const userMap: Record<string, User[]> = {};
    users.forEach(u => {
      const parentId = u.reportsTo || 'root';
      if (!userMap[parentId]) userMap[parentId] = [];
      userMap[parentId].push(u);
    });
    return userMap;
  }, [users]);

  const renderNode = (parentId: string, level: number = 0) => {
    const children = hierarchy[parentId] || [];
    if (children.length === 0) return null;

    return (
      <div className={`flex flex-col gap-8 ${level > 0 ? 'ml-12 md:ml-20 border-l-4 border-slate-100 dark:border-slate-800 pl-12 md:pl-20' : ''}`}>
        {children.map(user => {
          if (user.email === 'tam.agriviet@gmail.com') return null;

          // Cấu hình màu sắc đặc trưng cho từng cấp bậc
          const roleStyles = {
            ADMIN: 'bg-rose-600 border-rose-200 text-rose-600 shadow-rose-500/10',
            DEPT_HEAD: 'bg-amber-500 border-amber-200 text-amber-600 shadow-amber-500/10',
            MANAGER: 'bg-indigo-600 border-indigo-200 text-indigo-600 shadow-indigo-500/10',
            EMPLOYEE: 'bg-slate-500 border-slate-200 text-slate-500 shadow-slate-500/10'
          };

          const currentStyle = roleStyles[user.role];
          const userTasksCount = tasks.filter(tk => tk.userId === user.id && !tk.deletedAt).length;

          return (
            <div key={user.id} className="relative animate-in slide-in-from-left-8 duration-500">
              <div className="flex items-center gap-6 group">
                {/* Node Card với màu sắc cấp bậc */}
                <div className={`bg-white dark:bg-slate-900 border-2 border-l-[10px] p-5 rounded-[2rem] shadow-xl flex items-center gap-5 min-w-[320px] hover:-translate-y-1 transition-all ${currentStyle.split(' ')[1]} ${currentStyle.replace('bg-', 'border-l-')}`}>
                  <div className={`w-16 h-16 rounded-[1.5rem] flex items-center justify-center font-black text-white text-xl shadow-lg ${currentStyle.split(' ')[0]}`}>
                    {user.fullName.charAt(0)}
                  </div>
                  <div className="flex-1 min-w-0">
                    <h4 className="font-black text-slate-800 dark:text-white text-sm uppercase truncate tracking-tight">{user.fullName}</h4>
                    <p className={`text-[10px] font-black uppercase tracking-widest mt-0.5 ${currentStyle.split(' ')[2]}`}>
                      {user.jobTitle}
                    </p>
                    <span className="text-[8px] font-black px-2 py-0.5 rounded bg-slate-100 dark:bg-slate-800 text-slate-400 mt-2 inline-block">
                      {t[`role_${user.role}` as keyof typeof t]}
                    </span>
                  </div>
                  <div className="flex flex-col gap-2">
                     <button onClick={() => onSelectUser(user)} className="w-10 h-10 bg-slate-50 dark:bg-slate-800 text-slate-400 hover:text-blue-500 rounded-xl flex items-center justify-center transition-all border border-slate-100 dark:border-slate-800">
                        <i className="fas fa-eye text-xs"></i>
                     </button>
                     <button onClick={() => onEditUser(user)} className="w-10 h-10 bg-slate-50 dark:bg-slate-800 text-slate-400 hover:text-amber-500 rounded-xl flex items-center justify-center transition-all border border-slate-100 dark:border-slate-800">
                        <i className="fas fa-pen text-xs"></i>
                     </button>
                  </div>
                </div>

                {/* Badge thông tin công việc */}
                <div className={`px-5 py-2 bg-white dark:bg-slate-900 border-2 rounded-full text-[10px] font-black shadow-sm ${currentStyle.split(' ')[1]} ${currentStyle.split(' ')[2]}`}>
                  {userTasksCount} CÔNG VIỆC
                </div>
              </div>

              {renderNode(user.id, level + 1)}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="p-6 md:p-12 h-full overflow-auto custom-scrollbar bg-slate-50/50 dark:bg-slate-950/50">
      <div className="max-w-7xl mx-auto space-y-12 pb-20">
        <header className="flex items-center justify-between">
          <div>
            <h2 className="text-4xl font-black text-slate-800 dark:text-white tracking-tighter uppercase">{t.orgChart}</h2>
            <p className="text-[11px] text-slate-400 font-bold uppercase tracking-[0.3em] mt-3">Cấu trúc nhân sự & phân quyền hệ thống</p>
          </div>
          <div className="hidden md:flex gap-4">
             <div className="px-8 py-5 bg-white dark:bg-slate-900 border-2 border-slate-100 dark:border-slate-800 rounded-[2rem] flex items-center gap-4 shadow-sm">
                <div className="w-3 h-3 rounded-full bg-emerald-500 animate-ping"></div>
                <span className="text-[11px] font-black text-slate-600 dark:text-slate-400 uppercase tracking-widest">Hệ thống thời gian thực</span>
             </div>
          </div>
        </header>

        <div className="relative pt-12">
           {renderNode('root-admin', 0)}
           {renderNode('root', 0)}
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import TaskItem from './components/TaskItem';
import Login from './components/Login';
import Setup from './components/Setup';
import HistoryModal from './components/HistoryModal';
import ExportModal from './components/ExportModal';
import SettingsModal from './components/SettingsModal';
import ManageCompaniesModal from './components/ManageCompaniesModal';
import AdminUserModal from './components/AdminUserModal';
import AdminDashboard from './components/AdminDashboard';
import TeamSummary from './components/TeamSummary';
import { Task, TaskStatus, AppState, User, UserRole } from './types';
import { loadStateSecure, saveStateSecure } from './services/storageService';
import { translations } from './translations';

const App: React.FC = () => {
  const [state, setState] = useState<AppState | null>(null);
  const [loading, setLoading] = useState(false);
  const [newPassword, setNewPassword] = useState('');
  const [modals, setModals] = useState({
    history: false,
    export: false,
    settings: false,
    manageCompanies: false,
    manageUsers: false,
    userToEdit: null as User | null,
    userToView: null as User | null,
  });
  const [currentView, setCurrentView] = useState<'PERSONAL' | 'TEAM'>('PERSONAL');
  const [selectedTeamMember, setSelectedTeamMember] = useState<User | null>(null);

  const currentLanguage = state?.settings?.language || 'vi';
  const currentTheme = state?.settings?.theme || 'light';
  const t = translations[currentLanguage] || translations.vi;
  const isRootAdmin = state?.currentUser?.email === 'tam.agriviet@gmail.com';

  useEffect(() => {
    const root = document.documentElement;
    if (currentTheme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
  }, [currentTheme]);

  const handleLogin = async (email: string, pass: string) => {
    setLoading(true);
    try {
      const loaded = await loadStateSecure(email, pass);
      setState(loaded);
    } catch (e: any) { 
      alert(e.message); 
    }
    finally { setLoading(false); }
  };

  const handleLogout = () => {
    setState(null);
    setCurrentView('PERSONAL');
    setSelectedTeamMember(null);
  };

  useEffect(() => {
    if (state && state.currentUser) saveStateSecure(state);
  }, [state]);

  const isSupervisorOf = (supervisorId: string, subordinateId: string): boolean => {
    if (!state) return false;
    const subordinate = state.users.find(u => u.id === subordinateId);
    if (!subordinate) return false;
    if (subordinate.reportsTo === supervisorId) return true;
    const supervisor = state.users.find(u => u.id === supervisorId);
    if (supervisor?.role === 'ADMIN') return true;
    if (supervisor?.role === 'DEPT_HEAD') return subordinate.role !== 'ADMIN';
    if (subordinate.reportsTo) return isSupervisorOf(supervisorId, subordinate.reportsTo);
    return false;
  };

  const subordinates = useMemo(() => {
    if (!state) return [];
    return state.users.filter(u => u.id !== state.currentUser.id && isSupervisorOf(state.currentUser.id, u.id));
  }, [state]);

  const filteredTasks = useMemo(() => {
    if (!state) return [];
    let baseTasks: Task[] = [];
    if (currentView === 'PERSONAL') {
      baseTasks = state.tasks.filter(tk => tk.userId === state.currentUser.id && !tk.deletedAt);
    } else if (selectedTeamMember) {
      baseTasks = state.tasks.filter(tk => tk.userId === selectedTeamMember.id && !tk.deletedAt);
    }

    // Sắp xếp: Ưu tiên việc gấp (isPriority), sau đó đến việc mới nhất
    return [...baseTasks].sort((a, b) => {
      if (a.isPriority && !b.isPriority) return -1;
      if (!a.isPriority && b.isPriority) return 1;
      return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
    });
  }, [state, currentView, selectedTeamMember]);

  const stats = useMemo(() => {
    if (!state) return { active: 0, doneToday: 0 };
    const today = new Date().toISOString().split('T')[0];
    const pool = currentView === 'PERSONAL' 
      ? state.tasks.filter(tk => tk.userId === state.currentUser.id)
      : (selectedTeamMember 
          ? state.tasks.filter(tk => tk.userId === selectedTeamMember.id)
          : state.tasks.filter(tk => isSupervisorOf(state.currentUser.id, tk.userId))
        );

    return {
      active: pool.filter(tk => !tk.deletedAt && tk.status !== TaskStatus.DONE).length,
      doneToday: pool.filter(tk => !tk.deletedAt && tk.status === TaskStatus.DONE && tk.updatedAt.startsWith(today)).length
    };
  }, [state, currentView, selectedTeamMember]);

  if (!state) return <Login onLogin={handleLogin} />;

  // Bước 1: Bắt buộc đổi mật khẩu lần đầu
  if (state.currentUser.mustChangePassword) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6">
        <div className="w-full max-w-md bg-white p-12 rounded-[3.5rem] shadow-2xl text-center">
          <div className="w-20 h-20 bg-amber-500 rounded-full flex items-center justify-center text-white text-3xl mx-auto mb-6"><i className="fas fa-key"></i></div>
          <h2 className="text-2xl font-black text-slate-800 uppercase mb-8">Đổi mật khẩu lần đầu</h2>
          <input type="password" value={newPassword} onChange={e => setNewPassword(e.target.value)} placeholder="Mật khẩu mới..." className="w-full px-6 py-5 bg-slate-50 border rounded-2xl mb-6 font-bold text-center" />
          <button onClick={() => {
             if(newPassword.length < 6) return alert("Mật khẩu tối thiểu 6 ký tự");
             setState(p => {
               if (!p) return null;
               const updatedUser = { ...p.currentUser, password: newPassword, mustChangePassword: false };
               return {
                 ...p,
                 currentUser: updatedUser,
                 users: p.users.map(u => u.id === updatedUser.id ? updatedUser : u)
               };
             });
          }} className="w-full bg-blue-600 text-white font-black py-6 rounded-2xl shadow-xl uppercase">Cập nhật mật khẩu</button>
        </div>
      </div>
    );
  }

  // Bước 2: Bắt buộc thiết lập thông tin và Công ty nếu chưa có (Sau khi đã đổi pass)
  const isProfileIncomplete = !state.currentUser.fullName || state.currentUser.fullName === state.currentUser.email.split('@')[0];
  const hasNoCompanies = state.companies.length === 0;

  if (!isRootAdmin && (isProfileIncomplete || hasNoCompanies)) {
    return (
      <Setup 
        onComplete={(f, j, c) => setState(p => {
          if (!p) return null;
          const updatedUser = { ...p.currentUser, fullName: f, jobTitle: j };
          return {
            ...p,
            currentUser: updatedUser,
            users: p.users.map(u => u.id === updatedUser.id ? updatedUser : u),
            companies: c
          };
        })} 
        onLogout={handleLogout} 
      />
    );
  }

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-white dark:bg-slate-950 theme-transition">
      <Sidebar 
        currentUser={state.currentUser}
        companies={state.companies}
        language={currentLanguage}
        onAddTask={(content, company, isPriority) => {
          const newTask: Task = { id: crypto.randomUUID(), userId: state.currentUser.id, content, company, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString(), status: TaskStatus.IN_PROGRESS, isPriority };
          setState(prev => prev ? ({ ...prev, tasks: [newTask, ...prev.tasks] }) : null);
        }} 
        onAddCompany={c => setState(p => p ? ({...p, companies: [...p.companies, c]}) : null)}
        onOpenManageCompanies={() => setModals(m => ({...m, manageCompanies: true}))}
        onClearAll={() => {}} 
        onLogout={handleLogout}
        onOpenHistory={() => setModals(m => ({...m, history: true}))}
        onOpenExport={() => setModals(m => ({...m, export: true}))}
        onOpenSettings={() => setModals(m => ({...m, settings: true}))}
        onOpenManageUsers={() => setModals(m => ({...m, manageUsers: true}))}
      />

      <main className="flex-1 flex flex-col min-w-0 bg-slate-50 dark:bg-slate-950 relative h-screen overflow-hidden theme-transition">
        {isRootAdmin ? (
          <AdminDashboard 
            users={state.users} 
            tasks={state.tasks} 
            language={currentLanguage}
            onSelectUser={u => setModals(m => ({...m, manageUsers: true, userToView: u}))}
            onEditUser={u => setModals(m => ({...m, manageUsers: true, userToEdit: u}))}
          />
        ) : (
          <>
            <header className="min-h-[110px] py-4 px-6 md:px-10 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between z-10 shadow-sm transition-all">
              <div className="flex items-center gap-6">
                <button onClick={() => { setCurrentView('PERSONAL'); setSelectedTeamMember(null); }} className={`flex flex-col items-start transition-all ${currentView === 'PERSONAL' ? 'opacity-100 scale-105' : 'opacity-30 hover:opacity-50'}`}>
                  <h2 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.currentTasks}</h2>
                  <span className="text-[10px] font-black uppercase text-blue-500 tracking-widest">{state.currentUser.fullName}</span>
                </button>
                {state.currentUser.role !== 'EMPLOYEE' && (
                  <button onClick={() => { setCurrentView('TEAM'); setSelectedTeamMember(null); }} className={`flex flex-col items-start transition-all ${currentView === 'TEAM' ? 'opacity-100 scale-105' : 'opacity-30 hover:opacity-50'}`}>
                    <h2 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.teamTasks}</h2>
                    <span className="text-[10px] font-black uppercase text-amber-500 tracking-widest">Team Monitor</span>
                  </button>
                )}
              </div>

              <div className="flex items-center gap-8 md:gap-10">
                <div className="text-right">
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{t.doing}</p>
                  <p className="text-xl md:text-2xl font-black text-rose-500 leading-none">{stats.active}</p>
                </div>
                <div className="text-right">
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{t.doneToday}</p>
                  <p className="text-xl md:text-2xl font-black text-emerald-500 leading-none">{stats.doneToday}</p>
                </div>
              </div>
            </header>

            <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar">
              <div className="max-w-6xl mx-auto pb-24">
                {currentView === 'TEAM' && !selectedTeamMember ? (
                  <TeamSummary 
                    subordinates={subordinates}
                    tasks={state.tasks}
                    language={currentLanguage}
                    onSelectUser={setSelectedTeamMember}
                  />
                ) : (
                  <div className="max-w-4xl mx-auto space-y-4">
                    {selectedTeamMember && (
                      <div className="mb-8 flex items-center justify-between bg-white dark:bg-slate-900 p-6 rounded-[2rem] border border-slate-100 dark:border-slate-800 shadow-sm">
                         <div className="flex items-center gap-4">
                            <div className="w-12 h-12 rounded-2xl bg-blue-600 flex items-center justify-center text-white font-black">{selectedTeamMember.fullName.charAt(0)}</div>
                            <div>
                               <h3 className="font-black text-slate-800 dark:text-white uppercase text-sm">{selectedTeamMember.fullName}</h3>
                               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{selectedTeamMember.jobTitle}</p>
                            </div>
                         </div>
                         <button 
                           onClick={() => setSelectedTeamMember(null)}
                           className="px-6 py-2 bg-slate-100 dark:bg-slate-800 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-200 transition-all"
                         >
                           <i className="fas fa-arrow-left mr-2"></i> Quay lại
                         </button>
                      </div>
                    )}

                    {filteredTasks.length === 0 ? (
                      <div className="py-20 text-center opacity-30 italic font-bold text-slate-400 uppercase tracking-[0.2em]">
                        {t.noTasks}
                      </div>
                    ) : (
                      filteredTasks.map(task => (
                        <TaskItem 
                          key={task.id} 
                          task={task} 
                          language={currentLanguage} 
                          readOnly={currentView === 'TEAM'}
                          onStatusChange={(id, status) => setState(p => p ? ({...p, tasks: p.tasks.map(t => t.id === id ? {...t, status, updatedAt: new Date().toISOString()} : t)}) : null)}
                          onDelete={id => setState(p => p ? ({...p, tasks: p.tasks.map(t => t.id === id ? {...t, deletedAt: new Date().toISOString()} : t)}) : null)} 
                        />
                      ))
                    )}
                  </div>
                )}
              </div>
            </div>
          </>
        )}
      </main>

      {modals.manageUsers && (
        <AdminUserModal 
          currentUser={state.currentUser}
          users={state.users}
          tasks={state.tasks}
          language={currentLanguage}
          onAddUser={u => setState(p => p ? ({...p, users: [...p.users, u]}) : null)}
          onUpdateUser={u => setState(p => p ? ({...p, users: p.users.map(old => old.id === u.id ? u : old)}) : null)}
          onDeleteUser={id => setState(prev => prev ? ({...prev, users: prev.users.filter(u => u.id !== id)}) : null)}
          onClose={() => setModals(m => ({...m, manageUsers: false, userToEdit: null, userToView: null}))}
        />
      )}

      {modals.settings && <SettingsModal language={currentLanguage} theme={currentTheme} onUpdate={(l, theme) => setState(p => p ? ({...p, settings: {language: l, theme}}) : null)} onClose={() => setModals(m => ({...m, settings: false}))} />}
      {modals.manageCompanies && <ManageCompaniesModal companies={state.companies} language={currentLanguage} onRename={(o, n) => setState(p => p ? ({...p, companies: p.companies.map(c => c === o ? n : c), tasks: p.tasks.map(t => t.company === o ? {...t, company: n} : t)}) : null)} onDelete={c => setState(p => p ? ({...p, companies: p.companies.filter(x => x !== c)}) : null)} onClose={() => setModals(m => ({...m, manageCompanies: false}))} />}
      {modals.history && <HistoryModal tasks={state.tasks.filter(t => !t.deletedAt && t.userId === state.currentUser.id)} onClose={() => setModals(m => ({...m, history: false}))} />}
      {modals.export && <ExportModal tasks={state.tasks.filter(t => !t.deletedAt)} templates={state.templates || []} onSaveTemplate={tpl => setState(p => p ? ({...p, templates: [...(p.templates || []), tpl]}) : null)} onDeleteTemplate={id => setState(p => p ? ({...p, templates: (p.templates || []).filter(x => x.id !== id)}) : null)} onClose={() => setModals(m => ({...m, export: false}))} />}
    </div>
  );
};

export default App;

import React, { useMemo } from 'react';
import { User, Language, Task } from '../types';
import { translations } from '../translations';

interface AdminDashboardProps {
  users: User[];
  tasks: Task[];
  language: Language;
  onSelectUser: (user: User) => void;
  onEditUser: (user: User) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ users, tasks, language, onSelectUser, onEditUser }) => {
  const t = translations[language] || translations.vi;

  // Xây dựng cây phân cấp
  const hierarchy = useMemo(() => {
    const userMap: Record<string, User[]> = {};
    users.forEach(u => {
      const parentId = u.reportsTo || 'root-admin';
      if (!userMap[parentId]) userMap[parentId] = [];
      userMap[parentId].push(u);
    });
    return userMap;
  }, [users]);

  const renderNode = (parentId: string, level: number = 0) => {
    const children = hierarchy[parentId] || [];
    if (children.length === 0) return null;

    return (
      <div className={`flex flex-col gap-8 ${level > 0 ? 'ml-12 md:ml-20 border-l-4 border-slate-100 dark:border-slate-800 pl-12 md:pl-20' : ''}`}>
        {children.map(user => {
          // Ẩn admin hệ thống khỏi sơ đồ con để đỡ rối
          if (user.email === 'tam.agriviet@gmail.com' && level > 0) return null;

          // Cấu hình màu sắc đồng nhất theo cấp bậc
          const roleStyles = {
            ADMIN: 'bg-rose-600 border-rose-200 text-rose-600 shadow-rose-500/10',
            DEPT_HEAD: 'bg-amber-500 border-amber-200 text-amber-600 shadow-amber-500/10',
            MANAGER: 'bg-indigo-600 border-indigo-200 text-indigo-600 shadow-indigo-500/10',
            EMPLOYEE: 'bg-slate-500 border-slate-200 text-slate-500 shadow-slate-500/10'
          };

          const currentStyle = roleStyles[user.role];
          const userTasksCount = tasks.filter(tk => tk.userId === user.id && !tk.deletedAt).length;

          return (
            <div key={user.id} className="relative animate-in slide-in-from-left-8 duration-500">
              <div className="flex items-center gap-6 group">
                <div className={`bg-white dark:bg-slate-900 border-2 border-l-[10px] p-5 rounded-[2rem] shadow-xl flex items-center gap-5 min-w-[320px] hover:-translate-y-1 transition-all ${currentStyle.split(' ')[1]} ${currentStyle.replace('bg-', 'border-l-')}`}>
                  <div className={`w-16 h-16 rounded-[1.5rem] flex items-center justify-center font-black text-white text-xl shadow-lg ${currentStyle.split(' ')[0]}`}>
                    {user.fullName.charAt(0)}
                  </div>
                  <div className="flex-1 min-w-0">
                    <h4 className="font-black text-slate-800 dark:text-white text-sm uppercase truncate tracking-tight">{user.fullName}</h4>
                    <p className={`text-[10px] font-black uppercase tracking-widest mt-0.5 ${currentStyle.split(' ')[2]}`}>
                      {user.jobTitle}
                    </p>
                    <span className="text-[8px] font-black px-2 py-0.5 rounded bg-slate-100 dark:bg-slate-900 text-slate-400 mt-2 inline-block">
                      {t[`role_${user.role}` as keyof typeof t]}
                    </span>
                  </div>
                  <div className="flex flex-col gap-2">
                     <button onClick={() => onSelectUser(user)} className="w-10 h-10 bg-slate-50 dark:bg-slate-800 text-slate-400 hover:text-blue-500 rounded-xl flex items-center justify-center transition-all border border-slate-100 dark:border-slate-800">
                        <i className="fas fa-eye text-xs"></i>
                     </button>
                     <button onClick={() => onEditUser(user)} className="w-10 h-10 bg-slate-50 dark:bg-slate-800 text-slate-400 hover:text-amber-500 rounded-xl flex items-center justify-center transition-all border border-slate-100 dark:border-slate-800">
                        <i className="fas fa-pen text-xs"></i>
                     </button>
                  </div>
                </div>

                <div className={`px-5 py-2 bg-white dark:bg-slate-900 border-2 rounded-full text-[10px] font-black shadow-sm ${currentStyle.split(' ')[1]} ${currentStyle.split(' ')[2]}`}>
                  {userTasksCount} CÔNG VIỆC
                </div>
              </div>

              {renderNode(user.id, level + 1)}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="p-6 md:p-12 h-full overflow-auto custom-scrollbar bg-slate-50/50 dark:bg-slate-950/50">
      <div className="max-w-7xl mx-auto space-y-12 pb-20">
        <header className="flex items-center justify-between">
          <div>
            <h2 className="text-4xl font-black text-slate-800 dark:text-white tracking-tighter uppercase">{t.orgChart}</h2>
            <p className="text-[11px] text-slate-400 font-bold uppercase tracking-[0.3em] mt-3">Quản trị cấu trúc doanh nghiệp</p>
          </div>
          <div className="hidden md:flex gap-4">
             <div className="px-8 py-5 bg-white dark:bg-slate-900 border-2 border-slate-100 dark:border-slate-800 rounded-[2rem] flex items-center gap-4 shadow-sm">
                <div className="w-3 h-3 rounded-full bg-emerald-500 animate-ping"></div>
                <span className="text-[11px] font-black text-slate-600 dark:text-slate-400 uppercase tracking-widest">Hệ thống thời gian thực</span>
