export enum TaskStatus {
  NOT_STARTED = 'NOT_STARTED',
  IN_PROGRESS = 'IN_PROGRESS',
  DONE = 'DONE'
}

export type UserRole = 'ADMIN' | 'DEPT_HEAD' | 'MANAGER' | 'EMPLOYEE';
export type Language = 'vi' | 'en' | 'zh' | 'ru';
export type Theme = 'light' | 'dark';
export type ReportLayout = 'FLAT' | 'GROUPED_BY_COMPANY';

export interface User {
  id: string;
  email: string;
  password?: string;
  fullName: string;
  jobTitle: string; 
  role: UserRole;
  reportsTo?: string; 
  department?: string;
  mustChangePassword?: boolean;
  companies: string[]; // Mỗi user có danh sách công ty riêng
}

export interface Task {
  id: string;
  userId: string; 
  content: string;
  company: string;
  createdAt: string; 
  updatedAt: string;
  status: TaskStatus;
  isPriority: boolean;
  deletedAt?: string;
}

export interface ReportTemplate {
  id: string;
  name: string;
  layout: ReportLayout;
  columns: {
    company: boolean;
    content: boolean;
    status: boolean;
    priority: boolean;
    date: boolean;
    pendingTasks: boolean;
  };
}

export interface AppState {
  currentUser: User;
  users: User[]; 
  tasks: Task[]; 
  templates?: ReportTemplate[]; 
  settings: {
    language: Language;
    theme: Theme;
  };
}

import { AppState, User } from '../types';

const STORAGE_KEY = 'zentask_enterprise_db';
const ADMIN_EMAIL = 'tam.agriviet@gmail.com';
const ADMIN_PASS = '123456789';

const createDefaultState = (): AppState => {
  const admin: User = {
    id: 'root-admin',
    email: ADMIN_EMAIL,
    password: ADMIN_PASS,
    fullName: 'Tam Agriviet',
    jobTitle: 'Hệ thống Quản trị',
    role: 'ADMIN',
    mustChangePassword: false,
    companies: ["Agriviet"] // Công ty riêng của admin
  };

  return {
    currentUser: admin,
    users: [admin],
    tasks: [],
    settings: { language: 'vi', theme: 'light' }
  };
};

export const saveStateSecure = async (state: AppState) => {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  } catch (e) {
    console.error("Failed to save state:", e);
  }
};

export const loadStateSecure = async (email: string, password?: string): Promise<AppState> => {
  const raw = localStorage.getItem(STORAGE_KEY);
  let state: AppState;

  if (!raw) {
    state = createDefaultState();
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  } else {
    state = JSON.parse(raw);
  }

  // Tự động thêm admin nếu bị xóa nhầm
  if (!state.users.find(u => u.email === ADMIN_EMAIL)) {
     const root = createDefaultState().users[0];
     state.users.push(root);
  }

  const user = state.users.find(u => u.email === email && u.password === password);
  if (user) {
    // Đảm bảo user cũ cũng có mảng companies
    if (!user.companies) user.companies = [];
    return { ...state, currentUser: user };
  }

  throw new Error("Thông tin đăng nhập không chính xác");
};

export const authenticateUser = async (credentials: { email: string; password: string }) => {
  try {
    await loadStateSecure(credentials.email, credentials.password);
    return { success: true };
  } catch (e: any) {
    return { success: false, message: e.message };
  }
};

