      csvContent += "Công ty,Nội dung tóm tắt,Đang thực hiện\n";
      // Fix: Explicitly cast entries to [string, Task[]][] to avoid 'unknown' type for tks
      (Object.entries(groupedTasks || {}) as [string, Task[]][]).forEach(([company, tks]) => {
        const cName = company.replace(/"/g, '""');
        const summary = tks.map((tk, i) => `${i + 1}. ${tk.content}`).join('\n').replace(/"/g, '""');
        const pending = tks.filter(tk => tk.status !== TaskStatus.DONE).map((tk, i) => `${i + 1}. ${tk.content}`).join('\n').replace(/"/g, '""');
        csvContent += `"${cName}","${summary}","${pending}"\n`;
      });
    }

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `Bao_Cao_${startDate}.csv`;
    link.click();
  };

  const handleExportImage = async () => {
    if (!reportRef.current) return;
    try {
      const canvas = await (window as any).html2canvas(reportRef.current, { 
        scale: 2, 
        backgroundColor: '#ffffff',
        useCORS: true,
        logging: false
      });
      const dataUrl = canvas.toDataURL('image/png');
      const link = document.createElement('a');
      link.href = dataUrl;
      link.download = `Bao_Cao_${startDate}.png`;
      link.click();
    } catch (err) {
      alert("Xuất ảnh lỗi. Vui lòng thử lại!");
    }
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-0 md:p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="w-full h-full md:h-auto md:max-w-6xl bg-white md:rounded-[3rem] shadow-2xl flex flex-col max-h-[100vh] md:max-h-[95vh] overflow-hidden">
        <header className="p-6 md:p-8 border-b border-slate-100 flex items-center justify-between shrink-0">
          <div>
            <h2 className="text-xl md:text-2xl font-black text-slate-800 uppercase tracking-tight">Xuất báo cáo</h2>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">Dữ liệu cá nhân</p>
          </div>
          <button onClick={onClose} className="w-12 h-12 flex items-center justify-center rounded-2xl hover:bg-slate-50 text-slate-300">
            <i className="fas fa-times text-xl"></i>
          </button>
        </header>

        <div className="flex-1 overflow-y-auto p-6 md:p-8 custom-scrollbar space-y-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Từ ngày</label>
              <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-sm" />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Đến ngày</label>
              <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-sm" />
            </div>
          </div>

          <div className="space-y-3">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Bố cục</label>
            <div className="flex gap-4">
               <button onClick={() => setLayout('FLAT')} className={`flex-1 p-4 rounded-2xl border-2 transition-all ${layout === 'FLAT' ? 'border-blue-600 bg-blue-50 text-blue-600' : 'border-slate-100 bg-white text-slate-400'} font-black uppercase text-[10px]`}>Chi tiết từng việc</button>
               <button onClick={() => setLayout('GROUPED_BY_COMPANY')} className={`flex-1 p-4 rounded-2xl border-2 transition-all ${layout === 'GROUPED_BY_COMPANY' ? 'border-blue-600 bg-blue-50 text-blue-600' : 'border-slate-100 bg-white text-slate-400'} font-black uppercase text-[10px]`}>Gộp theo công ty</button>
            </div>
          </div>

          <div className="border border-slate-100 rounded-[2rem] bg-white overflow-hidden shadow-inner">
             <div ref={reportRef} className="p-10 bg-white min-w-[700px]">
                <div className="text-center mb-8">
                   <h1 className="text-2xl font-black text-slate-800 uppercase">BÁO CÁO CÔNG VIỆC CÁ NHÂN</h1>
                   <p className="text-xs font-bold text-slate-400 mt-2 uppercase">Thời gian: {formatDate(startDate)} - {formatDate(endDate)}</p>
                </div>
                <table className="w-full border-collapse">
                   <thead>
                      <tr className="bg-slate-50">
                        {layout === 'FLAT' ? (
                          <>
                            <th className="p-4 border text-[10px] font-black uppercase text-left">Công ty</th>
                            <th className="p-4 border text-[10px] font-black uppercase text-left">Nội dung</th>
                            <th className="p-4 border text-[10px] font-black uppercase text-left">Đang làm</th>
                            <th className="p-4 border text-[10px] font-black uppercase text-center">Ngày</th>
                          </>
                        ) : (
                          <>
                            <th className="p-4 border text-[10px] font-black uppercase text-left">Công ty</th>
                            <th className="p-4 border text-[10px] font-black uppercase text-left">Tóm tắt công việc</th>
                            <th className="p-4 border text-[10px] font-black uppercase text-left">Đang thực hiện</th>
                          </>
                        )}
                      </tr>
                   </thead>
                   <tbody>
                      {layout === 'FLAT' ? (
                        filteredTasks.map(t => {
                          const cpColor = getCompanyColor(t.company);
                          return (
                            <tr key={t.id}>
                               <td className={`p-4 border text-[11px] font-bold ${cpColor.text}`}>{t.company}</td>
                               <td className="p-4 border text-[11px] text-slate-700">{t.content}</td>
                               <td className="p-4 border text-[11px] text-blue-600 font-bold">{t.status !== TaskStatus.DONE ? t.content : ""}</td>
                               <td className="p-4 border text-[11px] text-center text-slate-400">{formatDate(t.createdAt.split('T')[0])}</td>
                            </tr>
                          );
                        })
                      ) : (
                        // Fix: Explicitly cast entries to [string, Task[]][] to avoid 'unknown' type for tks
                        (Object.entries(groupedTasks || {}) as [string, Task[]][]).map(([company, tks]) => {
                          const cpColor = getCompanyColor(company);
                          return (
                            <tr key={company}>
                               <td className={`p-4 border text-[11px] font-black uppercase ${cpColor.text} align-top`}>{company}</td>
                               <td className="p-4 border text-[11px] text-slate-700 whitespace-pre-line align-top">
                                  {tks.map((tk, i) => `${i + 1}. ${tk.content}`).join('\n')}
                                </td>
                               <td className="p-4 border text-[11px] text-blue-600 font-bold whitespace-pre-line align-top">
                                  {tks.filter(tk => tk.status !== TaskStatus.DONE).map((tk, i) => `${i + 1}. ${tk.content}`).join('\n') || "-"}
                               </td>
                            </tr>
                          );
                        })
                      )}
                   </tbody>
                </table>
             </div>
          </div>
        </div>

        <footer className="p-6 md:p-8 bg-slate-50 border-t border-slate-100 flex justify-end gap-4 shrink-0">
           <button onClick={handleExportCSV} className="px-8 py-4 bg-emerald-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg hover:opacity-90 active:scale-95 transition-all">
              <i className="fas fa-file-excel mr-2"></i> Xuất EXCEL
           </button>
           <button onClick={handleExportImage} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg hover:opacity-90 active:scale-95 transition-all">
              <i className="fas fa-file-image mr-2"></i> Xuất ẢNH
           </button>
        </footer>
      </div>
    </div>
  );
};

export default ExportModal;

import React, { useState } from 'react';

interface SetupProps {
  initialFullName: string;
  initialJobTitle: string;
  onComplete: (fullName: string, jobTitle: string, companies: string[]) => void;
  onLogout: () => void;
}

const Setup: React.FC<SetupProps> = ({ initialFullName, initialJobTitle, onComplete, onLogout }) => {
  const [companies, setCompanies] = useState<string[]>([]);
  const [companyInput, setCompanyInput] = useState('');

  const handleAddCompany = (e: React.FormEvent) => {
    e.preventDefault();
    const name = companyInput.trim();
    if (name && !companies.includes(name)) {
      setCompanies([...companies, name]);
      setCompanyInput('');
    }
  };

  const removeCompany = (name: string) => {
    setCompanies(companies.filter(c => c !== name));
  };

  const isFormValid = companies.length > 0;

  return (
    <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6">
      <div className="w-full max-w-2xl bg-white p-8 md:p-14 rounded-[3.5rem] shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-2 bg-blue-600"></div>

        <div className="flex justify-between items-start mb-10">
          <div className="space-y-2">
            <h1 className="text-3xl font-black text-slate-800 tracking-tighter uppercase leading-tight">
              Những công ty <br/> bạn làm việc
            </h1>
            <p className="text-blue-600 font-bold text-[10px] uppercase tracking-[0.2em]">Cấu hình hệ thống quản trị</p>
          </div>
          <button onClick={onLogout} className="w-12 h-12 flex items-center justify-center rounded-2xl bg-slate-50 text-slate-400 hover:text-rose-500 transition-all border border-slate-100">
            <i className="fas fa-sign-out-alt text-xl"></i>
          </button>
        </div>

        <div className="space-y-6">
          <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
            <p className="text-slate-500 text-xs font-bold leading-relaxed mb-6">
              Vui lòng nhập tên các công ty hoặc đối tác mà bạn đang trực tiếp theo dõi và xử lý công việc.
            </p>

            <form onSubmit={handleAddCompany} className="flex gap-3">
              <input
                value={companyInput}
                onChange={(e) => setCompanyInput(e.target.value)}
                placeholder="Nhập tên công ty (ví dụ: Agriviet)..."
                className="flex-1 px-6 py-5 bg-white border border-slate-200 rounded-2xl focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-slate-700 transition-all"
              />
              <button 
                type="submit"
                className="px-8 bg-blue-600 text-white font-black rounded-2xl shadow-lg shadow-blue-500/20 transition-all active:scale-95 uppercase text-[10px] tracking-widest"
              >
                THÊM
              </button>
            </form>
          </div>

          <div className="min-h-[180px] border-2 border-dashed border-slate-100 rounded-[2.5rem] p-8 flex flex-wrap gap-3 items-start content-start bg-slate-50/30 overflow-y-auto max-h-[300px] custom-scrollbar">
            {companies.length === 0 ? (
              <div className="w-full h-full flex flex-col items-center justify-center py-10 opacity-30">
                <i className="fas fa-building text-4xl mb-4"></i>
                <p className="italic font-black text-[10px] uppercase tracking-widest">Danh sách đang trống</p>
              </div>
            ) : (
              companies.map(c => (
                <div key={c} className="group bg-white border-2 border-slate-100 text-slate-700 px-5 py-3 rounded-2xl font-black text-[11px] uppercase tracking-wider flex items-center gap-4 shadow-sm transition-all hover:border-blue-300 hover:shadow-md">
                  {c}
                  <button onClick={() => removeCompany(c)} className="text-slate-300 hover:text-rose-500 transition-colors">
                    <i className="fas fa-times-circle text-lg"></i>
                  </button>
                </div>
              ))
            )}
          </div>
        </div>

        <button
          disabled={!isFormValid}
          onClick={() => onComplete(initialFullName, initialJobTitle, companies)}
          className="w-full bg-slate-900 hover:bg-black disabled:opacity-20 text-white font-black py-6 rounded-2xl shadow-2xl transition-all flex items-center justify-center gap-4 active:scale-95 mt-10 uppercase tracking-[0.2em] text-xs"
        >
          KÍCH HOẠT HỆ THỐNG
          <i className="fas fa-chevron-right text-[10px]"></i>
        </button>
      </div>
    </div>
  );
};

export default Setup;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import TaskItem from './components/TaskItem';
import Login from './components/Login';
import Setup from './components/Setup';
import HistoryModal from './components/HistoryModal';
import ExportModal from './components/ExportModal';
import SettingsModal from './components/SettingsModal';
import ManageCompaniesModal from './components/ManageCompaniesModal';
import AdminUserModal from './components/AdminUserModal';
import AdminDashboard from './components/AdminDashboard';
import TeamSummary from './components/TeamSummary';
import { Task, TaskStatus, AppState, User, UserRole } from './types';
import { loadStateSecure, saveStateSecure } from './services/storageService';
import { translations } from './translations';

const App: React.FC = () => {
  const [state, setState] = useState<AppState | null>(null);
  const [loading, setLoading] = useState(false);
  const [newPassword, setNewPassword] = useState('');
  const [modals, setModals] = useState({
    history: false,
    export: false,
    settings: false,
    manageCompanies: false,
    manageUsers: false,
    userToEdit: null as User | null,
    userToView: null as User | null,
  });
  const [currentView, setCurrentView] = useState<'PERSONAL' | 'TEAM'>('PERSONAL');
  const [selectedTeamMember, setSelectedTeamMember] = useState<User | null>(null);

  const currentLanguage = state?.settings?.language || 'vi';
  const currentTheme = state?.settings?.theme || 'light';
  const t = translations[currentLanguage] || translations.vi;
  const isRootAdmin = state?.currentUser?.email === 'tam.agriviet@gmail.com';

  useEffect(() => {
    const root = document.documentElement;
    if (currentTheme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
  }, [currentTheme]);

  const handleLogin = async (email: string, pass: string) => {
    setLoading(true);
    try {
      const loaded = await loadStateSecure(email, pass);
      setState(loaded);
    } catch (e: any) { 
      alert(e.message); 
    }
    finally { setLoading(false); }
  };

  const handleLogout = () => {
    setState(null);
    setCurrentView('PERSONAL');
    setSelectedTeamMember(null);
  };

  useEffect(() => {
    if (state && state.currentUser) saveStateSecure(state);
  }, [state]);

  const directSubordinates = useMemo(() => {
    if (!state) return [];
    return state.users.filter(u => u.reportsTo === state.currentUser.id);
  }, [state]);

  const filteredTasks = useMemo(() => {
    if (!state) return [];
    let baseTasks: Task[] = [];
    if (currentView === 'PERSONAL') {
      baseTasks = state.tasks.filter(tk => tk.userId === state.currentUser.id && !tk.deletedAt);
    } else if (selectedTeamMember && isRootAdmin) {
      baseTasks = state.tasks.filter(tk => tk.userId === selectedTeamMember.id && !tk.deletedAt);
    } else {
      return [];
    }

    return [...baseTasks].sort((a, b) => {
      if (a.isPriority && !b.isPriority) return -1;
      if (!a.isPriority && b.isPriority) return 1;
      return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
    });
  }, [state, currentView, selectedTeamMember, isRootAdmin]);

  const stats = useMemo(() => {
    if (!state) return { active: 0, doneToday: 0 };
    const today = new Date().toISOString().split('T')[0];

    let pool: Task[] = [];
    if (currentView === 'PERSONAL') {
      pool = state.tasks.filter(tk => tk.userId === state.currentUser.id && !tk.deletedAt);
    } else {
      const directIds = directSubordinates.map(u => u.id);
      pool = state.tasks.filter(tk => directIds.includes(tk.userId) && !tk.deletedAt);
    }

    return {
      active: pool.filter(tk => tk.status !== TaskStatus.DONE).length,
      doneToday: pool.filter(tk => tk.status === TaskStatus.DONE && tk.updatedAt.startsWith(today)).length
    };
  }, [state, currentView, directSubordinates]);

  const handleDeleteTask = (id: string) => {
    if (window.confirm(t.confirmDeleteTask)) {
      setState(p => p ? ({...p, tasks: p.tasks.map(t => t.id === id ? {...t, deletedAt: new Date().toISOString()} : t)}) : null);
    }
  };

  const updateCurrentUserCompanies = (newCompanies: string[]) => {
    setState(p => {
      if (!p) return null;
      const updatedUser = { ...p.currentUser, companies: newCompanies };
      return {
        ...p,
        currentUser: updatedUser,
        users: p.users.map(u => u.id === updatedUser.id ? updatedUser : u)
      };
    });
  };

  if (!state) return <Login onLogin={handleLogin} />;

  const isProfileIncomplete = !state.currentUser.fullName || state.currentUser.fullName === state.currentUser.email.split('@')[0];
  const hasNoCompanies = !state.currentUser.companies || state.currentUser.companies.length === 0;

  // Chỉ yêu cầu Setup nếu không có công ty nào (Root Admin luôn bỏ qua Setup)
  if (!isRootAdmin && hasNoCompanies) {
    return (
      <Setup 
        initialFullName={state.currentUser.fullName}
        initialJobTitle={state.currentUser.jobTitle}
        onComplete={(f, j, c) => setState(p => {
          if (!p) return null;
          const updatedUser = { ...p.currentUser, fullName: f, jobTitle: j, companies: c };
          return {
            ...p,
            currentUser: updatedUser,
            users: p.users.map(u => u.id === updatedUser.id ? updatedUser : u)
          };
        })} 
        onLogout={handleLogout} 
      />
    );
  }

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-white dark:bg-slate-950 theme-transition">
      <Sidebar 
        currentUser={state.currentUser}
        companies={state.currentUser.companies || []}
        language={currentLanguage}
        onAddTask={(content, company, isPriority) => {
          const newTask: Task = { id: crypto.randomUUID(), userId: state.currentUser.id, content, company, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString(), status: TaskStatus.NOT_STARTED, isPriority };
          setState(prev => prev ? ({ ...prev, tasks: [newTask, ...prev.tasks] }) : null);
        }} 
        onAddCompany={c => updateCurrentUserCompanies([...(state.currentUser.companies || []), c])}
        onOpenManageCompanies={() => setModals(m => ({...m, manageCompanies: true}))}
        onClearAll={() => {}} 
        onLogout={handleLogout}
        onOpenHistory={() => setModals(m => ({...m, history: true}))}
        onOpenExport={() => setModals(m => ({...m, export: true}))}
        onOpenSettings={() => setModals(m => ({...m, settings: true}))}
        onOpenManageUsers={() => setModals(m => ({...m, manageUsers: true}))}
      />

      <main className="flex-1 flex flex-col min-w-0 bg-slate-50 dark:bg-slate-950 relative h-screen overflow-hidden theme-transition">
        {isRootAdmin ? (
          <AdminDashboard 
            users={state.users} 
            tasks={state.tasks} 
            language={currentLanguage}
            onSelectUser={u => setModals(m => ({...m, manageUsers: true, userToView: u}))}
            onEditUser={u => setModals(m => ({...m, manageUsers: true, userToEdit: u}))}
          />
        ) : (
          <>
            <header className="min-h-[110px] py-4 px-6 md:px-10 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between z-10 shadow-sm transition-all">
              <div className="flex items-center gap-6">
                <button onClick={() => { setCurrentView('PERSONAL'); setSelectedTeamMember(null); }} className={`flex flex-col items-start transition-all ${currentView === 'PERSONAL' ? 'opacity-100 scale-105' : 'opacity-30 hover:opacity-50'}`}>
                  <h2 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.currentTasks}</h2>
                  <span className="text-[10px] font-black uppercase text-blue-500 tracking-widest">{state.currentUser.fullName}</span>
                </button>
                {state.currentUser.role !== 'EMPLOYEE' && (
                  <button onClick={() => { setCurrentView('TEAM'); setSelectedTeamMember(null); }} className={`flex flex-col items-start transition-all ${currentView === 'TEAM' ? 'opacity-100 scale-105' : 'opacity-30 hover:opacity-50'}`}>
                    <h2 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.teamTasks}</h2>
                    <span className="text-[10px] font-black uppercase text-amber-500 tracking-widest">Team Monitor</span>
                  </button>
                )}
              </div>

              <div className="flex items-center gap-8 md:gap-10">
                <div className="text-right">
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{currentView === 'PERSONAL' ? 'Đang xử lý' : 'Tổng việc chưa xong'}</p>
                  <p className="text-xl md:text-2xl font-black text-rose-500 leading-none">{stats.active}</p>
                </div>
                <div className="text-right">
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{t.doneToday}</p>
                  <p className="text-xl md:text-2xl font-black text-emerald-500 leading-none">{stats.doneToday}</p>
                </div>
              </div>
            </header>

            <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar">
              <div className="max-w-6xl mx-auto pb-24">
                {currentView === 'TEAM' && (!selectedTeamMember || !isRootAdmin) ? (
                  <TeamSummary 
                    subordinates={directSubordinates}
                    tasks={state.tasks}
                    language={currentLanguage}
                    onSelectUser={isRootAdmin ? setSelectedTeamMember : undefined}
                    isDrillDownEnabled={isRootAdmin}
                  />
                ) : (
                  <div className="max-w-4xl mx-auto space-y-4">
                    {filteredTasks.length === 0 ? (
                      <div className="py-20 text-center opacity-30 italic font-bold text-slate-400 uppercase tracking-[0.2em]">
                        {t.noTasks}
                      </div>
                    ) : (
                      filteredTasks.map(task => (
                        <TaskItem 
                          key={task.id} 
                          task={task} 
                          language={currentLanguage} 
                          readOnly={currentView === 'TEAM'}
                          onStatusChange={(id, status) => setState(p => p ? ({...p, tasks: p.tasks.map(t => t.id === id ? {...t, status, updatedAt: new Date().toISOString()} : t)}) : null)}
                          onDelete={handleDeleteTask} 
                        />
                      ))
                    )}
                  </div>
                )}
              </div>
            </div>
          </>
        )}
      </main>

      {modals.manageUsers && (
        <AdminUserModal 
          currentUser={state.currentUser}
          users={state.users}
          tasks={state.tasks}
          language={currentLanguage}
          onAddUser={u => setState(p => p ? ({...p, users: [...p.users, u]}) : null)}
          onUpdateUser={u => setState(p => p ? ({...p, users: p.users.map(old => old.id === u.id ? u : old)}) : null)}
          onDeleteUser={id => setState(prev => prev ? ({...prev, users: prev.users.filter(u => u.id !== id)}) : null)}
          onClose={() => setModals(m => ({...m, manageUsers: false, userToEdit: null, userToView: null}))}
        />
      )}

      {modals.settings && <SettingsModal language={currentLanguage} theme={currentTheme} onUpdate={(l, theme) => setState(p => p ? ({...p, settings: {language: l, theme}}) : null)} onClose={() => setModals(m => ({...m, settings: false}))} />}
      {modals.manageCompanies && <ManageCompaniesModal companies={state.currentUser.companies || []} language={currentLanguage} onAdd={c => updateCurrentUserCompanies([...(state.currentUser.companies || []), c])} onRename={(o, n) => updateCurrentUserCompanies((state.currentUser.companies || []).map(c => c === o ? n : c))} onDelete={c => updateCurrentUserCompanies((state.currentUser.companies || []).filter(x => x !== c))} onClose={() => setModals(m => ({...m, manageCompanies: false}))} />}
      {modals.history && <HistoryModal tasks={state.tasks.filter(t => !t.deletedAt && t.userId === state.currentUser.id)} onClose={() => setModals(m => ({...m, history: false}))} />}
      {modals.export && <ExportModal tasks={state.tasks.filter(t => t.userId === state.currentUser.id && !t.deletedAt)} templates={state.templates || []} onSaveTemplate={tpl => setState(p => p ? ({...p, templates: [...(p.templates || []), tpl]}) : null)} onDeleteTemplate={id => setState(p => p ? ({...p, templates: (p.templates || []).filter(x => x.id !== id)}) : null)} onClose={() => setModals(m => ({...m, export: false}))} />}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import TaskItem from './components/TaskItem';
import Login from './components/Login';
import Setup from './components/Setup';
import HistoryModal from './components/HistoryModal';
import ExportModal from './components/ExportModal';
import SettingsModal from './components/SettingsModal';
import ManageCompaniesModal from './components/ManageCompaniesModal';
import AdminUserModal from './components/AdminUserModal';
import AdminDashboard from './components/AdminDashboard';
import TeamSummary from './components/TeamSummary';
import { Task, TaskStatus, AppState, User, UserRole, Language, Theme } from './types';
import { loadStateSecure, saveStateSecure } from './services/storageService';
import { translations } from './translations';

const App: React.FC = () => {
  const [state, setState] = useState<AppState | null>(null);
  const [loading, setLoading] = useState(false);
  const [modals, setModals] = useState({
    history: false,
    export: false,
    settings: false,
    manageCompanies: false,
    manageUsers: false,
    userToEdit: null as User | null,
    userToView: null as User | null,
  });
  const [currentView, setCurrentView] = useState<'PERSONAL' | 'TEAM'>('PERSONAL');
  const [selectedTeamMember, setSelectedTeamMember] = useState<User | null>(null);

  const currentLanguage = state?.settings?.language || 'vi';
  const currentTheme = state?.settings?.theme || 'light';
  const t = translations[currentLanguage] || translations.vi;
  const isRootAdmin = state?.currentUser?.email === 'tam.agriviet@gmail.com';

  useEffect(() => {
    const root = document.documentElement;
    if (currentTheme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
  }, [currentTheme]);

  const handleLogin = async (email: string, pass: string) => {
    setLoading(true);
    try {
      const loaded = await loadStateSecure(email, pass);
      setState(loaded);
    } catch (e: any) { 
      alert(e.message); 
    }
    finally { setLoading(false); }
  };

  const handleLogout = () => {
    setState(null);
    setCurrentView('PERSONAL');
    setSelectedTeamMember(null);
  };

  useEffect(() => {
    if (state && state.currentUser) saveStateSecure(state);
  }, [state]);

  const directSubordinates = useMemo(() => {
    if (!state) return [];
    return state.users.filter(u => u.reportsTo === state.currentUser.id);
  }, [state]);

  const filteredTasks = useMemo(() => {
    if (!state) return [];
    let baseTasks: Task[] = [];
    if (currentView === 'PERSONAL') {
      baseTasks = state.tasks.filter(tk => tk.userId === state.currentUser.id && !tk.deletedAt);
    } else if (selectedTeamMember && isRootAdmin) {
      baseTasks = state.tasks.filter(tk => tk.userId === selectedTeamMember.id && !tk.deletedAt);
    } else {
      return [];
    }

    return [...baseTasks].sort((a, b) => {
      if (a.isPriority && !b.isPriority) return -1;
      if (!a.isPriority && b.isPriority) return 1;
      return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
    });
  }, [state, currentView, selectedTeamMember, isRootAdmin]);

  const stats = useMemo(() => {
    if (!state) return { active: 0, doneToday: 0 };
    const today = new Date().toISOString().split('T')[0];

    let pool: Task[] = [];
    if (currentView === 'PERSONAL') {
      pool = state.tasks.filter(tk => tk.userId === state.currentUser.id && !tk.deletedAt);
    } else {
      const directIds = directSubordinates.map(u => u.id);
      pool = state.tasks.filter(tk => directIds.includes(tk.userId) && !tk.deletedAt);
    }

    return {
      active: pool.filter(tk => tk.status !== TaskStatus.DONE).length,
      doneToday: pool.filter(tk => tk.status === TaskStatus.DONE && tk.updatedAt.startsWith(today)).length
    };
  }, [state, currentView, directSubordinates]);

  const handleDeleteTask = (id: string) => {
    if (window.confirm(t.confirmDeleteTask)) {
      setState(p => p ? ({...p, tasks: p.tasks.map(t => t.id === id ? {...t, deletedAt: new Date().toISOString()} : t)}) : null);
    }
  };

  const updateCurrentUserCompanies = (newCompanies: string[]) => {
    setState(p => {
      if (!p) return null;
      const updatedUser = { ...p.currentUser, companies: newCompanies };
      return {
        ...p,
        currentUser: updatedUser,
        users: p.users.map(u => u.id === updatedUser.id ? updatedUser : u)
      };
    });
  };

  const handleUpdatePassword = (newPass: string) => {
    setState(p => {
      if (!p) return null;
      const updatedUser = { ...p.currentUser, password: newPass };
      return {
        ...p,
        currentUser: updatedUser,
        users: p.users.map(u => u.id === updatedUser.id ? updatedUser : u)
      };
    });
  };

  if (!state) return <Login onLogin={handleLogin} />;

  const hasNoCompanies = !state.currentUser.companies || state.currentUser.companies.length === 0;

  if (!isRootAdmin && hasNoCompanies) {
    return (
      <Setup 
        initialFullName={state.currentUser.fullName}
        initialJobTitle={state.currentUser.jobTitle}
        onComplete={(f, j, c) => setState(p => {
          if (!p) return null;
          const updatedUser = { ...p.currentUser, fullName: f, jobTitle: j, companies: c };
          return {
            ...p,
            currentUser: updatedUser,
            users: p.users.map(u => u.id === updatedUser.id ? updatedUser : u)
          };
        })} 
        onLogout={handleLogout} 
      />
    );
  }

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-white dark:bg-slate-950 theme-transition">
      <Sidebar 
        currentUser={state.currentUser}
        companies={state.currentUser.companies || []}
        language={currentLanguage}
        onAddTask={(content, company, isPriority) => {
          const newTask: Task = { id: crypto.randomUUID(), userId: state.currentUser.id, content, company, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString(), status: TaskStatus.NOT_STARTED, isPriority };
          setState(prev => prev ? ({ ...prev, tasks: [newTask, ...prev.tasks] }) : null);
        }} 
        onAddCompany={c => updateCurrentUserCompanies([...(state.currentUser.companies || []), c])}
        onOpenManageCompanies={() => setModals(m => ({...m, manageCompanies: true}))}
        onClearAll={() => {}} 
        onLogout={handleLogout}
        onOpenHistory={() => setModals(m => ({...m, history: true}))}
        onOpenExport={() => setModals(m => ({...m, export: true}))}
        onOpenSettings={() => setModals(m => ({...m, settings: true}))}
        onOpenManageUsers={() => setModals(m => ({...m, manageUsers: true}))}
      />

      <main className="flex-1 flex flex-col min-w-0 bg-slate-50 dark:bg-slate-950 relative h-screen overflow-hidden theme-transition">
        {isRootAdmin ? (
          <AdminDashboard 
            users={state.users} 
            tasks={state.tasks} 
            language={currentLanguage}
            onSelectUser={u => setModals(m => ({...m, manageUsers: true, userToView: u}))}
            onEditUser={u => setModals(m => ({...m, manageUsers: true, userToEdit: u}))}
          />
        ) : (
          <>
            <header className="min-h-[110px] py-4 px-6 md:px-10 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between z-10 shadow-sm transition-all">
              <div className="flex items-center gap-6">
                <button onClick={() => { setCurrentView('PERSONAL'); setSelectedTeamMember(null); }} className={`flex flex-col items-start transition-all ${currentView === 'PERSONAL' ? 'opacity-100 scale-105' : 'opacity-30 hover:opacity-50'}`}>
                  <h2 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.currentTasks}</h2>
                  <span className="text-[10px] font-black uppercase text-blue-500 tracking-widest">{state.currentUser.fullName}</span>
                </button>
                {state.currentUser.role !== 'EMPLOYEE' && (
                  <button onClick={() => { setCurrentView('TEAM'); setSelectedTeamMember(null); }} className={`flex flex-col items-start transition-all ${currentView === 'TEAM' ? 'opacity-100 scale-105' : 'opacity-30 hover:opacity-50'}`}>
                    <h2 className="text-xl md:text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight">{t.teamTasks}</h2>
                    <span className="text-[10px] font-black uppercase text-amber-500 tracking-widest">Team Monitor</span>
                  </button>
                )}
              </div>

              <div className="flex items-center gap-8 md:gap-10">
                <div className="text-right">
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{currentView === 'PERSONAL' ? 'Đang xử lý' : 'Tổng việc chưa xong'}</p>
                  <p className="text-xl md:text-2xl font-black text-rose-500 leading-none">{stats.active}</p>
                </div>
                <div className="text-right">
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{t.doneToday}</p>
                  <p className="text-xl md:text-2xl font-black text-emerald-500 leading-none">{stats.doneToday}</p>
                </div>
              </div>
            </header>

            <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar">
              <div className="max-w-6xl mx-auto pb-24">
                {currentView === 'TEAM' && (!selectedTeamMember || !isRootAdmin) ? (
                  <TeamSummary 
                    subordinates={directSubordinates}
                    tasks={state.tasks}
                    language={currentLanguage}
                    onSelectUser={isRootAdmin ? setSelectedTeamMember : undefined}
                    isDrillDownEnabled={isRootAdmin}
                  />
                ) : (
                  <div className="max-w-4xl mx-auto space-y-4">
                    {filteredTasks.length === 0 ? (
                      <div className="py-20 text-center opacity-30 italic font-bold text-slate-400 uppercase tracking-[0.2em]">
                        {t.noTasks}
                      </div>
                    ) : (
                      filteredTasks.map(task => (
                        <TaskItem 
                          key={task.id} 
                          task={task} 
                          language={currentLanguage} 
                          readOnly={currentView === 'TEAM'}
                          onStatusChange={(id, status) => setState(p => p ? ({...p, tasks: p.tasks.map(t => t.id === id ? {...t, status, updatedAt: new Date().toISOString()} : t)}) : null)}
                          onDelete={handleDeleteTask} 
                        />
                      ))
                    )}
                  </div>
                )}
              </div>
            </div>
          </>
        )}
      </main>

      {modals.manageUsers && (
        <AdminUserModal 
          currentUser={state.currentUser}
          users={state.users}
          tasks={state.tasks}
          language={currentLanguage}
          onAddUser={u => setState(p => p ? ({...p, users: [...p.users, u]}) : null)}
          onUpdateUser={u => setState(p => p ? ({...p, users: p.users.map(old => old.id === u.id ? u : old)}) : null)}
          onDeleteUser={id => setState(prev => prev ? ({...prev, users: prev.users.filter(u => u.id !== id)}) : null)}
          onClose={() => setModals(m => ({...m, manageUsers: false, userToEdit: null, userToView: null}))}
        />
      )}

      {modals.settings && (
        <SettingsModal 
          language={currentLanguage} 
          theme={currentTheme} 
          currentUser={state.currentUser}
          onUpdate={(l, theme) => setState(p => p ? ({...p, settings: {language: l, theme}}) : null)} 
          onUpdatePassword={handleUpdatePassword}
          onClose={() => setModals(m => ({...m, settings: false}))} 
        />
      )}
      {modals.manageCompanies && <ManageCompaniesModal companies={state.currentUser.companies || []} language={currentLanguage} onAdd={c => updateCurrentUserCompanies([...(state.currentUser.companies || []), c])} onRename={(o, n) => updateCurrentUserCompanies((state.currentUser.companies || []).map(c => c === o ? n : c))} onDelete={c => updateCurrentUserCompanies((state.currentUser.companies || []).filter(x => x !== c))} onClose={() => setModals(m => ({...m, manageCompanies: false}))} />}
      {modals.history && <HistoryModal tasks={state.tasks.filter(t => !t.deletedAt && t.userId === state.currentUser.id)} onClose={() => setModals(m => ({...m, history: false}))} />}
      {modals.export && <ExportModal tasks={state.tasks.filter(t => t.userId === state.currentUser.id && !t.deletedAt)} templates={state.templates || []} onSaveTemplate={tpl => setState(p => p ? ({...p, templates: [...(p.templates || []), tpl]}) : null)} onDeleteTemplate={id => setState(p => p ? ({...p, templates: (p.templates || []).filter(x => x.id !== id)}) : null)} onClose={() => setModals(m => ({...m, export: false}))} />}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
